                        <span>Subject: <strong className="text-gray-700">{c.subjectType}</strong></span>
                        <span>Evidence: <strong className="text-gray-700">{(c.evidence as any)?.source || 'api'}</strong></span>
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

