                        </span>
                      ) : voiceWs.status === "connecting" ? (
                        t("connecting")
                      ) : voiceWs.isRecording ? (
                        t("listening")
                      ) : voiceWs.isPlaying ? (
                        t("aiSpeaking")
                      ) : (
                        t("tapToSpeak")
                      )}
                    </p>

                    {voiceWs.status === "error" ? (
                      <div className="flex flex-col items-center gap-2">
