    }
    if (!permission.collaborationAllowed) {
      return {
        success: false,
        error: "Editors are only available for workspace surveys",
      };
    }

    const editorIds = await getSurveyEditors(surveyId);
    if (editorIds.length === 0) {
      return { success: true, data: [] };
