"use server";

import { getDb } from "@/db";
import { notifications } from "@/db/schema";
import { auth } from "@/lib/auth";
import { headers } from "next/headers";
import { eq, desc, and } from "drizzle-orm";
import { nanoid } from "nanoid";
import { ActionResult } from "./workspace";

type NotificationRecord = typeof notifications.$inferSelect;

export async function getNotifications(): Promise<ActionResult<NotificationRecord[]>> {
    try {
        const session = await auth.api.getSession({ headers: await headers() });
        if (!session) return { success: false, error: "Unauthorized" };

        const userNotifications = await getDb().query.notifications.findMany({
            where: eq(notifications.userId, session.user.id),
            orderBy: [desc(notifications.createdAt)],
            limit: 20,
        });

        return {
            success: true,
            data: userNotifications,
        };
    } catch (error) {
        return {
            success: false,
            error: "Failed to get notifications",
        };
    }
}

export async function markNotificationAsRead(id: string): Promise<ActionResult<void>> {
    try {
        const session = await auth.api.getSession({ headers: await headers() });
        if (!session) return { success: false, error: "Unauthorized" };

        const updatedRows = await getDb()
            .update(notifications)
            .set({ read: true })
            .where(and(eq(notifications.id, id), eq(notifications.userId, session.user.id)))
            .returning({ id: notifications.id });

        if (updatedRows.length === 0) {
            return { success: false, error: "Notification not found" };
        }

        return { success: true, data: undefined };
    } catch (error) {
        return { success: false, error: "Failed to mark as read" };
    }
}

export async function createNotification(userId: string, title: string, message: string, type: "info" | "success" | "warning" | "error" = "info", link?: string) {
    await getDb().insert(notifications).values({
        id: nanoid(),
        userId,
        title,
        message,
        type,
        link,
        createdAt: new Date(),
    });
}

"use server";

import { getVerifiedSession } from "@/lib/auth/session";
import { getDb } from "@/db";
import { privacyRequests, consentEvents } from "@/db/schema/privacy";
import { users } from "@/db/schema/auth";
import { eq, desc } from "drizzle-orm";
import { isWorkspaceOwner } from "@/lib/workspace-access";

export type ActionResult<T> =
  | { success: true; data: T }
  | { success: false; error: string };

export async function getPrivacyDashboardData(): Promise<ActionResult<{
  requests: any[];
  consents: any[];
}>> {
  try {
    const session = await getVerifiedSession();
    const organizationId = session.session.activeOrganizationId;

    if (!organizationId) {
      return { success: false, error: "No active workspace selected" };
    }

    const isOwner = await isWorkspaceOwner(session.user.id, organizationId);
    if (!isOwner) {
      return { success: false, error: "Unauthorized: Owner access required" };
    }

    const db = getDb();

    // Fetch recent privacy requests with user info
    const requests = await db
      .select({
        id: privacyRequests.id,
        requestType: privacyRequests.requestType,
        status: privacyRequests.status,
        createdAt: privacyRequests.createdAt,
        user: {
          name: users.name,
          email: users.email,
        }
      })
      .from(privacyRequests)
      .leftJoin(users, eq(privacyRequests.userId, users.id))
      .where(eq(privacyRequests.organizationId, organizationId))
      .orderBy(desc(privacyRequests.createdAt))
      .limit(50);

    // Fetch recent consent events
    const consents = await db
      .select({
        id: consentEvents.id,
        subjectType: consentEvents.subjectType,
        consentKey: consentEvents.consentKey,
        decision: consentEvents.decision,
        createdAt: consentEvents.createdAt,
        evidence: consentEvents.evidence,
      })
      .from(consentEvents)
      .where(eq(consentEvents.organizationId, organizationId))
      .orderBy(desc(consentEvents.createdAt))
      .limit(50);

    return {
      success: true,
      data: {
        requests,
        consents,
      }
    };
  } catch (error) {
    console.error("Error fetching privacy dashboard data:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to fetch privacy data",
    };
  }
}

"use server";

import { getCurrentSession } from "@/lib/auth/session";
import { headers } from "next/headers";
import { auth } from "@/lib/auth";
import { getDb } from "@/db";
import { users } from "@/db/schema/auth";
import { eq } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import { cookies } from "next/headers";
import { normalizeAppLocale, type AppLocale } from "@/lib/i18n/config";

/**
 * Server Action to update the user's preferred language
 */
export async function updateUserLanguage(language: AppLocale) {
  try {
    const session = await auth.api.getSession({
      headers: await headers(),
    });

    if (!session?.user) {
      return { success: false, error: "Unauthorized" };
    }

    const db = getDb();
    await db
      .update(users)
      .set({ preferredLanguage: language, uiLocale: language })
      .where(eq(users.id, session.user.id));

    revalidatePath("/", "layout");

    // Sync the NEXT_LOCALE cookie so the proxy can perform optimistic redirects
    (await cookies()).set("NEXT_LOCALE", language, {
      path: "/",
      maxAge: 60 * 60 * 24 * 365, // 1 year
    });

    return { success: true };
  } catch (error) {
    return { success: false, error: "Failed to update language" };
  }
}

export async function getCurrentUiLocale() {
  const session = await getCurrentSession();
  return normalizeAppLocale(session?.user.uiLocale ?? session?.user.preferredLanguage);
}

"use server";

import { getVerifiedSession } from "@/lib/auth/session";
import { getDb } from "@/db";
import { voiceSessions, voiceQualityMetrics } from "@/db/schema/voice";
import { surveys } from "@/db/schema/surveys";
import { eq, desc, inArray } from "drizzle-orm";
import { isWorkspaceOwner } from "@/lib/workspace-access";
import { ActionResult } from "./workspace";

export async function getVoiceAnalyticsData(): Promise<ActionResult<{
  sessions: any[];
  metricsOverview: any;
}>> {
  try {
    const session = await getVerifiedSession();
    const organizationId = session.session.activeOrganizationId;

    if (!organizationId) {
      return { success: false, error: "No active workspace selected" };
    }

    const isOwner = await isWorkspaceOwner(session.user.id, organizationId);
    if (!isOwner) {
      return { success: false, error: "Unauthorized: Owner access required" };
    }

    const db = getDb();

    // First figure out the surveys
    const workspaceSurveys = await db
        .select({ id: surveys.id })
        .from(surveys)
        .where(eq(surveys.organizationId, organizationId));

    const surveyIds = workspaceSurveys.map(s => s.id);

    if (surveyIds.length === 0) {
        return {
            success: true,
            data: { sessions: [], metricsOverview: { avgLatency: 0, totalDuration: 0, fallbackCount: 0 } }
        };
    }

    // Fetch the recent sessions across all these surveys
    const sessions = await db
      .select({
        id: voiceSessions.id,
        surveyId: voiceSessions.surveyId,
        startedAt: voiceSessions.startedAt,
        durationMs: voiceSessions.durationMs,
        status: voiceSessions.status,
      })
      .from(voiceSessions)
      .where(inArray(voiceSessions.surveyId, surveyIds))
      .orderBy(desc(voiceSessions.startedAt))
      .limit(50);

    const sessionIds = sessions.map(s => s.id);

    let metrics = [];
    if (sessionIds.length > 0) {
       metrics = await db
         .select({
            metricType: voiceQualityMetrics.metricType,
            metricValue: voiceQualityMetrics.metricValue,
            sessionId: voiceQualityMetrics.sessionId,
         })
         .from(voiceQualityMetrics)
         .where(inArray(voiceQualityMetrics.sessionId, sessionIds));
    }

    // Calculate overviews (simple aggregation for the dashboard)
    let totalLatency = 0;
    let latencyCount = 0;
    let fallbackCount = 0;

    metrics.forEach(m => {
        if (m.metricType === 'latency_ms') {
            totalLatency += parseInt(m.metricValue, 10) || 0;
            latencyCount++;
        }
        if (m.metricType === 'fallback_triggered') fallbackCount++;
    });

    const metricsOverview = {
        avgLatency: latencyCount > 0 ? Math.round(totalLatency / latencyCount) : 0,
        totalDuration: sessions.reduce((acc, curr) => acc + (curr.durationMs || 0), 0),
        fallbackCount,
        sessionCount: sessions.length
    };

    return {
      success: true,
      data: {
        sessions,
        metricsOverview
      }
    };
  } catch (error) {
    console.error("Error fetching voice analytics data:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to fetch analytics",
    };
  }
}

import { NextResponse } from "next/server";
import { nanoid } from "nanoid";

import { getDb } from "@/db";
import { notifications } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import { getPrimaryStudentMembership } from "@/lib/learning/access";
import {
  buildOnboardingGreeting,
  runInterestOnboardingTurn,
  shouldRefreshInterestProfile,
} from "@/lib/learning/onboarding";
import { generateTeacherOnboardingSummary } from "@/lib/learning/reporting";
import { enqueueLearningPatternAnalysis } from "@/lib/queue";
import {
  appendLearningMessage,
  completeLearningSession,
  createLearningSession,
  getActiveLearningSession,
  listLearningMessages,
  markStudentOnboardingComplete,
  upsertInterestProfile,
} from "@/lib/learning/storage";

export async function GET() {
  try {
    const session = await getVerifiedSession();
    const membership = await getPrimaryStudentMembership(session.user.id);

    if (!membership) {
      return NextResponse.json({ error: "Student context not found" }, { status: 404 });
    }

    if (
      membership.interestProfile &&
      !shouldRefreshInterestProfile(membership.interestProfile.profile)
    ) {
      return NextResponse.json({
        completed: true,
        profile: membership.interestProfile.profile,
      });
    }

    let activeSession = await getActiveLearningSession({
      classroomStudentId: membership.id,
      topicId: null,
      sessionType: "interest_onboarding",
    });

    if (!activeSession) {
      activeSession = await createLearningSession({
        classroomStudentId: membership.id,
        topicId: null,
        sessionType: "interest_onboarding",
      });
      await appendLearningMessage({
        sessionId: activeSession.id,
        role: "assistant",
        content: buildOnboardingGreeting(membership.fullName),
      });
    }

    const messages = await listLearningMessages(activeSession.id);
    return NextResponse.json({
      completed: false,
      sessionId: activeSession.id,
      messages,
    });
  } catch (error) {
    return NextResponse.json(
      {
        error: error instanceof Error ? error.message : "Failed to load onboarding",
      },
      { status: 400 },
    );
  }
}

export async function POST(request: Request) {
  try {
    const session = await getVerifiedSession();
    const membership = await getPrimaryStudentMembership(session.user.id);
    const body = (await request.json()) as { sessionId?: string; message?: string };

    if (!membership) {
      return NextResponse.json({ error: "Student context not found" }, { status: 404 });
    }

    if (!body.message?.trim()) {
      return NextResponse.json({ error: "Message is required" }, { status: 400 });
    }

    const activeSession =
      (body.sessionId
        ? await getActiveLearningSession({
            classroomStudentId: membership.id,
            topicId: null,
            sessionType: "interest_onboarding",
          })
        : null) ??
      (await getActiveLearningSession({
        classroomStudentId: membership.id,
        topicId: null,
        sessionType: "interest_onboarding",
      })) ??
      (await createLearningSession({
        classroomStudentId: membership.id,
        topicId: null,
        sessionType: "interest_onboarding",
      }));

    await appendLearningMessage({
      sessionId: activeSession.id,
      role: "user",
      content: body.message.trim(),
    });

    const transcript = await listLearningMessages(activeSession.id);
    const result = await runInterestOnboardingTurn({
      studentName: membership.fullName,
      existingProfile: membership.interestProfile?.profile ?? null,
      messages: transcript.map((message) => ({
        role: message.role === "assistant" ? "assistant" : "user",
        content: message.content,
      })),
    });

    await appendLearningMessage({
      sessionId: activeSession.id,
      role: "assistant",
      content: result.response,
      metadata: {
        status: result.status,
      },
    });

    if (result.status === "complete" && result.profile) {
      await upsertInterestProfile({
        classroomStudentId: membership.id,
        profile: result.profile,
      });
      await markStudentOnboardingComplete(membership.id);
      const teacherSummary = await generateTeacherOnboardingSummary({
        studentName: membership.fullName,
        profile: result.profile,
      });

      await getDb().insert(notifications).values({
        id: nanoid(),
        userId: membership.classroom.teacherUserId,
        title: `${membership.fullName} onboarding summary`,
        message: teacherSummary.summary,
        type: "info",
        createdAt: new Date(),
        updatedAt: new Date(),
      });

      await completeLearningSession({
        sessionId: activeSession.id,
        summary: "Interest profile completed.",
      });

      await enqueueLearningPatternAnalysis({
        sourceType: "onboarding",
        sourceId: activeSession.id,
        organizationId: membership.classroom.organizationId,
        studentUserId: session.user.id,
        classroomStudentId: membership.id,
      }).catch((error) => {
      });
    }

    return NextResponse.json({
      sessionId: activeSession.id,
      response: result.response,
      completed: result.status === "complete",
      profile: result.profile,
    });
  } catch (error) {
    return NextResponse.json(
      {
        error: error instanceof Error ? error.message : "Failed to continue onboarding",
      },
      { status: 400 },
    );
  }
}

import { and, eq, gt, isNull } from "drizzle-orm";
import { NextResponse } from "next/server";
import { z } from "zod";

import { getDb } from "@/db";
import { classroomStudents, studentAccessTokens, users } from "@/db/schema";
import { auth } from "@/lib/auth";
import { assertWorkspacePrivacyReadiness } from "@/lib/privacy/compliance";
import { summarizeErrorForLogs } from "@/lib/privacy/logging";
import { hashOpaqueToken } from "@/lib/learning/tokens";

const studentActivationBodySchema = z.object({
  token: z.string().min(1).optional(),
  password: z.string().min(8).optional(),
  fullName: z.string().trim().min(1).optional(),
});

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const token = searchParams.get("token");

    if (!token) {
      return NextResponse.json({ error: "Missing token" }, { status: 400 });
    }

    const tokenHash = hashOpaqueToken(token);
    const record = await getDb().query.studentAccessTokens.findFirst({
      where: and(
        eq(studentAccessTokens.tokenHash, tokenHash),
        eq(studentAccessTokens.purpose, "activate"),
        isNull(studentAccessTokens.consumedAt),
        gt(studentAccessTokens.expiresAt, new Date()),
      ),
      with: {
        classroomStudent: {
          with: {
            classroom: true,
          },
        },
      },
    });

    if (!record) {
      return NextResponse.json({ valid: false }, { status: 404 });
    }

    await assertWorkspacePrivacyReadiness({
      organizationId: record.classroomStudent.classroom.organizationId,
      requireAgeMode: true,
    });

    return NextResponse.json({
      valid: true,
      student: {
        fullName: record.classroomStudent.fullName,
        email: record.classroomStudent.email,
      },
      classroom: {
        id: record.classroomStudent.classroom.id,
        title: record.classroomStudent.classroom.title,
      },
      expiresAt: record.expiresAt.toISOString(),
    });
  } catch (error) {
    if (
      error instanceof Error &&
      error.name === "GDPR_WORKSPACE_PRIVACY_INCOMPLETE"
    ) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }

    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const body = studentActivationBodySchema.parse(await request.json());

    if (!body.token || !body.password || body.password.length < 8) {
      return NextResponse.json(
        { error: "Token and a password of at least 8 characters are required." },
        { status: 400 },
      );
    }

    const normalizedName = body.fullName?.trim();

    const tokenHash = hashOpaqueToken(body.token);
    const record = await getDb().query.studentAccessTokens.findFirst({
      where: and(
        eq(studentAccessTokens.tokenHash, tokenHash),
        eq(studentAccessTokens.purpose, "activate"),
        isNull(studentAccessTokens.consumedAt),
        gt(studentAccessTokens.expiresAt, new Date()),
      ),
      with: {
        classroomStudent: true,
      },
    });

    if (!record) {
      return NextResponse.json({ error: "Invalid or expired token." }, { status: 404 });
    }

    const classroomStudent = await getDb().query.classroomStudents.findFirst({
      where: eq(classroomStudents.id, record.classroomStudentId),
      with: {
        classroom: true,
      },
    });

    await assertWorkspacePrivacyReadiness({
      organizationId: classroomStudent?.classroom.organizationId,
      requireAgeMode: true,
    });

    await auth.api.setUserPassword({
      body: {
        userId: record.userId,
        newPassword: body.password,
      },
    });

    await getDb().transaction(async (tx) => {
      await tx
        .update(users)
        .set({
          name: normalizedName || record.classroomStudent.fullName,
          emailVerified: true,
          updatedAt: new Date(),
        })
        .where(eq(users.id, record.userId));

      await tx
        .update(classroomStudents)
        .set({
          userId: record.userId,
          fullName: normalizedName || record.classroomStudent.fullName,
          inviteStatus: "accepted",
          onboardingStatus: "interest_profile_pending",
          updatedAt: new Date(),
        })
        .where(eq(classroomStudents.id, record.classroomStudentId));

      await tx
        .update(studentAccessTokens)
        .set({
          consumedAt: new Date(),
          updatedAt: new Date(),
        })
        .where(eq(studentAccessTokens.id, record.id));
    });

    return NextResponse.json({
      success: true,
      userId: record.userId,
      classroomStudentId: record.classroomStudentId,
    });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: error.errors[0]?.message ?? "Invalid request body." },
        { status: 400 },
      );
    }
    if (
      error instanceof Error &&
      error.name === "GDPR_WORKSPACE_PRIVACY_INCOMPLETE"
    ) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }

    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

