import { and, eq } from "drizzle-orm";
import { NextResponse } from "next/server";
import { nanoid } from "nanoid";

import { getDb } from "@/db";
import { sampleConversations, surveyCollaborationComments } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import {
  recordRealtimeEvent,
} from "@/lib/collaboration-service";
import {
  getSurveyPermissionContext,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;
    const body = await request.json();
    const permission = await getSurveyPermissionForSession(session, surveyId);

    if (!hasSurveyPermission(permission, "canComment")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }
    if (!permission.collaborationAllowed) {
      return NextResponse.json(
        { error: "Comments are only available for workspace surveys" },
        { status: 403 },
      );
    }

    const text = typeof body.body === "string" ? body.body.trim() : "";
    const contextType =
      body.contextType === "rehearsal" ? "rehearsal" : "creation";
    let contextId =
      typeof body.contextId === "string" && body.contextId.trim()
        ? body.contextId
        : surveyId;

    if (!text) {
      return NextResponse.json({ error: "Comment body is required" }, { status: 400 });
    }

    if (
      contextType === "rehearsal" &&
      typeof body.conversationNumber === "number" &&
      (!body.contextId || body.contextId === surveyId)
    ) {
      const [conversation] = await getDb()
        .select({ id: sampleConversations.id })
        .from(sampleConversations)
        .where(
          and(
            eq(sampleConversations.surveyId, surveyId),
            eq(sampleConversations.conversationNumber, body.conversationNumber),
          ),
        );
      if (!conversation) {
        return NextResponse.json(
          { error: "Sample conversation not found" },
          { status: 404 },
        );
      }
      contextId = conversation.id;
    }

    const commentId = nanoid();
    await getDb().transaction(async (tx) => {
      await tx.insert(surveyCollaborationComments).values({
        id: commentId,
        surveyId,
        contextType,
        contextId,
        authorId: session.user.id,
        body: text,
      });

      await recordRealtimeEvent(tx, {
        scope: "survey",
        surveyId,
        workspaceId: permission.workspaceId,
        eventType: "survey.comment_added",
        actorId: session.user.id,
        payload: {
          surveyId,
          comment: {
            id: commentId,
            contextType,
            contextId,
            body: text,
            authorId: session.user.id,
          },
        },
      });
    });

    return NextResponse.json({ id: commentId });
  } catch (error) {
    if (
      error instanceof Error &&
      (error.message === "UNAUTHENTICATED" ||
        error.message === "EMAIL_NOT_VERIFIED")
    ) {
      return NextResponse.json({ error: error.message }, { status: 401 });
    }
    console.error("[Comments] Error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

/**
 * POST /api/surveys/[surveyId]/conversations/[conversationId]/feedback
 *
 * Participant micro-rating submitted at the end of a survey conversation.
 * Anonymous respondents must present a valid survey session.
 *
 * Body: { rating?: 1-5, feltNatural?: bool, uncomfortableTopics?: bool, freeText?: string }
 */

import { NextResponse } from "next/server";
import { z } from "zod";
import { nanoid } from "nanoid";
import { eq, and } from "drizzle-orm";

import { getDb } from "@/db";
import { surveyConversations, participantFeedback } from "@/db/schema";
import { resolveRespondentAccess } from "@/lib/privacy/respondent";

const bodySchema = z.object({
  rating: z.number().int().min(1).max(5).optional(),
  feltNatural: z.boolean().optional(),
  uncomfortableTopics: z.boolean().optional().default(false),
  freeText: z.string().max(1000).optional(),
  respondentToken: z.string().min(1).optional(),
});

export async function POST(
  request: Request,
  { params }: { params: Promise<{ surveyId: string; conversationId: string }> }
) {
  try {
    const { surveyId, conversationId } = await params;

    // Verify conversation belongs to the survey
    const [conv] = await getDb()
      .select({ id: surveyConversations.id, surveyId: surveyConversations.surveyId })
      .from(surveyConversations)
      .where(
        and(
          eq(surveyConversations.id, conversationId),
          eq(surveyConversations.surveyId, surveyId)
        )
      )
      .limit(1);

    if (!conv) {
      return NextResponse.json({ error: "Conversation not found" }, { status: 404 });
    }

    // Parse + validate body
    const body = await request.json();
    const parsed = bodySchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json({ error: "Invalid body", details: parsed.error.flatten() }, { status: 400 });
    }

    const { rating, feltNatural, uncomfortableTopics, freeText, respondentToken } = parsed.data;

    const tokenRecord = await resolveRespondentAccess({
      cookieHeader: request.headers.get("cookie"),
      surveyId,
      conversationId,
      explicitToken: respondentToken ?? null,
      sessionAllowedScopes: ["respondent_session"],
      explicitAllowedScopes: [
        "respondent_resume",
        "respondent_self_service",
        "respondent_session",
      ],
    });
    if (!tokenRecord) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    // Insert feedback record
    await getDb().insert(participantFeedback).values({
      id: nanoid(),
      conversationId,
      surveyId,
      rating: rating ?? null,
      feltNatural: feltNatural ?? null,
      uncomfortableTopics: uncomfortableTopics ?? false,
      freeText: freeText ?? null,
    });


    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { eq, count, and, desc, sql } from "drizzle-orm";
import { NextResponse } from "next/server";

import { getDb } from "@/db";
import { surveyBriefs, surveys, surveyConversations } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import { env } from "@/lib/env";
import {
  getSurveyEditors,
  getSurveyPermissionContext,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

/**
 * GET - Get detailed survey info for the owner
 */
export async function GET(
  _request: Request,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;

    const [survey, briefRow] = await Promise.all([
      getDb().query.surveys.findFirst({
        where: eq(surveys.id, surveyId),
        with: {
          classroom: {
            columns: {
              title: true,
            },
          },
        },
      }),
      getDb().select().from(surveyBriefs).where(eq(surveyBriefs.surveyId, surveyId)).then((rows) => rows[0]),
    ]);

    if (!survey) {
      return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    }

    const permission = await getSurveyPermissionForSession(session, survey.id);
    if (!hasSurveyPermission(permission, "canView")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    const editors = permission.collaborationAllowed
      ? await getSurveyEditors(surveyId)
      : [];

    // Get response statistics (only count if they have at least one user message)
    const [stats] = await getDb()
      .select({
        totalResponses: count(surveyConversations.id),
      })
      .from(surveyConversations)
      .where(
        and(
          eq(surveyConversations.surveyId, surveyId),
          sql`EXISTS (
            SELECT 1 FROM jsonb_array_elements(${surveyConversations.rawConversation}) as msg 
            WHERE msg->>'role' = 'user'
          )`,
        ),
      );

    // Get completed count separately
    const [completedStats] = await getDb()
      .select({
        count: count(surveyConversations.id),
      })
      .from(surveyConversations)
      .where(
        and(
          eq(surveyConversations.surveyId, surveyId),
          eq(surveyConversations.completed, true),
        ),
      );

    // Get recent responses
    const recentResponses = await getDb()
      .select({
        id: surveyConversations.id,
        participantId: surveyConversations.participantId,
        completed: surveyConversations.completed,
        createdAt: surveyConversations.createdAt,
        updatedAt: surveyConversations.updatedAt,
      })
      .from(surveyConversations)
      .where(eq(surveyConversations.surveyId, surveyId))
      .orderBy(desc(surveyConversations.createdAt))
      .limit(10);

    // Calculate completion rate
    const totalResponses = stats?.totalResponses || 0;
    const completedResponses = completedStats?.count || 0;
    const completionRate =
      totalResponses > 0
        ? Math.round((completedResponses / totalResponses) * 100)
        : 0;

    // Calculate average duration using the stored durationMs column
    const [durationStats] = await getDb()
      .select({
        avgDuration: sql<number>`avg(${surveyConversations.durationMs})`,
      })
      .from(surveyConversations)
      .where(
        and(
          eq(surveyConversations.surveyId, surveyId),
          eq(surveyConversations.completed, true),
          sql`${surveyConversations.durationMs} > 0`,
        ),
      );

    const avgDurationMs = Math.round(Number(durationStats?.avgDuration) || 0);

    // Format duration display
    let avgDurationDisplay = "0 min";
    if (avgDurationMs > 0) {
      if (avgDurationMs < 60000) {
        const seconds = Math.round(avgDurationMs / 1000);
        avgDurationDisplay = `${seconds}s`; // e.g. "45s"
      } else {
        const minutes = Math.round(avgDurationMs / 60000);
        avgDurationDisplay = minutes === 0 ? "< 1 min" : `${minutes} min`;
      }
    }

    // Build shareable URL
    const shareableUrl = survey.shareableLink
      ? `${env.APP_BASE_URL}/s/${survey.shareableLink}`
      : null;

    return NextResponse.json({
      survey: {
        id: survey.id,
        title: survey.title,
        status: survey.status,
        description: survey.description,
        createdAt: survey.createdAt,
        updatedAt: survey.updatedAt,
        coreObjective: survey.coreObjective,
        programId: survey.programId,
        brief: briefRow?.brief || null,
        tone: survey.tone,
        shareableLink: survey.shareableLink,
        shareableUrl,
        participantLimit: survey.participantLimit,
        currentParticipants: survey.currentParticipants,
        requiredQuestions: survey.requiredQuestions,
        metrics: survey.metrics,
        language: survey.language,
        isVoice: survey.isVoice,
        media: survey.media,
        sampleConversationCount: survey.sampleConversationCount,
        userId: survey.userId,
        organizationId: survey.organizationId,
        deliveryMode: survey.deliveryMode,
        classroomId: survey.classroomId,
        classroomTitle: survey.classroom?.title ?? null,
        editors,
        permission,
      },
      stats: {
        totalResponses,
        completedResponses,
        completionRate,
        avgDuration: avgDurationDisplay,
      },
      recentResponses: recentResponses.map((r) => ({
        id: r.id,
        participantId: r.participantId,
        completed: r.completed,
        completedAt: r.completed ? r.updatedAt?.toISOString() : null,
        createdAt: r.createdAt?.toISOString(),
      })),
    });
  } catch (error) {
    if (error instanceof Error) {
      if (
        error.message === "UNAUTHENTICATED" ||
        error.message === "EMAIL_NOT_VERIFIED"
      ) {
        return NextResponse.json({ error: error.message }, { status: 401 });
      }
    }
    console.error("Error fetching survey details:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

