import { eq } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

import { getDb } from "@/db";
import { surveys } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import {
  getPersonalityPreset,
  PERSONALITY_PRESETS,
  personalityOverlaySchema,
  personalityPresetIdSchema,
} from "@/lib/education/playbooks";
import {
  getActivePersonalityAssignment,
  replacePersonalityAssignment,
} from "@/lib/education/storage";
import {
  getSurveyPermissionContext,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;
    const [survey] = await getDb()
      .select()
      .from(surveys)
      .where(eq(surveys.id, surveyId));
    if (!survey)
      return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    const permission = await getSurveyPermissionForSession(session, surveyId,);
    if (!hasSurveyPermission(permission, "canView"))
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });

    const [sampleAssignment, liveAssignment] = await Promise.all([
      getActivePersonalityAssignment(surveyId, "sample"),
      getActivePersonalityAssignment(surveyId, "live"),
    ]);

    return NextResponse.json({
      presets: PERSONALITY_PRESETS,
      active: {
        sample: sampleAssignment?.assignment ?? null,
        live: liveAssignment?.assignment ?? null,
      },
    });
  } catch (error) {
    console.error("[Personalities GET] Error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;
    const [survey] = await getDb()
      .select()
      .from(surveys)
      .where(eq(surveys.id, surveyId));
    if (!survey)
      return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    const permission = await getSurveyPermissionForSession(session, surveyId,);
    if (!hasSurveyPermission(permission, "canEdit")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    const body = await req.json();
    const mode: "live" | "sample" = body.mode === "live" ? "live" : "sample";
    const presetId = personalityPresetIdSchema.parse(body.presetId);
    const overlay = personalityOverlaySchema.parse(body.overlay ?? {});

    const current = await getActivePersonalityAssignment(surveyId, mode);
    const assignment = {
      version: (current?.assignment.version ?? 0) + 1,
      mode,
      presetId,
      overlay,
      createdAt: new Date().toISOString(),
    };

    await replacePersonalityAssignment({
      surveyId,
      mode,
      assignment,
    });

    if (body.applyToLive && mode === "sample") {
      const liveCurrent = await getActivePersonalityAssignment(
        surveyId,
        "live",
      );
      await replacePersonalityAssignment({
        surveyId,
        mode: "live",
        assignment: {
          ...assignment,
          mode: "live",
          version: (liveCurrent?.assignment.version ?? 0) + 1,
          createdAt: new Date().toISOString(),
        },
      });
    }

    return NextResponse.json({
      success: true,
      preset: getPersonalityPreset(presetId),
      assignment,
    });
  } catch (error) {
    console.error("[Personalities POST] Error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

import { eq } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

import { getDb } from "@/db";
import { playbooks, surveys } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import { playbookAuthorInputSchema } from "@/lib/education/playbooks";
import { compilePlaybookAuthorInput } from "@/lib/education/playbook-workflow";
import {
  approvePlaybookVersion,
  archivePlaybook,
  attachPlaybookToSurvey,
  createPlaybookVersion,
  detachPlaybookFromSurvey,
} from "@/lib/education/storage";
import {
  getSurveyPermissionContext,
  isWorkspaceOwner,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ surveyId: string; playbookId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId, playbookId } = await params;
    const body = await req.json();
    const action = String(body.action || "");

    const [survey, playbook] = await Promise.all([
      getDb().select().from(surveys).where(eq(surveys.id, surveyId)).then((rows) => rows[0]),
      getDb().select().from(playbooks).where(eq(playbooks.id, playbookId)).then((rows) => rows[0]),
    ]);
    if (!survey || !playbook) return NextResponse.json({ error: "Not found" }, { status: 404 });

    const permission = await getSurveyPermissionForSession(session, surveyId);
    if (!hasSurveyPermission(permission, "canEdit")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    if (playbook.scope === "workspace" && survey.organizationId) {
      const isOwner = await isWorkspaceOwner(session.user.id, survey.organizationId);
      if (!isOwner && action !== "attach" && action !== "detach") {
        return NextResponse.json({ error: "Only workspace owners can edit workspace playbooks." }, { status: 403 });
      }
    }

    switch (action) {
      case "approve": {
        const versionId = String(body.versionId || playbook.activeVersionId || "");
        if (!versionId) {
          return NextResponse.json({ error: "versionId is required" }, { status: 400 });
        }
        await approvePlaybookVersion({ playbookId, versionId, approvedBy: session.user.id });
        return NextResponse.json({ success: true });
      }
      case "archive": {
        await archivePlaybook(playbookId);
        return NextResponse.json({ success: true });
      }
      case "attach": {
        await attachPlaybookToSurvey({
          surveyId,
          playbookId,
          attachedBy: session.user.id,
        });
        return NextResponse.json({ success: true });
      }
      case "detach": {
        await detachPlaybookFromSurvey(surveyId, playbookId);
        return NextResponse.json({ success: true });
      }
      case "edit": {
        const parsed = playbookAuthorInputSchema.safeParse(body.input);
        if (!parsed.success) {
          return NextResponse.json({ error: parsed.error.errors[0]?.message ?? "Invalid input" }, { status: 400 });
        }
        const compiled = await compilePlaybookAuthorInput(parsed.data);
        const version = await createPlaybookVersion({
          playbookId,
          createdBy: session.user.id,
          input: parsed.data,
          interpretation: compiled.interpretation,
          preview: compiled.preview,
          status: compiled.status,
        });
        return NextResponse.json({
          success: true,
          version,
          interpretation: compiled.interpretation,
          preview: compiled.preview,
          status: compiled.status,
        });
      }
      default:
        return NextResponse.json({ error: "Unsupported action" }, { status: 400 });
    }
  } catch (error) {
    console.error("[Playbook PATCH] Error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

