export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;
    const [survey] = await getDb().select().from(surveys).where(eq(surveys.id, surveyId));
    if (!survey) return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    const permission = await getSurveyPermissionForSession(session, surveyId);
    if (!hasSurveyPermission(permission, "canEdit")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    const body = await req.json();
    const content = String(body.content || "").trim();
    if (!content) return NextResponse.json({ error: "content is required" }, { status: 400 });

    const [briefRow, latestSample, personality, playbooks] = await Promise.all([
      getResearchBrief(surveyId),
      getDb()
        .select()
        .from(sampleConversations)
        .where(eq(sampleConversations.surveyId, surveyId))
        .orderBy(desc(sampleConversations.conversationNumber))
        .then((rows) => rows[0]),
      getActivePersonalityAssignment(surveyId, "sample"),
      listPlaybooksForSurvey({ surveyId, organizationId: survey.organizationId }),
    ]);
    if (!briefRow) {
      return NextResponse.json({ error: "Survey brief is not ready." }, { status: 400 });
    }

    const thread = await getOrCreateRefinementThread({
      surveyId,
      createdBy: session.user.id,
      sampleConversationId: latestSample?.id ?? null,
    });

    await appendRefinementMessage({
      threadId: thread.id,
      role: "user",
      content,
    });

    const transcript = Array.isArray(latestSample?.messages)
      ? latestSample.messages
          .map((message: ChatMessage) => `${message.role}: ${message.content}`)
          .join("\n\n")
      : "";
    const activePreset = getPersonalityPreset(personality?.assignment.presetId);
    const assistantResult = await buildRefinementAssistantResponse({
      creatorMessage: content,
      surveyTitle: survey.title || briefRow.brief.title,
      currentPersonalityLabel: activePreset.label,
      playbookSummaries: playbooks
        .filter((record) => record.activeVersion)
        .map((record) => `${record.playbook.name}: ${record.activeVersion!.interpretation.summary}`),
      latestSampleTranscript: transcript,
      brief: briefRow.brief,
    });

    await appendRefinementMessage({
      threadId: thread.id,
      role: "assistant",
      content: assistantResult.reply,
    });

    const savedProposals = await Promise.all(
      assistantResult.proposals.map((proposal) =>
        createRefinementProposal({
          threadId: thread.id,
          surveyId,
          proposal,
        }),
      ),
    );

    return NextResponse.json({
      reply: assistantResult.reply,
      proposals: savedProposals,
    });
  } catch (error) {
    console.error("[Refinement POST] Error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { and, eq, or } from "drizzle-orm";
import { NextResponse } from "next/server";

import { getDb } from "@/db";
import {
  surveyCoveragePlans,
  surveyEvidence,
  surveySessionInsights,
  surveySessions,
  surveyTurns,
  surveys,
} from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import type { AnalyticsSessionDetail } from "@/lib/analytics";
import type {
  ConversationInsight,
  CoverageNode,
  EvidenceRecord,
} from "@/lib/education/types";
import {
  conversationInsightSchema,
  evidenceRecordSchema,
} from "@/lib/education/types";
import {
  getSurveyPermissionContext,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

export async function GET(
  _request: Request,
  { params }: { params: Promise<{ surveyId: string; responseId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId, responseId } = await params;

    const [survey] = await getDb()
      .select({
        id: surveys.id,
        title: surveys.title,
        userId: surveys.userId,
      })
      .from(surveys)
      .where(eq(surveys.id, surveyId));

    if (!survey) {
      return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    }

    const permission = await getSurveyPermissionForSession(session, surveyId);
    if (!hasSurveyPermission(permission, "canView")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    const [sessionRow] = await getDb()
      .select()
      .from(surveySessions)
      .where(
        and(
          eq(surveySessions.surveyId, surveyId),
          or(
            eq(surveySessions.id, responseId),
            eq(surveySessions.sourceConversationId, responseId),
          ),
        ),
      );

    if (!sessionRow) {
      return NextResponse.json({ error: "Response not found" }, { status: 404 });
    }

    const [insightRow, turnRows, evidenceRows, activePlan] = await Promise.all([
      getDb()
        .select()
        .from(surveySessionInsights)
        .where(eq(surveySessionInsights.sessionId, sessionRow.id))
        .then((rows) => rows[0]),
      getDb()
        .select()
        .from(surveyTurns)
        .where(eq(surveyTurns.sessionId, sessionRow.id)),
      getDb()
        .select()
        .from(surveyEvidence)
        .where(eq(surveyEvidence.sessionId, sessionRow.id)),
      getDb()
        .select()
        .from(surveyCoveragePlans)
        .where(
          and(
            eq(surveyCoveragePlans.surveyId, surveyId),
            eq(surveyCoveragePlans.isActive, true),
          ),
        )
        .then((rows) => rows[0]),
    ]);

    const insightResult = conversationInsightSchema.safeParse(insightRow?.insight);
    const insight: ConversationInsight | undefined = insightResult.success
      ? insightResult.data
      : undefined;
    const nodeCoverageMap = sessionRow.sessionState.coverageByNode || {};
    const planNodes = activePlan?.plan.nodes || [];
    const evidence = evidenceRows
      .map((row) => evidenceRecordSchema.safeParse(row.metadata))
      .filter((result): result is { success: true; data: EvidenceRecord } => result.success)
      .map((result) => result.data);

    const payload: AnalyticsSessionDetail = {
      id: sessionRow.id,
      surveyId: survey.id,
      surveyTitle: survey.title,
      sessionType: sessionRow.sessionType,
      sourceConversationId: sessionRow.sourceConversationId,
      startedAt: sessionRow.createdAt.toISOString(),
      completedAt: sessionRow.completedAt?.toISOString() ?? null,
      status: sessionRow.sessionStatus,
      summary:
        insight?.summary ||
        sessionRow.summary ||
        "No session summary is available yet.",
      keyFindings: Array.isArray(insight?.keyFindings) ? insight.keyFindings : [],
      risks: Array.isArray(insight?.risks) ? insight.risks : [],
      reliabilityPercent: Math.round(
        (sessionRow.sessionState.reliabilityScore || 0) * 100,
      ),
      completenessPercent: Math.round(
        (sessionRow.sessionState.overallCoverage || 0) * 100,
      ),
      fatiguePercent: Math.round(
        (sessionRow.sessionState.fatigueScore || 0) * 100,
      ),
      nodeCoverage: planNodes.map((node: CoverageNode) => ({
        id: node.id,
        label: node.label,
        description: node.description,
        coveragePercent: Math.round((nodeCoverageMap[node.id] || 0) * 100),
      })),
      notableQuotes: Array.isArray(insight?.notableQuotes) ? insight.notableQuotes : [],
      evidence,
      transcript: turnRows
        .sort((a, b) => a.turnIndex - b.turnIndex)
        .map((turn) => ({
          id: turn.id,
          role: turn.role,
          content: turn.content,
        })),
    };

    return NextResponse.json(payload);
  } catch (error) {
    if (
      error instanceof Error &&
      (error.message === "UNAUTHENTICATED" ||
        error.message === "EMAIL_NOT_VERIFIED")
    ) {
      return NextResponse.json({ error: error.message }, { status: 401 });
    }

    console.error("[Response Details API] Error:", error);
    return NextResponse.json(
      { error: "Failed to fetch response details" },
      { status: 500 },
    );
  }
}

import { eq, desc, count, and } from "drizzle-orm";
import { NextResponse } from "next/server";

import { getDb } from "@/db";
import { surveyConversations } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
import {
  getSurveyPermissionContext,
  getSurveyPermissionForSession,
  hasSurveyPermission,
} from "@/lib/workspace-access";

type ConversationMessage = {
  role: string;
  content: string;
  timestamp?: string;
};

function normalizeConversationMessages(value: unknown): ConversationMessage[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (typeof item !== "object" || item === null) {
      return [];
    }

    const role = typeof item.role === "string" ? item.role : null;
    const content = typeof item.content === "string" ? item.content : null;
    const timestamp =
      typeof item.timestamp === "string" ? item.timestamp : undefined;

    if (!role || !content) {
      return [];
    }

    return [{ role, content, timestamp }];
  });
}

/**
 * GET - Get all responses for a survey
 */
export async function GET(
  request: Request,
  { params }: { params: Promise<{ surveyId: string }> },
) {
  try {
    const session = await getVerifiedSession();
    const { surveyId } = await params;
    const { searchParams } = new URL(request.url);

    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "10");
    const status = searchParams.get("status") || "all";
    const offset = (page - 1) * limit;

    const permission = await getSurveyPermissionForSession(session, surveyId);
    if (!hasSurveyPermission(permission, "canView")) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    // Build where clause
    const whereConditions = [eq(surveyConversations.surveyId, surveyId)];
    if (status === "completed") {
      whereConditions.push(eq(surveyConversations.completed, true));
    } else if (status === "in_progress") {
      whereConditions.push(eq(surveyConversations.completed, false));
    }

    // Get total count
    const [totalResult] = await getDb()
      .select({ count: count() })
      .from(surveyConversations)
      .where(and(...whereConditions));

    const total = totalResult?.count || 0;

    // Get paginated responses
    const responses = await getDb()
      .select()
      .from(surveyConversations)
      .where(and(...whereConditions))
      .orderBy(desc(surveyConversations.createdAt))
      .limit(limit)
      .offset(offset);

    // Format responses for frontend
    const formattedResponses = responses.map((r) => {
      const messages = normalizeConversationMessages(r.rawConversation);
      const messageCount = messages?.length || 0;

      // Calculate duration from first to last message
      let duration = "N/A";
      if (messages && messages.length >= 2) {
        const firstTimestamp = messages[0]?.timestamp;
        const lastTimestamp = messages[messages.length - 1]?.timestamp;
        if (firstTimestamp && lastTimestamp) {
          const durationMs =
            new Date(lastTimestamp).getTime() -
            new Date(firstTimestamp).getTime();
          const minutes = Math.floor(durationMs / 60000);
          const seconds = Math.floor((durationMs % 60000) / 1000);
          duration = `${minutes}:${seconds.toString().padStart(2, "0")}`;
        }
      }

      // Simple sentiment analysis based on keywords
      let sentiment: "positive" | "neutral" | "negative" | null = null;
      if (r.completed && messages) {
        const allText = messages
          .filter((m) => m.role === "user")
          .map((m) => m.content.toLowerCase())
          .join(" ");

        const positiveWords = [
          "great",
          "love",
          "excellent",
          "amazing",
          "good",
          "happy",
          "satisfied",
          "helpful",
          "wonderful",
          "best",
        ];
        const negativeWords = [
          "bad",
          "terrible",
          "awful",
          "hate",
          "poor",
          "frustrated",
          "disappointed",
          "unhappy",
          "worst",
          "issue",
        ];

        const positiveCount = positiveWords.filter((w) =>
          allText.includes(w),
        ).length;
        const negativeCount = negativeWords.filter((w) =>
          allText.includes(w),
        ).length;

        if (positiveCount > negativeCount) sentiment = "positive";
        else if (negativeCount > positiveCount) sentiment = "negative";
        else sentiment = "neutral";
      }

      // Extract key insights (user messages excerpts)
      const keyInsights =
        messages
          ?.filter((m) => m.role === "user")
          .slice(0, 3)
          .map(
            (m) =>
              m.content.slice(0, 50) + (m.content.length > 50 ? "..." : ""),
          ) || [];

      return {
        id: r.id,
        participantId: r.participantId || "Anonymous",
        status: r.completed ? "completed" : "abandoned",
        completedAt: r.updatedAt?.toISOString() || null,
        createdAt: r.createdAt?.toISOString() || null,
        duration,
        sentiment,
        keyInsights,
        messageCount,
      };
    });

    return NextResponse.json({
      responses: formattedResponses,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (
        error.message === "UNAUTHENTICATED" ||
        error.message === "EMAIL_NOT_VERIFIED"
      ) {
        return NextResponse.json({ error: error.message }, { status: 401 });
      }
    }
    console.error("Error fetching survey responses:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

import { eq, and, isNull } from "drizzle-orm";
import { NextResponse } from "next/server";

import { getDb } from "@/db";
import { surveys } from "@/db/schema";
import { getVerifiedSession } from "@/lib/auth/session";
