type RespondRouteBody = {
  messages?: unknown[];
  context?: {
    conversationId?: string;
  };
  conversationId?: string;
  language?: unknown;
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isRespondentLanguage(value: unknown): value is RespondentLanguage {
  return (
    value === "en" ||
    value === "fr" ||
    value === "de" ||
    value === "es" ||
    value === "it"
  );
}

function getRequestedLanguage(value: unknown): RespondentLanguage | undefined {
  return isRespondentLanguage(value) ? value : undefined;
}

function parseRespondRouteBody(value: unknown): RespondRouteBody {
  if (!isRecord(value)) {
    return {};
  }

  const context = isRecord(value.context) ? value.context : undefined;

  return {
    messages: Array.isArray(value.messages) ? value.messages : undefined,
    context:
      context && typeof context.conversationId === "string"
        ? { conversationId: context.conversationId }
        : undefined,
    conversationId:
      typeof value.conversationId === "string" ? value.conversationId : undefined,
    language: value.language,
  };
}

function getConversationIdFromBody(body: RespondRouteBody): string | undefined {
  if (typeof body.context?.conversationId === "string") {
    return body.context.conversationId;
  }

  return typeof body.conversationId === "string"
    ? body.conversationId
    : undefined;
}

function getRawMessages(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

function jsonNoStore(body: unknown, init?: ResponseInit) {
  const response = NextResponse.json(body, init);
  response.headers.set("Cache-Control", "no-store");
  return response;
}

type ClassroomAssignedAccess =
  | {
      mode: "classroom_assigned";
      classroomStudent: {
        id: string;
        userId: string | null;
      };
    }
  | { mode: "link" };

async function resolveClassroomAssignedAccess(
  survey: typeof surveys.$inferSelect,
): Promise<
  | { success: true; data: ClassroomAssignedAccess }
  | { success: false; response: NextResponse }
> {
  if (survey.deliveryMode !== "classroom_assigned") {
    return {
      success: true,
      data: { mode: "link" },
    };
  }

  if (!survey.classroomId) {
    return {
      success: false,
      response: jsonNoStore(
        { error: "Classroom-assigned survey is misconfigured" },
        { status: 400 },
      ),
    };
  }

  const session = await getVerifiedSession().catch(() => null);
  if (!session) {
    return {
      success: false,
      response: jsonNoStore(
        { error: "Sign in with your classroom account to access this survey" },
        { status: 403 },
      ),
    };
  }

  const classroomStudent = await getDb().query.classroomStudents.findFirst({
    where: and(
      eq(classroomStudents.classroomId, survey.classroomId),
      eq(classroomStudents.userId, session.user.id),
    ),
    columns: {
      id: true,
      userId: true,
    },
  });

  if (!classroomStudent) {
    return {
      success: false,
      response: jsonNoStore(
        { error: "You do not have access to this classroom survey" },
        { status: 403 },
      ),
    };
  }

  return {
    success: true,
    data: {
      mode: "classroom_assigned",
      classroomStudent,
    },
  };
}

function buildSurveyResponsePayload(survey: typeof surveys.$inferSelect) {
  return {
    id: survey.id,
    title: survey.title,
    objective: survey.coreObjective,
    tone: survey.tone,
    requiredQuestions: survey.requiredQuestions || [],
    isVoice: survey.isVoice,
    programId: survey.programId,
  };
}

async function respondWithExistingConversation(input: {
  request: Request;
  survey: typeof surveys.$inferSelect;
  conversation: typeof surveyConversations.$inferSelect;
}) {
  const respondentSessionToken = await issueRespondentSessionToken({
    surveyId: input.survey.id,
    conversationId: input.conversation.id,
    participantId: input.conversation.participantId,
    ipAddress: input.request.headers.get("x-forwarded-for")?.split(",")[0]?.trim(),
  });
  const usableMessages = getUsableRespondentMessages(
    toVisibleConversationMessages(
      toPersistedUIChatMessages(
        getRawMessages(input.conversation.rawConversation),
        ["user", "assistant"],
      ),
    ),
    input.survey.isVoice,
  );

  if (input.conversation.completed) {
    const completedResponse = jsonNoStore({
      completed: true,
      survey: {
        id: input.survey.id,
        title: input.survey.title,
        isVoice: input.survey.isVoice,
      },
      conversationId: input.conversation.id,
      participantId: input.conversation.participantId,
    });
    completedResponse.cookies.set(
      getRespondentSessionCookieName(input.survey.id),
      respondentSessionToken,
      getRespondentSessionCookieOptions(),
    );
    return completedResponse;
  }

  const response = jsonNoStore({
    survey: buildSurveyResponsePayload(input.survey),
    conversationId: input.conversation.id,
    participantId: input.conversation.participantId,
    messages: usableMessages,
  });
  response.cookies.set(
    getRespondentSessionCookieName(input.survey.id),
    respondentSessionToken,
    getRespondentSessionCookieOptions(),
  );
  return response;
}

export async function GET(
  request: Request,
  { params }: { params: Promise<{ shareableLink: string }> },
) {
  try {
    const { shareableLink } = await params;
    const { searchParams } = new URL(request.url);
    const language = getRequestedLanguage(searchParams.get("language"));
    const resumeToken = searchParams.get(RESPONDENT_RESUME_QUERY_PARAM);

    const survey = await getDb()
      .select()
      .from(surveys)
      .where(eq(surveys.shareableLink, shareableLink))
      .then((rows) => rows[0]);

    if (!survey) {
      return jsonNoStore({ error: "Survey not found" }, { status: 404 });
    }
    if (survey.status !== "active") {
      return jsonNoStore(
        { error: "Survey is not active" },
        { status: 403 },
      );
    }

    const access = await resolveClassroomAssignedAccess(survey);
    if (!access.success) {
      return access.response;
    }

    const authorizedAccess = await resolveRespondentAccess({
      cookieHeader: request.headers.get("cookie"),
      surveyId: survey.id,
      explicitToken: resumeToken,
      sessionAllowedScopes: ["respondent_session"],
      explicitAllowedScopes: ["respondent_resume"],
    });
    const existingConversationId = authorizedAccess?.conversationId ?? null;

    if (existingConversationId) {
      const [existingConversation] = await getDb()
        .select()
        .from(surveyConversations)
        .where(eq(surveyConversations.id, existingConversationId));

      if (existingConversation && existingConversation.surveyId === survey.id) {
        if (
          access.data.mode === "classroom_assigned" &&
          existingConversation.participantId !== access.data.classroomStudent.id
        ) {
          return jsonNoStore({ error: "Unauthorized" }, { status: 403 });
        }

        return respondWithExistingConversation({
          request,
          survey,
          conversation: existingConversation,
        });
      }
    }

    if (
      survey.deliveryMode !== "classroom_assigned" &&
      survey.currentParticipants >= survey.participantLimit
    ) {
      return jsonNoStore(
        { error: "Survey has reached its participant limit" },
        { status: 403 },
      );
    }

    if (access.data.mode === "classroom_assigned") {
      const existingClassroomConversation = await getDb()
        .select()
        .from(surveyConversations)
        .where(
          and(
            eq(surveyConversations.surveyId, survey.id),
            eq(
              surveyConversations.participantId,
              access.data.classroomStudent.id,
            ),
          ),
        )
        .orderBy(desc(surveyConversations.updatedAt))
        .then((rows) => rows[0] ?? null);

      if (existingClassroomConversation) {
        return respondWithExistingConversation({
          request,
          survey,
          conversation: existingClassroomConversation,
        });
      }
    }

    const conversationId = nanoid();
    const participantId =
      access.data.mode === "classroom_assigned"
        ? access.data.classroomStudent.id
        : nanoid(8);
    const respondentSessionToken = await issueRespondentSessionToken({
      surveyId: survey.id,
      conversationId,
      participantId,
      ipAddress: request.headers.get("x-forwarded-for")?.split(",")[0]?.trim(),
    });
    const greetingText = buildRespondentVoiceGreeting({
      language: getRequestedLanguage(language || survey.language) || "en",
      surveyTitle: survey.title,
      brief: null,
    });
    const greetingMessage = survey.isVoice
      ? null
      : {
          id: nanoid(),
          role: "assistant",
          content: greetingText,
          parts: [{ type: "text", text: greetingText }],
          timestamp: new Date().toISOString(),
        };

    await getDb().insert(surveyConversations).values({
      id: conversationId,
      surveyId: survey.id,
      participantId,
      rawConversation: greetingMessage ? [greetingMessage] : [],
      completed: false,
      originalLanguage: language || survey.language || "en",
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    const response = jsonNoStore({
      survey: {
        id: survey.id,
        title: survey.title,
        objective: survey.coreObjective,
        tone: survey.tone,
        requiredQuestions: survey.requiredQuestions || [],
        isVoice: survey.isVoice,
        programId: survey.programId,
      },
      conversationId,
      participantId,
      messages: greetingMessage ? [greetingMessage] : [],
    });
    response.cookies.set(
      getRespondentSessionCookieName(survey.id),
      respondentSessionToken,
      getRespondentSessionCookieOptions(),
    );
    return response;
  } catch (error) {
    return jsonNoStore(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

export async function POST(
  req: Request,
  { params }: { params: Promise<{ shareableLink: string }> },
) {
  try {
    const body = parseRespondRouteBody(await req.json());
    const rawMessages = getRawMessages(body.messages);
    const language = getRequestedLanguage(body.language);
    const { shareableLink } = await params;

    const [survey] = await getDb()
      .select()
      .from(surveys)
      .where(eq(surveys.shareableLink, shareableLink))
      .limit(1);
    if (!survey) {
      return jsonNoStore({ error: "Survey not found" }, { status: 404 });
    }
    if (survey.status !== "active") {
      return jsonNoStore(
        { error: "Survey is not active" },
        { status: 403 },
      );
    }

    const conversationId = getConversationIdFromBody(body);
    if (!conversationId) {
      return jsonNoStore(
        { error: "Conversation ID is required" },
        { status: 400 },
      );
    }

    const [conversation, briefRow, planRow] = await Promise.all([
      getDb()
        .select()
        .from(surveyConversations)
        .where(eq(surveyConversations.id, conversationId))
        .then((rows) => rows[0]),
      getResearchBrief(survey.id),
      getActiveCoveragePlan(survey.id),
    ]);
    const access = await resolveClassroomAssignedAccess(survey);
    if (!access.success) {
      return access.response;
    }

    if (!conversation || conversation.surveyId !== survey.id) {
      return jsonNoStore(
        { error: "Conversation not found" },
        { status: 404 },
      );
    }
    if (
      access.data.mode === "classroom_assigned" &&
      conversation.participantId !== access.data.classroomStudent.id
    ) {
      return jsonNoStore({ error: "Unauthorized" }, { status: 403 });
    }
    const respondentAccess = await resolveRespondentAccess({
      cookieHeader: req.headers.get("cookie"),
      surveyId: survey.id,
      conversationId: conversation.id,
      sessionAllowedScopes: ["respondent_session"],
    });
    if (!respondentAccess) {
      return jsonNoStore({ error: "Unauthorized" }, { status: 403 });
    }
    if (!briefRow || !planRow) {
      return jsonNoStore(
        { error: "This survey does not have an approved education brief yet." },
        { status: 400 },
      );
    }

    const persistedIncomingMessages = toPersistedUIChatMessages(rawMessages, [
      "user",
      "assistant",
    ]);
    const visibleMessages = toVisibleConversationMessages(
      persistedIncomingMessages,
    );

    if (
      !hasUserTurn(
        toPersistedUIChatMessages(
          getRawMessages(conversation.rawConversation),
          ["user", "assistant"],
        ),
      ) &&
      visibleMessages.some((message) => message.role === "user")
    ) {
      const admission = await admitParticipantOnFirstUserTurn({
        surveyId: survey.id,
        conversationId: conversation.id,
        enforceParticipantLimit: survey.deliveryMode !== "classroom_assigned",
      });

      if (!admission.allowed) {
        return jsonNoStore(
          { error: "Survey has reached participant limit" },
          { status: 403 },
        );
      }
    }

    let sessionRow = await getSessionBySourceId(conversation.id);
    if (!sessionRow) {
      sessionRow = await ensureSession({
        surveyId: survey.id,
        sessionType: "live",
        sourceConversationId: conversation.id,
        language: getRequestedLanguage(language || survey.language) || "en",
        respondentId: conversation.participantId,
        initialState: createInitialSessionState({
          surveyId: survey.id,
          sessionId: nanoid(),
          sessionType: "live",
          language: getRequestedLanguage(language || survey.language) || "en",
          coveragePlan: planRow.plan,
        }),
      });
    }

    const [activeLiveProfile, sampleFallbackProfile, runtimeLayers] =
      await Promise.all([
        getActiveConductingProfile(survey.id, "live"),
        getActiveConductingProfile(survey.id, "sample"),
        getConductingRuntimeLayers({
          surveyId: survey.id,
          organizationId: survey.organizationId,
          classroomId: survey.classroomId,
          programId: survey.programId,
          language:
            getRequestedLanguage(language || survey.language) ||
            survey.language ||
            "en",
          mode: "live",
        }),
      ]);

    const promptParts = buildConductingSystemPromptParts({
      brief: briefRow.brief,
      coveragePlan: planRow.plan,
      sessionState: sessionRow.sessionState,
      sessionType: "live",
      conductingProfile:
        activeLiveProfile?.profile ?? sampleFallbackProfile?.profile ?? null,
      playbookContext: runtimeLayers.playbookContext,
      personalityContext: runtimeLayers.personalityContext,
      expertGuidanceContext: runtimeLayers.expertGuidanceContext,
      toolContext: {
        canFinishSurvey: true,
        canShowMedia: false,
      },
    });
    const systemPrompt = `${promptParts.dynamicSystemPrompt}

Respond to the user in the language they are speaking to you in. Match the language of each user message naturally.`;

    let currentSessionState = sessionRow.sessionState;
    let completedByTool = false;

    const tools = {
      finishSurvey: tool({
        description: getRespondentFinishSurveyToolDefinition().description,
        inputSchema: z.object({}),
        execute: async () => {
          const threshold =
            planRow.plan.completionRule.minimumRequiredNodeCoverage;
          if (
            currentSessionState.status !== "completed" &&
            currentSessionState.overallCoverage < threshold
          ) {
            return {
              error: "Interview coverage is not high enough to finish yet",
              currentCoverage: currentSessionState.overallCoverage,
              requiredCoverage: threshold,
            };
          }

          if (currentSessionState.status !== "completed") {
            currentSessionState = {
              ...currentSessionState,
              status: "completed",
              stopReason: "agent_finish_signal",
            };
            await updateSessionState(sessionRow.id, currentSessionState);
          }

          completedByTool = true;
          return { success: true, message: "Survey marked as complete" };
        },
      }),
    };

    const starterMessages: Awaited<ReturnType<typeof toModelMessages>> = [
      {
        role: "user",
        content:
          "Start the interview by greeting the participant and asking the first best question.",
      },
    ];
    const modelMessages =
      rawMessages.length > 0
        ? await toModelMessages(rawMessages)
        : starterMessages;

    const result = streamAIResponse(
      modelMessages,
      systemPrompt,
      {
        surveyId: survey.id,
        maxTokens: 550,
        temperature: 0.4,
        promptCache: {
          namespace: "conducting-respond",
          staticSystemPrompt: promptParts.staticSystemPrompt,
        },
        tools,
        stopWhen: stepCountIs(5),
        observability: {
          feature: "survey_conducting",
          scenarioType: "respondent_turn",
          resourceType: "survey_session",
          resourceId: sessionRow.id,
          metadata: {
            surveyId: survey.id,
            guidanceVersionIds: runtimeLayers.expertGuidanceVersionIds,
          },
        },
      },
    );

    return result.toUIMessageStreamResponse({
      originalMessages: toUIMessages(persistedIncomingMessages),
      onFinish: async ({ messages }) => {
        const persistedMessages = toVisibleConversationMessages(
          toPersistedUIChatMessages(messages, ["user", "assistant"]),
        );

        await getDb()
          .update(surveyConversations)
          .set({
            rawConversation: persistedMessages,
            completed:
              completedByTool || currentSessionState.status === "completed",
            updatedAt: new Date(),
          })
          .where(eq(surveyConversations.id, conversation.id));

        if (persistedMessages.some((message) => message.role === "user")) {
          if (!completedByTool) {
            const { nextState } = await finalizeConductingTurn({
              surveyId: survey.id,
              sessionId: sessionRow.id,
              brief: briefRow.brief,
              coveragePlan: planRow.plan,
              sessionState: currentSessionState,
              messages: persistedMessages,
            });
            currentSessionState = nextState;
          }

          await enqueueConversationInsights({
            conversationId: conversation.id,
            surveyId: survey.id,
            userId: survey.userId,
          }).catch((error) => {
          });

          await getDb()
            .update(surveyConversations)
            .set({
              completed:
                completedByTool || currentSessionState.status === "completed",
              updatedAt: new Date(),
            })
            .where(eq(surveyConversations.id, conversation.id));
        }
      },
    });
  } catch (error) {
    return jsonNoStore(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

import { eq } from "drizzle-orm";
import { NextResponse } from "next/server";

import { getDb } from "@/db";
import { surveys } from "@/db/schema";
import { getResearchBrief } from "@/lib/education/storage";

/**
 * Get a survey by its shareable link (public endpoint)
 */
export async function GET(
  _request: Request,
  { params }: { params: Promise<{ shareableLink: string }> },
) {
  try {
    const { shareableLink } = await params;

    const [survey] = await getDb()
      .select({
        id: surveys.id,
        title: surveys.title,
        programId: surveys.programId,
        coreObjective: surveys.coreObjective,
        status: surveys.status,
        currentParticipants: surveys.currentParticipants,
        participantLimit: surveys.participantLimit,
      })
      .from(surveys)
      .where(eq(surveys.shareableLink, shareableLink));

    if (!survey) {
      return NextResponse.json({ error: "Survey not found" }, { status: 404 });
    }

    if (survey.status !== "active") {
      return NextResponse.json(
        { error: "Survey is not active" },
        { status: 403 },
      );
    }

    const briefRow = await getResearchBrief(survey.id);

    return NextResponse.json({
      survey: {
        ...survey,
        brief: briefRow?.brief || null,
      },
    });
  } catch (error) {
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 },
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { users } from "@/db/schema";
import { eq } from "drizzle-orm";
import { auth } from "@/lib/auth";
import { headers } from "next/headers";
import { normalizeAppLocale, isAppLocale } from "@/lib/i18n/config";
import { cookies } from "next/headers";

/**
 * GET /api/user/language
 * Fetch the current user's preferred language
 */
export async function GET() {
  try {
    const session = await auth.api.getSession({
      headers: await headers(),
    });

    if (!session?.user?.id) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const [user] = await getDb()
      .select({ preferredLanguage: users.preferredLanguage, uiLocale: users.uiLocale })
      .from(users)
      .where(eq(users.id, session.user.id))
      .limit(1);

    const uiLocale = normalizeAppLocale(user?.uiLocale ?? user?.preferredLanguage);

    return NextResponse.json({
      uiLocale,
      preferredLanguage: uiLocale,
    });
  } catch (error) {
    return NextResponse.json(
      { error: "Failed to fetch language" },
      { status: 500 },
    );
  }
}

/**
 * PATCH /api/user/language
 * Update the current user's preferred language
 */
export async function PATCH(request: NextRequest) {
  try {
    const session = await auth.api.getSession({
      headers: await headers(),
    });

    if (!session?.user?.id) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();
    const { language } = body;

    if (!isAppLocale(language)) {
      return NextResponse.json({ error: "Invalid language" }, { status: 400 });
    }

    await getDb()
      .update(users)
      .set({ preferredLanguage: language, uiLocale: language })
      .where(eq(users.id, session.user.id));

    (await cookies()).set("NEXT_LOCALE", language, {
      path: "/",
      maxAge: 60 * 60 * 24 * 365,
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
    });

    return NextResponse.json({
      success: true,
      uiLocale: language,
      preferredLanguage: language,
    });
  } catch (error) {
    return NextResponse.json(
      { error: "Failed to update language" },
      { status: 500 },
    );
  }
}

"use client";

import { useChat } from "@ai-sdk/react";
import { UIMessage, DefaultChatTransport, isTextUIPart, isToolUIPart, getToolName } from "ai";
import { useState, useRef, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import {
    History,
    ChevronDown,
    PlusCircle,
    Bot,
    User,
    Loader2,
    Send,
    Mic,
    Square,
    Search,
    Table,
    BarChart2,
    Sparkles
} from "lucide-react";
import { cn } from "@/lib/utils";
import {
    GenerativeAnalyticsRenderer,
    RenderChartResult,
    RenderTableResult,
    isRenderChartResult,
    isRenderTableResult
} from "./GenerativeAnalytics";
import toast from "react-hot-toast";
import { useLocale } from "next-intl";

interface ChatSession {
    id: string;
    title: string;
    updatedAt: string;
    messages: Record<string, unknown>[];
}

interface ChatWithDataProps {
    surveyId: string;
}

type MyUITools = {
    renderChart: { input: Record<string, unknown>; output: RenderChartResult };
    renderTable: { input: Record<string, unknown>; output: RenderTableResult };
};

type ChatMessage = UIMessage<unknown, Record<string, unknown>, MyUITools>;

function isRecord(value: unknown): value is Record<string, unknown> {
    return typeof value === "object" && value !== null;
}

function parseChatSessionsResponse(value: unknown): { sessions: ChatSession[] } {
    if (!isRecord(value) || !Array.isArray(value.sessions)) {
        return { sessions: [] };
    }

    return {
        sessions: value.sessions.flatMap((session) => {
            if (
                !isRecord(session) ||
                typeof session.id !== "string" ||
                typeof session.title !== "string" ||
                typeof session.updatedAt !== "string" ||
                !Array.isArray(session.messages)
            ) {
                return [];
            }

            return [{
                id: session.id,
                title: session.title,
                updatedAt: session.updatedAt,
                messages: session.messages.filter(isRecord),
            }];
        }),
    };
}

function getToolOutput(
    part: ChatMessage["parts"][number],
): RenderChartResult | RenderTableResult | null {
    if (!isToolUIPart(part) || part.state !== "output-available") {
        return null;
    }

    const output = part.output;

    if (isRenderChartResult(output) || isRenderTableResult(output)) {
        return output;
    }

    return null;
}

function SuggestionPill({
    icon: Icon,
    label,
    onClick,
}: {
    icon: React.ElementType,
    label: string,
    onClick?: () => void,
}) {
    return (
        <button
            onClick={onClick}
            className="flex items-center gap-2 px-4 py-2 bg-gray-50 border border-gray-100 rounded-full text-xs font-bold text-gray-500 hover:bg-white hover:border-gray-900 hover:text-gray-900 transition-all whitespace-nowrap"
        >
            <Icon className="w-3.5 h-3.5" />
            {label}
        </button>
    );
}

export function ChatWithData({ surveyId }: ChatWithDataProps) {
    const locale = useLocale();
    const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
    const [isSessionsOpen, setIsSessionsOpen] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);
    const [input, setInput] = useState("");
    const [chatPlaceholder, setChatPlaceholder] = useState("Ask anything about your data...");
    const [isRecordingAudio, setIsRecordingAudio] = useState(false);
    const [isTranscribingAudio, setIsTranscribingAudio] = useState(false);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const mediaStreamRef = useRef<MediaStream | null>(null);
    const audioChunksRef = useRef<Blob[]>([]);
    const suggestions = [
        "How many students reported positive outcomes?",
        "What barriers appear most often?",
        "Compare the latest snapshot with the previous one.",
        "Show the strongest evidence behind the top finding.",
    ];

    // 1. Fetch past sessions
    const { data: sessionsData, refetch: refetchSessions } = useQuery({
        queryKey: ["chat-sessions", surveyId],
        queryFn: async () => {
            const res = await fetch(`/api/surveys/${surveyId}/analytics/chat-sessions`);
            if (!res.ok) throw new Error("Failed to fetch sessions");
            return parseChatSessionsResponse(await res.json());
        },
    });

    // 2. Initialize Chat
    const { messages, setMessages, sendMessage, status } = useChat<ChatMessage>({
        transport: new DefaultChatTransport({
            api: `/api/surveys/${surveyId}/analytics/chat`,
        }),
        onFinish: async ({ message, messages }) => {
            // Save session on finish
            saveSession([...messages, message]);
        },
    });

    const isLoading = status === "streaming" || status === "submitted";

    // 3. Save session to DB
    const saveSession = async (currentMessages: ChatMessage[]) => {
        try {
            const res = await fetch(`/api/surveys/${surveyId}/analytics/chat-sessions`, {
                method: "POST",
                body: JSON.stringify({
                    sessionId: currentSessionId,
                    messages: currentMessages,
                }),
            });
            if (res.ok) {
                const { session } = await res.json();
                if (!currentSessionId) {
                    setCurrentSessionId(session.id);
                    refetchSessions();
                }
            }
        } catch (error) {
        }
    };

    // 4. Load a session
    const loadSession = async (sessionId: string) => {
        try {
            const res = await fetch(`/api/surveys/${surveyId}/analytics/chat-sessions/${sessionId}`);
            if (res.ok) {
                const { session } = await res.json();
                setMessages(session.messages || []);
                setCurrentSessionId(session.id);
            }
        } catch (e) {
        }
    };

    const handleNewChat = () => {
        setMessages([]);
        setCurrentSessionId(null);
        setInput("");
    };

    const handleSubmit = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!input.trim() || isLoading) return;

        const text = input;
        setInput("");
        sendMessage({ role: "user", parts: [{ type: "text", text }] });
    };

    const stopAudioStream = () => {
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach((track) => track.stop());
            mediaStreamRef.current = null;
        }
    };

    const handleVoiceInput = async () => {
        if (isTranscribingAudio || isLoading) return;

        if (isRecordingAudio) {
            mediaRecorderRef.current?.stop();
            setIsRecordingAudio(false);
            return;
        }

        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                audio: {
                    echoCancellation: true,
                    noiseSuppression: true,
                    autoGainControl: true,
                },
            });
            mediaStreamRef.current = stream;
            audioChunksRef.current = [];

            const preferredMimeType =
                typeof MediaRecorder !== "undefined" &&
                MediaRecorder.isTypeSupported("audio/webm;codecs=opus")
                    ? "audio/webm;codecs=opus"
                    : undefined;
            const recorder = preferredMimeType
                ? new MediaRecorder(stream, { mimeType: preferredMimeType })
                : new MediaRecorder(stream);

            mediaRecorderRef.current = recorder;

            recorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    audioChunksRef.current.push(event.data);
                }
            };

            recorder.onstop = async () => {
                stopAudioStream();
                const audioBlob = new Blob(audioChunksRef.current, {
                    type: recorder.mimeType || "audio/webm",
                });
                audioChunksRef.current = [];
                mediaRecorderRef.current = null;

                if (audioBlob.size === 0) {
                    return;
                }

                setIsTranscribingAudio(true);
                try {
                    const formData = new FormData();
                    formData.append(
                        "audio",
                        new File([audioBlob], "analytics-voice.webm", {
                            type: audioBlob.type || "audio/webm",
                        }),
                    );
                    formData.append("language", locale || "multi");

                    const response = await fetch(
                        `/api/surveys/${surveyId}/analytics/transcribe`,
                        {
                            method: "POST",
                            body: formData,
                        },
                    );

                    const data = await response.json();
                    if (!response.ok) {
                        throw new Error(data.error || "Voice transcription failed");
                    }

                    const transcript = typeof data.transcript === "string" ? data.transcript.trim() : "";
                    if (!transcript) {
                        throw new Error("No transcript generated from audio");
                    }

                    await sendMessage({
                        role: "user",
                        parts: [{ type: "text", text: transcript }],
                    });
                } catch (error) {
                    const message =
                        error instanceof Error
                            ? error.message
                            : "Voice transcription failed";
                    toast.error(message);
                } finally {
                    setIsTranscribingAudio(false);
                }
            };

            recorder.start(250);
            setIsRecordingAudio(true);
        } catch (error) {
            stopAudioStream();
            mediaRecorderRef.current = null;
            setIsRecordingAudio(false);
            toast.error(
                "Microphone access failed. Please check your browser permissions.",
            );
        }
    };

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    useEffect(() => {
        return () => {
            if (mediaRecorderRef.current && mediaRecorderRef.current.state !== "inactive") {
                mediaRecorderRef.current.stop();
            }
            stopAudioStream();
        };
    }, []);

    const [welcomeMessage, setWelcomeMessage] = useState<ChatMessage | null>(null);

    useEffect(() => {
        setWelcomeMessage({
            id: "welcome",
            role: "assistant",
            parts: [{
                type: "text",
                text: "Hi! I'm your research assistant. I can help you analyze your data, find patterns, or visualize specific metrics. What would you like to explore today?",
            }],
        });
    }, []);

    const allMessages = messages.length === 0 ? (welcomeMessage ? [welcomeMessage] : []) : messages;

    const getTextContent = (m: ChatMessage) => {
        return m.parts
            .filter(isTextUIPart)
            .map(p => p.text)
            .join("\n");
    };

    return (
        <div className="flex flex-col h-full bg-white">
            {/* Session Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 flex-shrink-0">
                <div className="relative">
                    <button
                        onClick={() => setIsSessionsOpen(!isSessionsOpen)}
                        className="flex items-center gap-2 px-4 py-2 hover:bg-gray-50 rounded-full transition-all text-sm font-bold text-gray-900"
                    >
                        <History className="w-4 h-4 text-gray-400" />
                        {currentSessionId
                            ? sessionsData?.sessions.find(s => s.id === currentSessionId)?.title || "Current Chat"
                            : "New Exploration"}
                        <ChevronDown className={cn("w-4 h-4 text-gray-400 transition-transform", isSessionsOpen && "rotate-180")} />
                    </button>

                    {isSessionsOpen && (
                        <div className="absolute top-full left-0 mt-2 w-72 bg-white border border-gray-100 rounded-3xl shadow-2xl z-50 p-2 overflow-hidden">
                            <div className="max-h-64 overflow-y-auto custom-scrollbar">
                                {sessionsData?.sessions.length === 0 ? (
                                    <div className="p-4 text-xs text-gray-400 text-center italic">No past sessions</div>
                                ) : (
                                    sessionsData?.sessions.map((s) => (
                                        <button
                                            key={s.id}
                                            onClick={() => {
                                                loadSession(s.id);
                                                setIsSessionsOpen(false);
                                            }}
                                            className="w-full text-left px-4 py-3 hover:bg-gray-50 rounded-2xl transition-all group"
                                        >
                                            <div className="text-xs font-bold text-gray-900 truncate">{s.title}</div>
                                            <div className="text-[10px] text-gray-400 mt-0.5">{new Date(s.updatedAt).toLocaleDateString()}</div>
                                        </button>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <button
                    onClick={handleNewChat}
                    className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-gray-500 hover:text-gray-900 transition-colors"
                >
                    <PlusCircle className="w-4 h-4" />
                    New Chat
                </button>
            </div>

            {/* Messages Area */}
            <div
                ref={scrollRef}
                className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8"
            >
                {allMessages.map((m: ChatMessage) => (
                    <div
                        key={m.id}
                        className={cn(
                            "flex gap-4 max-w-4xl mx-auto",
                            m.role === "user" ? "justify-end" : "justify-start"
                        )}
                    >
                        {m.role === "assistant" && (
                            <div className="w-8 h-8 rounded-full bg-gray-900 flex items-center justify-center flex-shrink-0 mt-1">
                                <Bot className="w-4 h-4 text-white" />
                            </div>
                        )}

                        <div className={cn(
                            "space-y-4",
                            m.role === "user" ? "max-w-[80%]" : "max-w-full flex-1"
                        )}>
                            {getTextContent(m) && (
                                <div className={cn(
                                    "p-5 rounded-[2rem] text-sm leading-relaxed",
                                    m.role === "user"
                                        ? "bg-gray-900 text-white font-medium"
                                        : "text-gray-900 bg-transparent p-0"
                                )}>
                                    {getTextContent(m)}
                                </div>
                            )}

                            {/* Handle Tool Invocations from parts */}
                            {m.parts.filter(isToolUIPart).map((part) => {
                                const toolOutput = getToolOutput(part);

                                return (
                                    <div
                                        key={part.toolCallId}
                                        className="mt-4 rounded-[2.5rem] bg-[#F2F5F8] overflow-hidden p-8 border border-[#E5E9EE]"
                                    >
                                        {toolOutput ? (
                                            <GenerativeAnalyticsRenderer
                                                toolName={getToolName(part)}
                                                result={toolOutput}
                                            />
                                        ) : (
                                            <div className="flex items-center gap-3 text-sm text-gray-400 font-bold italic animate-pulse">
                                                <Sparkles className="w-4 h-4" />
                                                Synthesizing {getToolName(part).replace("render", "").toLowerCase()}...
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>

                        {m.role === "user" && (
                            <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center flex-shrink-0 mt-1">
                                <User className="w-4 h-4 text-gray-500" />
                            </div>
                        )}
                    </div>
                ))}
                {isLoading && !allMessages[allMessages.length - 1]?.parts.some(isToolUIPart) && (
                    <div className="flex gap-4 max-w-4xl mx-auto">
                        <div className="w-8 h-8 rounded-full bg-gray-900 flex items-center justify-center flex-shrink-0 animate-pulse">
                            <Bot className="w-4 h-4 text-white" />
                        </div>
                        <div className="p-2">
                            <Loader2 className="w-5 h-5 animate-spin text-gray-300" />
                        </div>
                    </div>
                )}
            </div>

            {/* Input Area */}
            <div className="p-6 border-t border-gray-100 flex-shrink-0">
                <form
                    onSubmit={handleSubmit}
                    className="max-w-4xl mx-auto relative group"
                >
                    <input
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder={chatPlaceholder}
                        disabled={isLoading || isTranscribingAudio}
                        className="w-full pl-6 pr-28 py-5 bg-[#F2F5F8] focus:bg-white border-2 border-transparent focus:border-gray-900 rounded-[2rem] text-sm font-medium transition-all outline-none disabled:opacity-70"
                    />
                    <button
                        type="button"
                        onClick={handleVoiceInput}
                        disabled={isLoading || isTranscribingAudio}
                        className={cn(
                            "absolute right-16 top-2.5 p-3 h-12 w-12 rounded-full flex items-center justify-center transition-all disabled:opacity-50",
                            isRecordingAudio
                                ? "bg-red-100 text-red-600 hover:bg-red-200"
                                : "bg-white text-gray-500 hover:text-gray-900 border border-gray-200 hover:border-gray-900",
                        )}
                        aria-label={isRecordingAudio ? "Stop recording" : "Start voice input"}
                    >
                        {isTranscribingAudio ? (
                            <Loader2 className="w-5 h-5 animate-spin" />
                        ) : isRecordingAudio ? (
                            <Square className="w-4 h-4 fill-current" />
                        ) : (
                            <Mic className="w-5 h-5" />
                        )}
                    </button>
                    <button
                        type="submit"
                        disabled={!input.trim() || isLoading || isTranscribingAudio}
                        className="absolute right-3 top-2.5 p-3 h-12 w-12 bg-gray-900 text-white rounded-full flex items-center justify-center hover:bg-black transition-all disabled:opacity-50 disabled:bg-gray-200"
                    >
                        {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
                    </button>
                </form>
                {(isRecordingAudio || isTranscribingAudio) && (
                    <div className="max-w-4xl mx-auto mt-3 px-2 text-sm text-gray-500">
                        {isRecordingAudio ? (
                            "Listening for your question..."
                        ) : (
                            "Transcribing your question..."
                        )}
                    </div>
                )}
                <div className="max-w-4xl mx-auto flex gap-4 mt-6 overflow-x-auto pb-2 px-2 no-scrollbar">
                    <SuggestionPill icon={Search} label="Finding trends" onClick={() => setInput(suggestions[1])} />
                    <SuggestionPill icon={Table} label="Pivot data" onClick={() => setInput(suggestions[0])} />
                    <SuggestionPill icon={BarChart2} label="Visualize metrics" onClick={() => setInput(suggestions[2])} />
                    <SuggestionPill icon={Sparkles} label="AI Insights" onClick={() => setInput(suggestions[3])} />
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { createPortal } from "react-dom";
import { X, Loader2, Plus, Building2 } from "lucide-react";
import { createWorkspace, setActiveWorkspace } from "@/app/actions/workspace";
import { useRouter } from "@/i18n/routing";
import { useTranslations } from "next-intl";

type CreateWorkspaceModalProps = {
    isOpen: boolean;
    onClose: () => void;
    onSuccess?: (workspaceId: string) => void | Promise<void>;
};

export function CreateWorkspaceModal({ isOpen, onClose, onSuccess }: CreateWorkspaceModalProps) {
    const router = useRouter();
    const [name, setName] = useState("");
    const [slug, setSlug] = useState("");
    const [description, setDescription] = useState("");
    const [isCreating, setIsCreating] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [mounted, setMounted] = useState(false);
    const t = useTranslations("Workspace.Create");

    useEffect(() => {
        setMounted(true);
    }, []);

    const handleCreate = async () => {
        if (!name.trim()) return;

        setIsCreating(true);
        setError(null);

        try {
            // Auto-generate slug if not provided or just rely on name
            const finalSlug = slug || name.toLowerCase().replace(/[^a-z0-9]+/g, "-");

            const result = await createWorkspace({
                name,
                slug: finalSlug,
            });

            if (result.success) {
                // Set as active instantly
                const activationResult = await setActiveWorkspace(result.data.id);
                if (!activationResult.success) {
                    setError(activationResult.error);
                    return;
                }

                setName("");
                setSlug("");
                setDescription("");
                await onSuccess?.(result.data.id);
                onClose();
                router.refresh();
                router.push("/dashboard");
            } else {
                setError(result.error);
            }
        } catch (error) {
            setError(t("Error"));
        } finally {
            setIsCreating(false);
        }
    };

    if (!isOpen || !mounted) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center">
            <div
                className="absolute inset-0 bg-black/50 backdrop-blur-sm"
                onClick={onClose}
            />

            <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-md mx-4 animate-in fade-in zoom-in-95 duration-200">
                <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
                            <Building2 className="w-5 h-5 text-white" />
                        </div>
                        <h3 className="text-lg font-semibold text-gray-900">{t("Title")}</h3>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <div className="px-6 py-5 space-y-4">
                    {error && (
                        <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-600">
                            {error}
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            {t("NameLabel")}
                        </label>
                        <input
                            type="text"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            placeholder={t("NamePlaceholder")}
                            className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none transition-all"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            {t("DescLabel")}
                        </label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder={t("DescPlaceholder")}
                            rows={3}
                            className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none transition-all resize-none"
                        />
                    </div>

                    <div className="bg-blue-50 rounded-xl p-4">
                        <p className="text-sm text-blue-700">
                            <span className="font-medium">{t("TipTitle")}</span> {t("TipDesc")}
                        </p>
                    </div>
                </div>

                <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-4 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                    >
                        {t("Cancel")}
                    </button>
                    <button
                        onClick={handleCreate}
                        disabled={!name.trim() || isCreating}
                        className="flex items-center gap-2 px-4 py-2.5 bg-gray-900 text-white rounded-lg font-medium text-sm hover:bg-gray-800 transition-colors disabled:opacity-50"
                    >
                        {isCreating ? (
                            <>
                                <Loader2 className="w-4 h-4 animate-spin" />
                                {t("Creating")}
                            </>
                        ) : (
                            <>
                                <Plus className="w-4 h-4" />
                                {t("CreateButton")}
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>,
        document.body
    );
}

"use client";

import { useState } from "react";
import Image, { type ImageLoaderProps } from "next/image";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { ChevronDown, Plus, Building2, User, Check, Loader2 } from "lucide-react";
import toast from "react-hot-toast";
import { cn } from "@/lib/utils";
import { setActiveWorkspace } from "@/app/actions/workspace";
import { fetchWorkspaces, fetchActiveWorkspace } from "@/lib/api/workspace";
import { queryKeys } from "@/lib/query-keys";
import { useTranslations } from "next-intl";
import { useRouter } from "@/i18n/routing";

type Workspace = {
    id: string;
    name: string;
    slug: string;
    role: string;
    logo?: string | null;
};

const passthroughImageLoader = ({ src }: ImageLoaderProps) => src;

export function WorkspaceSwitcher() {
    const router = useRouter();
    const queryClient = useQueryClient();
    const [isOpen, setIsOpen] = useState(false);
    const [isSwitching, setIsSwitching] = useState(false);
    const t = useTranslations("Workspace.Switcher");

    // Fetch workspaces using React Query
    const { data: workspaces = [], isLoading: isLoadingWorkspaces } = useQuery({
        queryKey: queryKeys.workspaces.all,
        queryFn: fetchWorkspaces,
    });

    // Fetch active workspace using React Query
    const { data: activeWorkspace = null, isLoading: isLoadingActive } = useQuery({
        queryKey: queryKeys.workspaces.active,
        queryFn: fetchActiveWorkspace,
    });

    const isLoading = isLoadingWorkspaces || isLoadingActive;

    const refreshWorkspaceState = async () => {
        await Promise.all([
            queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all }),
            queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.active }),
            queryClient.invalidateQueries({ queryKey: ["surveys"] }),
            queryClient.invalidateQueries({ queryKey: ["projects"] }),
            queryClient.invalidateQueries({ queryKey: ["notifications"] }),
        ]);
        router.refresh();
    };

    const handleSwitchWorkspace = async (workspace: Workspace | null) => {
        setIsSwitching(true);
        try {
            const result = await setActiveWorkspace(workspace?.id || null);
            if (result.success) {
                await refreshWorkspaceState();
            } else {
                toast.error(result.error);
            }
        } catch (error) {
            toast.error("Failed to switch workspace");
        } finally {
            setIsSwitching(false);
            setIsOpen(false);
        }
    };

    if (isLoading) {
        return (
            <div className="px-4 py-3 flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-gray-100 animate-pulse" />
                <div className="flex-1">
                    <div className="h-4 w-24 bg-gray-100 rounded animate-pulse" />
                </div>
            </div>
        );
    }

    return (
        <div className="relative px-4 py-3 border-b border-gray-100">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 transition-all duration-200"
                disabled={isSwitching}
            >
                {/* Avatar */}
                <div className={cn(
                    "w-9 h-9 rounded-lg flex items-center justify-center font-semibold text-sm",
                    activeWorkspace
                        ? "bg-gradient-to-br from-blue-500 to-purple-600 text-white"
                        : "bg-gradient-to-br from-gray-700 to-gray-900 text-white"
                )}>
                    {activeWorkspace ? (
                        activeWorkspace.logo ? (
                            <Image
                                loader={passthroughImageLoader}
                                unoptimized
                                src={activeWorkspace.logo}
                                alt=""
                                width={36}
                                height={36}
                                className="w-full h-full rounded-lg object-cover"
                            />
                        ) : (
                            <Building2 className="w-4 h-4" />
                        )
                    ) : (
                        <User className="w-4 h-4" />
                    )}
                </div>

                {/* Name & Role */}
                <div className="flex-1 text-left min-w-0">
                    <p className="text-sm font-semibold text-gray-900 truncate">
                        {activeWorkspace?.name || t("PersonalAccount")}
                    </p>
                    <p className="text-xs text-gray-500 truncate">
                        {activeWorkspace ? <>{t(`Roles.${activeWorkspace.role === 'owner' ? 'Owner' : 'Member'}`)} • {t("Workspace")}</> : t("Individual")}
                    </p>
                </div>

                {/* Chevron */}
                {isSwitching ? (
                    <Loader2 className="w-4 h-4 text-gray-400 animate-spin" />
                ) : (
                    <ChevronDown className={cn(
                        "w-4 h-4 text-gray-400 transition-transform duration-200",
                        isOpen && "rotate-180"
                    )} />
                )}
            </button>

            {/* Dropdown */}
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsOpen(false)}
                    />

                    {/* Menu */}
                    <div className="absolute left-4 right-4 top-full mt-1 bg-white rounded-xl border border-gray-200 shadow-xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                        {/* Personal Account */}
                        <button
                            onClick={() => handleSwitchWorkspace(null)}
                            className={cn(
                                "w-full flex items-center gap-3 p-3 hover:bg-gray-50 transition-colors",
                                !activeWorkspace && "bg-gray-50"
                            )}
                        >
                            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-gray-700 to-gray-900 text-white flex items-center justify-center">
                                <User className="w-4 h-4" />
                            </div>
                            <div className="flex-1 text-left">
                                <p className="text-sm font-medium text-gray-900">{t("PersonalAccount")}</p>
                                <p className="text-xs text-gray-500">{t("PersonalDesc")}</p>
                            </div>
                            {!activeWorkspace && (
                                <Check className="w-4 h-4 text-green-500" />
                            )}
                        </button>

                        {/* Divider */}
                        {workspaces.length > 0 && (
                            <div className="border-t border-gray-100 my-1" />
                        )}

                        {/* Workspaces */}
                        <div className="max-h-48 overflow-y-auto">
                            {workspaces.map((workspace) => (
                                <button
                                    key={workspace.id}
                                    onClick={() => handleSwitchWorkspace(workspace)}
                                    className={cn(
                                        "w-full flex items-center gap-3 p-3 hover:bg-gray-50 transition-colors",
                                        activeWorkspace?.id === workspace.id && "bg-gray-50"
                                    )}
                                >
                                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-purple-600 text-white flex items-center justify-center">
                                        {workspace.logo ? (
                                            <Image
                                                loader={passthroughImageLoader}
                                                unoptimized
                                                src={workspace.logo}
                                                alt=""
                                                width={32}
                                                height={32}
                                                className="w-full h-full rounded-lg object-cover"
                                            />
                                        ) : (
                                            <Building2 className="w-4 h-4" />
                                        )}
                                    </div>
                                    <div className="flex-1 text-left min-w-0">
                                        <p className="text-sm font-medium text-gray-900 truncate">{workspace.name}</p>
                                        <p className="text-xs text-gray-500 capitalize">{t(`Roles.${workspace.role === 'owner' ? 'Owner' : 'Member'}`)}</p>
                                    </div>
                                    {activeWorkspace?.id === workspace.id && (
                                        <Check className="w-4 h-4 text-green-500 flex-shrink-0" />
                                    )}
                                </button>
                            ))}
                        </div>

                        {/* Create Workspace */}
                        <div className="border-t border-gray-100">
                            <button
                                onClick={() => {
                                    setIsOpen(false);
                                    router.push("/dashboard/workspaces/new");
                                }}
                                className="w-full flex items-center gap-3 p-3 text-gray-600 hover:bg-gray-50 hover:text-gray-900 transition-colors"
                            >
                                <div className="w-8 h-8 rounded-lg border-2 border-dashed border-gray-300 flex items-center justify-center">
                                    <Plus className="w-4 h-4" />
                                </div>
                                <span className="text-sm font-medium">{t("CreateWorkspace")}</span>
                            </button>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

"use client";

import { useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  ArrowRight,
  BookOpen,
  Brain,
  ClipboardList,
  Keyboard,
  Loader2,
  MessageSquare,
  Mic,
  Send,
  Sparkles,
} from "lucide-react";
import { useLocale } from "next-intl";
import toast from "react-hot-toast";

import { Link } from "@/i18n/routing";
import {
  askOutOfSessionQuestion,
  fetchMyPatterns,
  fetchOnboardingState,
  fetchTutoringSession,
  sendOnboardingTurn,
  sendTutoringMessage,
} from "@/lib/api/learning";
import { queryKeys } from "@/lib/query-keys";
import { useAudioTranscription } from "@/hooks/use-audio-transcription";
import { isAppLocale } from "@/lib/i18n/config";
import { GlassPanel } from "@/components/learning/glass-panel";
import { MetricTile } from "@/components/learning/metric-tile";
import { SectionHeading } from "@/components/learning/section-heading";

import type { LearningMeData } from "@/lib/api/learning";
type StudentLearningMeData = Extract<LearningMeData, { role: "student" }>;

type LiveMessage = {
  id: string;
  role: string;
  content: string;
  metadata: Record<string, unknown>;
  createdAt?: string | Date;
};

type TutorMediaMetadata = {
  assetType: "image" | "video";
  title: string;
  description?: string | null;
  mediaUrl: string;
  thumbnailUrl?: string | null;
  durationSeconds?: number | null;
  selectionSource: string;
  reason: string;
  expectedBenefit: string;
  followUpPrompt: string;
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function getTutorMediaMetadata(metadata: Record<string, unknown>) {
  const tutorMedia = metadata.tutorMedia;
  if (!isRecord(tutorMedia)) return null;

  const assetType = tutorMedia.assetType;
  const title = tutorMedia.title;
  const mediaUrl = tutorMedia.mediaUrl;
  const reason = tutorMedia.reason;
  const expectedBenefit = tutorMedia.expectedBenefit;
  const followUpPrompt = tutorMedia.followUpPrompt;
  if (
    (assetType !== "image" && assetType !== "video") ||
    typeof title !== "string" ||
    typeof mediaUrl !== "string" ||
    typeof reason !== "string" ||
    typeof expectedBenefit !== "string" ||
    typeof followUpPrompt !== "string"
  ) {
    return null;
  }

  return {
    assetType,
    title,
    description:
      typeof tutorMedia.description === "string" ? tutorMedia.description : null,
    mediaUrl,
    thumbnailUrl:
      typeof tutorMedia.thumbnailUrl === "string"
        ? tutorMedia.thumbnailUrl
        : null,
    durationSeconds:
      typeof tutorMedia.durationSeconds === "number"
        ? tutorMedia.durationSeconds
        : null,
    selectionSource:
      typeof tutorMedia.selectionSource === "string"
        ? tutorMedia.selectionSource
        : "system",
    reason,
    expectedBenefit,
    followUpPrompt,
  };
}

type TutoringSessionResponse = Awaited<ReturnType<typeof fetchTutoringSession>>;

function formatPhaseLabel(value: string) {
  return value
    .split("_")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function formatDate(value: string | Date | null | undefined) {
  if (!value) return "Not yet";
  return new Intl.DateTimeFormat(undefined, {
    month: "short",
    day: "numeric",
  }).format(new Date(value));
}

function appendTranscript(currentValue: string, transcript: string) {
  const trimmedCurrent = currentValue.trim();
  return trimmedCurrent ? `${trimmedCurrent} ${transcript}`.trim() : transcript;
}

export function StudentWorkspace({ learningMe }: { learningMe: StudentLearningMeData }) {
  const queryClient = useQueryClient();
  const locale = useLocale();
  const dictationLocale = isAppLocale(locale) ? locale : "en";
  const memberships = learningMe.student;
  const [selectedMembershipId, setSelectedMembershipId] = useState<string | null>(
    memberships[0]?.classroomStudentId ?? null,
  );
  const selectedMembership =
    memberships.find((item) => item.classroomStudentId === selectedMembershipId) ??
    memberships[0] ??
    null;

  const availableTopics = selectedMembership?.topics ?? [];
  const availableSurveys = selectedMembership?.surveys ?? [];
  const [selectedTopicId, setSelectedTopicId] = useState<string | null>(
    availableTopics[0]?.id ?? null,
  );
  const effectiveSelectedTopicId = availableTopics.some((topic) => topic.id === selectedTopicId)
    ? selectedTopicId
    : (availableTopics[0]?.id ?? null);
  const [onboardingInput, setOnboardingInput] = useState("");
  const [sessionInput, setSessionInput] = useState("");
  const [questionInput, setQuestionInput] = useState("");
  const [inputMode, setInputMode] = useState<"text" | "voice">("text");
  const [outOfSessionReply, setOutOfSessionReply] = useState<string | null>(null);
  const {
    isSupported: isVoiceInputSupported,
    activeTarget: transcriptionTarget,
    phase: transcriptionPhase,
    startTranscription,
    stopRecording: stopDictation,
  } = useAudioTranscription({
    onError: (message) => toast.error(message),
  });
  const isDictationSupported = isVoiceInputSupported;
  const isVoiceInputMode = inputMode === "voice";

  const onboardingQuery = useQuery({
    queryKey: queryKeys.learning.onboarding,
    queryFn: fetchOnboardingState,
    enabled: Boolean(selectedMembership?.needsOnboarding),
  });

  const patternsQuery = useQuery({
    queryKey: queryKeys.learning.myPatterns,
    queryFn: fetchMyPatterns,
  });

  const tutoringSessionQuery = useQuery({
    queryKey: effectiveSelectedTopicId
      ? queryKeys.learning.tutoring(effectiveSelectedTopicId)
      : ["learningTutoring", "idle"],
    queryFn: () => fetchTutoringSession(effectiveSelectedTopicId!),
    enabled: Boolean(effectiveSelectedTopicId && !selectedMembership?.needsOnboarding),
  });
  const liveMessages = useMemo<LiveMessage[]>(
    () =>
      tutoringSessionQuery.data?.data.messages.map((message) => ({
        id: message.id,
        role: message.role,
        content: message.content,
        metadata: message.metadata ?? {},
        createdAt: message.createdAt,
      })) ?? [],
    [tutoringSessionQuery.data?.data.messages],
  );

  const onboardingMutation = useMutation({
    mutationFn: sendOnboardingTurn,
    onSuccess: async (data) => {
      setOnboardingInput("");

      if (!data.completed) {
        await queryClient.invalidateQueries({ queryKey: queryKeys.learning.onboarding });
        return;
      }

      toast.success("Onboarding complete");
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.learning.onboarding }),
        queryClient.invalidateQueries({ queryKey: queryKeys.learning.me }),
        queryClient.invalidateQueries({ queryKey: queryKeys.learning.myPatterns }),
      ]);
    },
    onError: (error) => {
      toast.error(error instanceof Error ? error.message : "Failed to continue onboarding");
    },
  });

  const tutoringMutation = useMutation({
    mutationFn: sendTutoringMessage,
    onSuccess: async (data, variables) => {
      setSessionInput("");
      queryClient.setQueryData<TutoringSessionResponse | undefined>(
        queryKeys.learning.tutoring(variables.topicId),
        (current) => {
          if (!current) {
            return current;
          }

          const now = new Date().toISOString();
          return {
            ...current,
            data: {
              ...current.data,
              sessionId: data.data.sessionId,
              sessionState: data.data.sessionState,
              messages: [
                ...current.data.messages,
                {
                  id: `student-${Date.now()}`,
                  role: "user",
                  content: variables.message,
                  metadata: {},
                  createdAt: now,
                },
                {
                  id: `assistant-${Date.now() + 1}`,
                  role: "assistant",
                  content: data.data.assistantMessage.content,
                  metadata: data.data.assistantMessage.metadata ?? {},
                  createdAt: data.data.assistantMessage.createdAt ?? now,
                },
              ],
            },
          };
        },
      );

      await queryClient.invalidateQueries({
        queryKey: queryKeys.learning.tutoring(variables.topicId),
      });
    },
    onError: (error) => {
      toast.error(error instanceof Error ? error.message : "Failed to send message");
    },
  });

  const outOfSessionMutation = useMutation({
    mutationFn: askOutOfSessionQuestion,
    onSuccess: (data) => {
      setQuestionInput("");
      setOutOfSessionReply(data.data.response);
      toast.success("Question sent");
