              <h3 className="text-lg font-semibold tracking-tight">
                How you learn best
              </h3>
            </div>
            <div className="mt-4 space-y-3">
              {patternsQuery.isLoading ? (
                <div className="flex items-center gap-2 text-sm text-slate-500">
                  <Loader2 className="h-4 w-4 animate-spin" />
