                            <Mic className="h-3.5 w-3.5" />
                          )}
                          {transcriptionTarget === "student-onboarding"
                            ? transcriptionPhase === "recording"
                              ? "Listening..."
                              : "Transcribing..."
                            : "Tap to speak"}
                        </button>
                      </div>
                    ) : null}
                    <textarea
                      value={onboardingInput}
                      onChange={(event) => setOnboardingInput(event.target.value)}
                      rows={3}
