                            {isPosting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                        </button>
                    </form>
                </div>
            </div>

            {/* Backdrop for mobile or focus */}
            {isOpen && (
                <div 
                    className="fixed inset-0 bg-black/5 backdrop-blur-[1px] z-40 transition-opacity" 
