                            </span>
                            <span className="flex items-center gap-1.5">
                                <div className="w-1 h-1 rounded-full bg-slate-300" />
                                Encrypted
                            </span>
                            <span className="flex items-center gap-1.5">
                                <div className="w-1 h-1 rounded-full bg-slate-300" />
                                Privacy First
                            </span>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef, useCallback } from "react";

export interface PresenceUser {
  userId: string;
  name: string;
  image?: string | null;
  lastActive: number;
}

export interface PresenceMessage {
  type: "presence_update" | "user_joined" | "user_left" | "error" | "connected";
  workspaceId: string;
  surveyId?: string;
  users?: PresenceUser[];
  user?: Partial<PresenceUser>;
}

interface UsePresenceOptions {
  workspaceId: string;
  surveyId?: string;
  onUserJoined?: (user: Partial<PresenceUser>) => void;
  onUserLeft?: (user: Partial<PresenceUser>) => void;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function normalizePresenceUser(value: unknown): PresenceUser | null {
  if (!isRecord(value) || typeof value.userId !== "string") {
    return null;
  }

  return {
    userId: value.userId,
    name: typeof value.name === "string" ? value.name : "Unknown user",
    image:
      typeof value.image === "string" || value.image === null
        ? value.image
        : null,
    lastActive:
      typeof value.lastActive === "number" ? value.lastActive : Date.now(),
  };
}

function normalizePresenceUsers(value: unknown): PresenceUser[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((user) => {
    const normalized = normalizePresenceUser(user);
    return normalized ? [normalized] : [];
  });
}

function parsePresenceMessage(value: unknown): PresenceMessage | null {
  if (
    !isRecord(value) ||
    (value.type !== "presence_update" &&
      value.type !== "user_joined" &&
      value.type !== "user_left" &&
      value.type !== "error" &&
      value.type !== "connected") ||
    typeof value.workspaceId !== "string"
  ) {
    return null;
  }

  return {
    type: value.type,
    workspaceId: value.workspaceId,
    surveyId: typeof value.surveyId === "string" ? value.surveyId : undefined,
    users: normalizePresenceUsers(value.users),
    user: normalizePresenceUser(value.user) ?? undefined,
  };
}

export function usePresence({
  workspaceId,
  surveyId,
  onUserJoined,
  onUserLeft,
}: UsePresenceOptions) {
  const [users, setUsers] = useState<PresenceUser[]>([]);
  const [status, setStatus] = useState<"disconnected" | "connecting" | "connected" | "error">("disconnected");
  const wsRef = useRef<WebSocket | null>(null);

  const connect = useCallback(async () => {
    if (wsRef.current || !workspaceId) return;

    setStatus("connecting");

    const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
    const wsHost = process.env.NEXT_PUBLIC_WEBSOCKET_URL || "localhost:3001";
    let url = `${protocol}//${wsHost}/presence?workspaceId=${workspaceId}`;
    if (surveyId) url += `&surveyId=${surveyId}`;

    try {
      const res = await fetch("/api/auth/token");
      if (res.ok) {
        const { token } = await res.json();
        if (token) url += `&token=${encodeURIComponent(token)}`;
      }
    } catch (e) {
    }

    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => {
      setStatus("connected");
    };

    ws.onmessage = (event) => {
      try {
        if (typeof event.data !== "string") {
          return;
        }

        const data = parsePresenceMessage(JSON.parse(event.data));
        if (!data) {
          return;
        }

        switch (data.type) {
          case "connected":
          case "presence_update":
            if (data.users) setUsers(data.users);
            break;
          case "user_joined":
            if (data.user?.userId && data.user.name) {
              const fullUser: PresenceUser = {
                userId: data.user.userId,
                name: data.user.name,
                image: data.user.image,
                lastActive: data.user.lastActive || Date.now()
              };
              setUsers(prev => {
                if (prev.find(u => u.userId === fullUser.userId)) return prev;
                return [...prev, fullUser];
              });
              onUserJoined?.(fullUser);
            }
            break;
          case "user_left":
            if (data.user?.userId) {
              setUsers(prev => prev.filter(u => u.userId !== data.user?.userId));
              onUserLeft?.(data.user);
            }
            break;
        }
      } catch (e) {
      }
    };

    ws.onerror = (e) => {
      setStatus("error");
    };

    ws.onclose = () => {
      setStatus("disconnected");
      wsRef.current = null;
    };
  }, [workspaceId, surveyId, onUserJoined, onUserLeft]);

  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
  }, []);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      void connect();
    }, 0);

    return () => {
      window.clearTimeout(timer);
      disconnect();
    };
  }, [connect, disconnect]);

  // Heartbeat/Update presence
  useEffect(() => {
    if (status !== "connected" || !wsRef.current) return;

    const interval = setInterval(() => {
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({ type: "heartbeat" }));
      }
    }, 30000); // Heartbeat every 30s

    return () => clearInterval(interval);
  }, [status]);

  return {
    users,
    status,
    connect,
    disconnect
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { SurveyMedia, VoiceAgentMessage } from "@/lib/chat-types";

declare global {
  interface Window {
    webkitAudioContext?: typeof AudioContext;
  }
}

type VoiceWebSocketStatus = "disconnected" | "connecting" | "connected" | "error";

type VoiceSocketJsonMessage = VoiceAgentMessage;

interface UseVoiceWebSocketOptions {
  url: string;
  onMessage?: (message: VoiceSocketJsonMessage) => void;
  onReady?: () => void;
  onError?: (error: unknown) => void;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseSurveyMedia(value: unknown): (SurveyMedia & { id: string }) | undefined {
  if (!isRecord(value)) {
    return undefined;
  }

  if (
    typeof value.id !== "string" ||
    (value.type !== "image" && value.type !== "video" && value.type !== "audio") ||
    typeof value.url !== "string"
  ) {
    return undefined;
  }

  return {
    id: value.id,
    type: value.type,
    url: value.url,
    description: typeof value.description === "string" ? value.description : undefined,
    mimeType: typeof value.mimeType === "string" ? value.mimeType : undefined,
    altText: typeof value.altText === "string" ? value.altText : undefined,
    durationMs: typeof value.durationMs === "number" ? value.durationMs : undefined,
  };
}

function parseVoiceSocketJsonMessage(value: unknown): VoiceSocketJsonMessage | null {
  if (!isRecord(value) || typeof value.type !== "string") {
    return null;
  }

  return {
    type: value.type,
    text: typeof value.text === "string" ? value.text : undefined,
    isFinal: typeof value.isFinal === "boolean" ? value.isFinal : undefined,
    role: typeof value.role === "string" ? value.role : undefined,
    content: typeof value.content === "string" ? value.content : undefined,
    error:
      typeof value.error === "string" || isRecord(value.error)
        ? value.error
        : undefined,
    description: typeof value.description === "string" ? value.description : undefined,
    awaitingAgentIntro:
      typeof value.awaitingAgentIntro === "boolean"
        ? value.awaitingAgentIntro
        : undefined,
    streamId: typeof value.streamId === "string" ? value.streamId : undefined,
    toolCallId: typeof value.toolCallId === "string" ? value.toolCallId : undefined,
    allowedTypes:
      Array.isArray(value.allowedTypes) &&
      value.allowedTypes.every((item) => typeof item === "string")
        ? value.allowedTypes
        : undefined,
    recommendation:
      typeof value.recommendation === "string" ? value.recommendation : undefined,
    rationale: typeof value.rationale === "string" ? value.rationale : undefined,
    suggestedDescription:
      typeof value.suggestedDescription === "string"
        ? value.suggestedDescription
        : undefined,
    suggestedFeedbackFocus:
      typeof value.suggestedFeedbackFocus === "string"
        ? value.suggestedFeedbackFocus
        : undefined,
    extractedData: isRecord(value.extractedData) ? value.extractedData : undefined,
    collectedInfo: isRecord(value.collectedInfo) ? value.collectedInfo : undefined,
    media: parseSurveyMedia(value.media),
    connectionId:
      typeof value.connectionId === "string" ? value.connectionId : undefined,
  };
}

function getTokenFromPayload(value: unknown): string | null {
  if (!isRecord(value) || typeof value.token !== "string") {
    return null;
  }

  return value.token;
}

function getAudioContextConstructor() {
  const AudioContextConstructor = window.AudioContext ?? window.webkitAudioContext;
  if (!AudioContextConstructor) {
    throw new Error("AudioContext is not supported in this browser.");
  }
  return AudioContextConstructor;
}

export function useVoiceWebSocket({
  url,
  onMessage,
  onReady,
  onError,
}: UseVoiceWebSocketOptions) {
  const [status, setStatus] = useState<VoiceWebSocketStatus>("disconnected");
  const [isRecording, setIsRecording] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hasAudioPlayed, setHasAudioPlayed] = useState(false);
  const [transcription, setTranscription] = useState("");
  const [interimTranscription, setInterimTranscription] = useState("");
  const [isMicMuted, setIsMicMutedState] = useState(false);
  const isMicMutedRef = useRef(false);
  const micEnabledRef = useRef(false);
  const [isMicEnabled, setIsMicEnabled] = useState(false);

  const [lastEventId] = useState<string | null>(null);
  const lastEventIdRef = useRef<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const wsRef = useRef<WebSocket | null>(null);
  const recordingContextRef = useRef<AudioContext | null>(null);
  const playbackContextRef = useRef<AudioContext | null>(null);
  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const activeAudioRef = useRef<HTMLAudioElement | null>(null);
  const isPlayingRef = useRef(false);
  const isPlayingTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const isAgentSpeakingRef = useRef(false);
  const lastPlaybackEndTimeRef = useRef<number>(0);
  const nextStartTimeRef = useRef<number>(0);

  useEffect(() => {
    lastEventIdRef.current = lastEventId;
  }, [lastEventId]);

  const onMessageRef = useRef(onMessage);
  useEffect(() => {
    onMessageRef.current = onMessage;
  }, [onMessage]);

  const getPlaybackContext = useCallback(() => {
    if (!playbackContextRef.current) {
      const AudioContextConstructor = getAudioContextConstructor();
      playbackContextRef.current = new AudioContextConstructor();
    }

    if (playbackContextRef.current.state === "suspended") {
      void playbackContextRef.current.resume();
    }

    return playbackContextRef.current;
  }, []);

  const queueAudioBuffer = useCallback(
    (audioBuffer: AudioBuffer) => {
      const audioCtx = getPlaybackContext();
      const source = audioCtx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioCtx.destination);

      const currentTime = audioCtx.currentTime;
      if (nextStartTimeRef.current < currentTime) {
        nextStartTimeRef.current = currentTime + 0.15;
      }

      source.start(nextStartTimeRef.current);
      nextStartTimeRef.current += audioBuffer.duration;

      setIsPlaying(true);
      isPlayingRef.current = true;
      setHasAudioPlayed(true);

      source.onended = () => {
        if (isPlayingTimeoutRef.current) {
          clearTimeout(isPlayingTimeoutRef.current);
        }

        isPlayingTimeoutRef.current = setTimeout(() => {
          if (audioCtx.currentTime >= nextStartTimeRef.current - 0.1) {
            setIsPlaying(false);
            isPlayingRef.current = false;
            lastPlaybackEndTimeRef.current = Date.now();
          }
        }, 100);
      };
    },
    [getPlaybackContext],
  );

  const handleIncomingAudio = useCallback(
    async (blob: Blob) => {
      try {
        const arrayBuffer = await blob.arrayBuffer();
        const sampleRate = 24000;
        const int16Data = new Int16Array(arrayBuffer);
        const float32Data = new Float32Array(int16Data.length);

        for (let index = 0; index < int16Data.length; index += 1) {
          float32Data[index] = int16Data[index] / 32768;
        }

        const audioCtx = getPlaybackContext();
        const audioBuffer = audioCtx.createBuffer(1, float32Data.length, sampleRate);
        audioBuffer.getChannelData(0).set(float32Data);
        queueAudioBuffer(audioBuffer);
      } catch (processingError) {
      }
    },
    [getPlaybackContext, queueAudioBuffer],
  );

  const stopRecording = useCallback(() => {
    if (workletNodeRef.current) {
      workletNodeRef.current.port.postMessage({ command: "stop" });
      workletNodeRef.current.disconnect();
      workletNodeRef.current = null;
    }

    if (sourceNodeRef.current) {
      sourceNodeRef.current.disconnect();
      sourceNodeRef.current = null;
    }

    if (recordingContextRef.current) {
      void recordingContextRef.current.close().catch(() => undefined);
      recordingContextRef.current = null;
    }

    if (playbackContextRef.current) {
      void playbackContextRef.current.close().catch(() => undefined);
      playbackContextRef.current = null;
      nextStartTimeRef.current = 0;
    }

    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }

    micEnabledRef.current = false;
    setIsMicEnabled(false);
    setIsRecording(false);
  }, []);

  const startRecording = useCallback(async () => {
    if (isRecording) return;
    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        },
      });
      streamRef.current = stream;

      const AudioContextConstructor = getAudioContextConstructor();
      const recordingContext = new AudioContextConstructor({ sampleRate: 16000 });
      recordingContextRef.current = recordingContext;
      await recordingContext.audioWorklet.addModule("/audio-worklet-processor.js");

      const source = recordingContext.createMediaStreamSource(stream);
      sourceNodeRef.current = source;

      const workletNode = new AudioWorkletNode(recordingContext, "pcm-processor");
      workletNodeRef.current = workletNode;

      workletNode.port.onmessage = (event) => {
        const payload = event.data;
        if (!isRecord(payload) || payload.type !== "audio") {
          return;
        }

        if (!micEnabledRef.current || wsRef.current?.readyState !== WebSocket.OPEN) {
          return;
        }

        const timeSincePlayback = Date.now() - (lastPlaybackEndTimeRef.current || 0);
        if (
          isAgentSpeakingRef.current ||
          isPlayingRef.current ||
          (lastPlaybackEndTimeRef.current > 0 && timeSincePlayback < 150)
        ) {
          return;
        }

        if (payload.buffer instanceof ArrayBuffer) {
          wsRef.current.send(payload.buffer);
        }
      };

      source.connect(workletNode);
      setIsRecording(true);
    } catch (recordingError) {
      setError("Microphone access failed. Please check permissions.");
      onError?.(recordingError);
    }
  }, [isRecording, onError]);

  const handleJsonMessage = useCallback(
    (data: VoiceSocketJsonMessage) => {
      switch (data.type) {
        case "transcription":
          if (data.isFinal) {
            setTranscription(data.text ?? "");
            setInterimTranscription("");
          }
          break;
        case "transcription_interim":
          setInterimTranscription(data.text ?? "");
          break;
        case "conversation_text":
          if (data.role === "user") {
            setTranscription(data.content ?? "");
            setInterimTranscription("");
          }
          break;
        case "agent_started_speaking":
          isAgentSpeakingRef.current = true;
          break;
        case "agent_ready":
          if (!micEnabledRef.current) {
            micEnabledRef.current = true;
            setIsMicEnabled(true);
            void startRecording().catch((recordingError) => {
            });
          }
          break;
        case "agent_audio_done":
          isAgentSpeakingRef.current = false;
          break;
        case "interrupt":
          if (activeAudioRef.current) {
            activeAudioRef.current.pause();
            activeAudioRef.current = null;
          }
          setIsPlaying(false);
          isPlayingRef.current = false;
          isAgentSpeakingRef.current = false;
          break;
        case "error": {
          let nextErrorMessage = "Unknown error";
          if (typeof data.error === "string") {
            nextErrorMessage = data.error;
          } else if (typeof data.description === "string") {
            nextErrorMessage = data.description;
          } else if (data.error !== undefined) {
            nextErrorMessage = JSON.stringify(data.error);
          } else {
            nextErrorMessage = JSON.stringify(data);
          }

          setStatus("error");
          setError(nextErrorMessage);
          onError?.(nextErrorMessage);
          break;
        }
        default:
          break;
      }

      onMessageRef.current?.(data);
    },
    [onError, startRecording],
  );

  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    stopRecording();
  }, [stopRecording]);

  const connect = useCallback(async () => {
    if (wsRef.current) return;

    setStatus("connecting");
    setHasAudioPlayed(false);
    setError(null);

    let connectionUrl = url;

    if (url.includes("/voice/sample-conversation")) {
      try {
        const response = await fetch("/api/auth/token");
        if (response.ok) {
          const token = getTokenFromPayload(await response.json());
          if (token) {
            const urlObject = new URL(url);
            urlObject.searchParams.set("token", token);
            connectionUrl = urlObject.toString();
          }
        }
      } catch (tokenError) {
      }
    }

    let ws: WebSocket;
    try {
      ws = new WebSocket(connectionUrl);
      wsRef.current = ws;
    } catch (connectionError) {
      setStatus("error");
      setError(
        connectionError instanceof Error
          ? connectionError.message
          : "Failed to create WebSocket connection",
      );
      onError?.(connectionError);
      return;
    }

    ws.onopen = () => {
      setStatus("connected");
      onReady?.();
    };

    ws.onmessage = async (event) => {
      if (event.data instanceof Blob) {
        await handleIncomingAudio(event.data);
        return;
      }

      if (typeof event.data !== "string") {
        return;
      }

      try {
        const parsed = parseVoiceSocketJsonMessage(JSON.parse(event.data));
        if (!parsed) {
          return;
        }

        handleJsonMessage(parsed);
      } catch (messageError) {
      }
    };

    ws.onerror = (socketError) => {
      setStatus("error");
      onError?.(socketError);
    };

    ws.onclose = (event) => {
      setStatus((currentStatus) =>
        currentStatus !== "error" ? "disconnected" : currentStatus,
      );
      if (event.reason) {
        setError(event.reason);
      }
      wsRef.current = null;
    };
  }, [handleIncomingAudio, handleJsonMessage, onError, onReady, url]);

  const sendJson = useCallback((data: unknown) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(data));
    } else {
    }
  }, []);

  const enableMic = useCallback(() => {
    micEnabledRef.current = true;
    setIsMicEnabled(true);
  }, []);

  const disableMic = useCallback(() => {
    micEnabledRef.current = false;
    setIsMicEnabled(false);
  }, []);

  const setMicMuted = useCallback((muted: boolean) => {
    isMicMutedRef.current = muted;
    setIsMicMutedState(muted);
  }, []);

  useEffect(() => {
    return () => {
      stopRecording();
      if (wsRef.current) {
        wsRef.current.close();
      }
    };
  }, [stopRecording]);

  const statusRef = useRef(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  return {
    status,
    statusRef,
    connect,
    disconnect,
    isRecording,
    isPlaying,
    isMicEnabled,
    startRecording,
    stopRecording,
    transcription,
    interimTranscription,
    sendJson,
    error,
    isMicMuted,
    setMicMuted,
    enableMic,
    disableMic,
    hasAudioPlayed,
    lastEventId,
  };
}

import { getDb } from "@/db";
import { usageLogs } from "@/db/schema/billing";
import { nanoid } from "nanoid";

export type UsageLogInput = {
  userId?: string;
  organizationId?: string;
  projectId?: string;
  surveyId?: string;
  type:
    | "llm_text"
    | "llm_embedding"
    | "stt"
    | "tts"
    | "search"
    | "voice_session";
  provider: string;
  modelName?: string;
  promptTokens?: number;
  completionTokens?: number;
  totalTokens?: number;
  inputNoCacheTokens?: number;
  cacheReadTokens?: number;
  cacheWriteTokens?: number;
  durationMs?: number;
};

// Rough pricing per 1M tokens or per minute/query
const PRICING: Record<string, { prompt: number; completion: number }> = {
  "gemini-2.5-flash": { prompt: 0.1, completion: 0.4 },
  "gemini-2.5-flash-lite": { prompt: 0.075, completion: 0.3 },
  "gpt-4o": { prompt: 5.0, completion: 15.0 },
  "gpt-4o-mini": { prompt: 0.15, completion: 0.6 },
  "gpt-4.1-mini": { prompt: 0.4, completion: 1.6 },
};

export function calculateCost(input: UsageLogInput): string {
  if (input.type === "llm_text" && input.modelName) {
    const pricing = PRICING[input.modelName] || PRICING["gemini-2.5-flash"];
    const promptCost = (input.promptTokens || 0) * (pricing.prompt / 1_000_000);
    const completionCost =
      (input.completionTokens || 0) * (pricing.completion / 1_000_000);
    return (promptCost + completionCost).toFixed(6);
  }

  if (input.type === "stt") {
    // Deepgram Nova-2: ~$0.0043/min
    const minutes = (input.durationMs || 0) / 60000;
    return (minutes * 0.0043).toFixed(6);
  }

  if (input.type === "tts") {
    // Deepgram Aura: ~$0.015 / 1000 characters (rough approx as duration)
    // Assuming 150 words per minute, 5 characters per word = 750 chars/min
    const minutes = (input.durationMs || 0) / 60000;
    const estimatedChars = minutes * 750;
    return ((estimatedChars / 1000) * 0.015).toFixed(6);
  }

  if (input.type === "voice_session") {
    // Bundle cost for STT + LLM + TTS (Deepgram Voice Agent)
    // Est: $0.10 per minute of "active" conversation
    const minutes = (input.durationMs || 0) / 60000;
    return (minutes * 0.1).toFixed(6);
  }

  if (input.type === "search") {
    // e.g. Tavily search: ~$0.01 per search
    return "0.010000";
  }

  if (input.type === "llm_embedding") {
    // OpenAI text-embedding-3-small: $0.00002 / 1k tokens
    const tokens = input.totalTokens || 0;
    return (tokens * (0.00002 / 1000)).toFixed(6);
  }

  return "0";
}

export function estimateUsageCost(input: UsageLogInput) {
  return Number(calculateCost(input));
}

/**
 * Log a software usage event to the database.
 */
export async function logUsage(input: UsageLogInput) {
  try {
    const cost = calculateCost(input);

    await getDb().insert(usageLogs).values({
      id: nanoid(),
      ...input,
      cost,
    });
  } catch (error) {
    // Don't let billing errors crash the main app flow, just log them
  }
}

