  selectionSource: "teacher_curated" | "internal_catalog" | "external_catalog";
  reason: string;
  expectedBenefit: string;
  followUpPrompt: string;
  transcript: string | null;
};

function shouldOfferMedia(params: {
  currentPhaseType: string | null;
  gapCount: number;
  conceptTitle: string | null;
}) {
  if (!params.conceptTitle) return false;
  if (params.currentPhaseType === "quiz" || params.currentPhaseType === "self_reflection") {
    return false;
  }
  return params.gapCount > 0 || params.currentPhaseType === "concept_teaching";
}

function inferPreferredAssetType(params: {
  currentPhaseType: string | null;
  gapCount: number;
}) {
  if (params.currentPhaseType === "concept_teaching" && params.gapCount > 0) {
    return "video";
  }

  return "image";
}

export async function selectTutorMedia(params: {
  organizationId: string;
  topicId: string;
  classroomId: string;
  gradeBand: string;
  currentPhaseType: string | null;
  conceptKey?: string | null;
  conceptTitle?: string | null;
  gapCount: number;
}) {
  if (
    !shouldOfferMedia({
      currentPhaseType: params.currentPhaseType,
      gapCount: params.gapCount,
      conceptTitle: params.conceptTitle ?? null,
    })
  ) {
    return null;
  }

  const preferredType = inferPreferredAssetType({
    currentPhaseType: params.currentPhaseType,
    gapCount: params.gapCount,
  });

  const bindings = await getDb()
    .select({
      bindingId: teachingMediaBindings.id,
      assetId: teachingMediaAssets.id,
      assetType: teachingMediaAssets.assetType,
      title: teachingMediaAssets.title,
      description: teachingMediaAssets.description,
      mediaUrl: teachingMediaAssets.mediaUrl,
      thumbnailUrl: teachingMediaAssets.thumbnailUrl,
      durationSeconds: teachingMediaAssets.durationSeconds,
      transcript: teachingMediaAssets.transcript,
      sourceType: teachingMediaAssets.sourceType,
      priority: teachingMediaBindings.priority,
      conceptKey: teachingMediaBindings.conceptKey,
      phaseType: teachingMediaBindings.phaseType,
    })
    .from(teachingMediaBindings)
    .innerJoin(teachingMediaAssets, eq(teachingMediaBindings.assetId, teachingMediaAssets.id))
    .where(
      and(
        eq(teachingMediaAssets.organizationId, params.organizationId),
        eq(teachingMediaAssets.status, "approved"),
        eq(teachingMediaAssets.assetType, preferredType),
        or(
          eq(teachingMediaBindings.topicId, params.topicId),
          and(isNull(teachingMediaBindings.topicId), eq(teachingMediaBindings.classroomId, params.classroomId)),
        ),
        or(
          isNull(teachingMediaBindings.gradeBand),
          eq(teachingMediaBindings.gradeBand, params.gradeBand),
        ),
        or(
          isNull(teachingMediaBindings.phaseType),
          eq(teachingMediaBindings.phaseType, params.currentPhaseType ?? ""),
        ),
        or(
          isNull(teachingMediaBindings.conceptKey),
          eq(teachingMediaBindings.conceptKey, params.conceptKey ?? ""),
        ),
      ),
    )
    .orderBy(asc(teachingMediaBindings.priority), asc(teachingMediaAssets.createdAt))
    .limit(1);

  const curated = bindings[0];
  if (curated) {
    return {
      assetId: curated.assetId,
      externalMediaId: null,
      assetType: curated.assetType as "image" | "video",
      title: curated.title,
      description: curated.description,
      mediaUrl: curated.mediaUrl,
      thumbnailUrl: curated.thumbnailUrl,
      durationSeconds: curated.durationSeconds,
      transcript: curated.transcript,
      selectionSource:
        curated.sourceType === "internal_catalog" ? "internal_catalog" : "teacher_curated",
      reason: `This ${curated.assetType} directly supports ${params.conceptTitle ?? "the current concept"} during ${params.currentPhaseType ?? "the current phase"}.`,
      expectedBenefit:
        curated.assetType === "video"
          ? "A short visual walkthrough can make the explanation easier to anchor."
          : "A focused visual reference can reduce abstraction and make the concept easier to picture.",
      followUpPrompt: `After looking at ${curated.title}, what part makes more sense now?`,
    } satisfies TutorMediaRecommendation;
  }

  const external = await getDb().query.externalMediaCache.findFirst({
    where: and(
      eq(externalMediaCache.assetType, preferredType),
      eq(externalMediaCache.approvedForDirectUse, true),
    ),
    orderBy: [asc(externalMediaCache.updatedAt)],
  });

  if (!external) {
    return null;
  }

  return {
    assetId: null,
    externalMediaId: external.id,
    assetType: external.assetType as "image" | "video",
    title: external.title,
    description: external.description,
    mediaUrl: external.sourceUrl,
    thumbnailUrl: external.thumbnailUrl,
    durationSeconds: external.durationSeconds,
    transcript: external.transcript,
    selectionSource: "external_catalog",
    reason: `No teacher-curated ${preferredType} matched this concept, so the tutor selected an approved external fallback.`,
    expectedBenefit:
      preferredType === "video"
        ? "A short approved clip can reinforce the idea with motion and sequence."
        : "An approved image can provide a quick visual anchor for the explanation.",
    followUpPrompt: `What did you notice in ${external.title} that connects back to ${params.conceptTitle ?? "the topic"}?`,
  } satisfies TutorMediaRecommendation;
}

export async function logTutorMediaUsage(params: {
  topicId: string;
  sessionId: string;
  classroomStudentId: string;
  aiRunId?: string | null;
  recommendation: TutorMediaRecommendation;
}) {
  await getDb().insert(teachingMediaUsageEvents).values({
    id: nanoid(),
    assetId: params.recommendation.assetId ?? null,
    externalMediaId: params.recommendation.externalMediaId ?? null,
    topicId: params.topicId,
    sessionId: params.sessionId,
    classroomStudentId: params.classroomStudentId,
    aiRunId: params.aiRunId ?? null,
    selectionSource: params.recommendation.selectionSource,
    reason: params.recommendation.reason,
    expectedBenefit: params.recommendation.expectedBenefit,
    followUpPrompt: params.recommendation.followUpPrompt,
    relevanceScore: null,
    usefulnessScore: null,
    metadata: {
      title: params.recommendation.title,
      assetType: params.recommendation.assetType,
      durationSeconds: params.recommendation.durationSeconds,
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  });
}

import { createHash } from "node:crypto";

import type { LanguageModel } from "ai";
import type { ProviderOptions } from "@ai-sdk/provider-utils";

export type { ProviderOptions };

import { env } from "@/lib/env";
import { getRedisClient } from "@/lib/redis";

const GOOGLE_CACHE_TTL_SECONDS = 60 * 60;
const GOOGLE_CACHE_REFRESH_WINDOW_SECONDS = 5 * 60;
// Keep this low enough that our reusable tutoring/survey prompt frames
// can participate in provider-side caching, while still avoiding tiny,
// low-signal prefixes that would churn cache keys.
const MIN_CACHEABLE_PREFIX_CHARS = 1400;

export type PromptCacheOptions = {
  namespace: string;
  staticSystemPrompt?: string;
  staticPromptPrefix?: string;
  ttlSeconds?: number;
};

type PromptCachePreparation = {
  providerOptions?: ProviderOptions;
  systemPrompt?: string;
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function getModelId(model: LanguageModel): string {
  return typeof model === "string" ? model : model.modelId ?? "";
}

function isOpenAIModel(modelId: string) {
  return modelId.startsWith("gpt") || modelId.startsWith("o");
}

function isGeminiModel(modelId: string) {
  return modelId.startsWith("gemini");
}

function isCacheablePrefix(value?: string | null) {
  return Boolean(value && value.trim().length >= MIN_CACHEABLE_PREFIX_CHARS);
}

function stableHash(value: string) {
  return createHash("sha256").update(value).digest("hex");
}

function buildOpenAIPromptCacheKey(input: {
  namespace: string;
  modelId: string;
  stablePrefix: string;
}) {
  return `convy:${input.namespace}:${input.modelId}:${stableHash(input.stablePrefix).slice(0, 24)}`;
}

async function getOrCreateGoogleCachedContent(input: {
  namespace: string;
  modelId: string;
  systemInstruction: string;
  ttlSeconds: number;
}) {
  const normalizedModel = input.modelId.startsWith("models/")
    ? input.modelId
    : `models/${input.modelId}`;
  const contentHash = stableHash(
    `${normalizedModel}\n${input.namespace}\n${input.systemInstruction}`,
  );
  const redis = getRedisClient();
  const redisKey = `prompt-cache:google:${contentHash}`;
  const lockKey = `${redisKey}:lock`;

  function parseCachedContentMetadata(value: unknown): {
    cachedContent: string;
    expiresAt: string;
  } | null {
    if (
      !isRecord(value) ||
      typeof value.cachedContent !== "string" ||
      typeof value.expiresAt !== "string"
    ) {
      return null;
    }

    return {
      cachedContent: value.cachedContent,
      expiresAt: value.expiresAt,
    };
  }

  try {
    const cachedRaw = await redis.get(redisKey);
    if (typeof cachedRaw === "string" && cachedRaw.length > 0) {
      const parsed = parseCachedContentMetadata(JSON.parse(cachedRaw));
      if (
        parsed &&
        Date.parse(parsed.expiresAt) - Date.now() >
          GOOGLE_CACHE_REFRESH_WINDOW_SECONDS * 1000
      ) {
        return parsed.cachedContent;
      }
    }
  } catch (error) {
  }

  let lockAcquired = false;
  try {
    const lockResult = await redis.set(lockKey, "1", "EX", 30, "NX");
    lockAcquired = lockResult === "OK";
  } catch (error) {
  }

  if (!lockAcquired) {
    for (let attempt = 0; attempt < 3; attempt += 1) {
      await new Promise((resolve) => setTimeout(resolve, 200));
      try {
        const cachedRaw = await redis.get(redisKey);
        if (typeof cachedRaw === "string" && cachedRaw.length > 0) {
          const parsed = parseCachedContentMetadata(JSON.parse(cachedRaw));
          if (parsed?.cachedContent) {
            return parsed.cachedContent;
          }
        }
      } catch {
        break;
      }
    }

    return null;
  }

  try {
    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/cachedContents?key=${env.GOOGLE_GENERATIVE_AI_API_KEY}`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: normalizedModel,
          displayName: `convy-${input.namespace}-${contentHash.slice(0, 8)}`,
          systemInstruction: {
            role: "system",
            parts: [{ text: input.systemInstruction }],
          },
          ttl: `${input.ttlSeconds}s`,
        }),
      },
    );

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(
        `Google cachedContents create failed (${response.status}): ${errorText}`,
      );
    }

    const rawPayload = await response.json();
    if (!isRecord(rawPayload) || typeof rawPayload.name !== "string") {
      throw new Error("Google cachedContents response did not include a name");
    }

    const expiresAt =
      (typeof rawPayload.expireTime === "string" ? rawPayload.expireTime : undefined) ||
      new Date(Date.now() + input.ttlSeconds * 1000).toISOString();

    try {
      await redis.set(
        redisKey,
        JSON.stringify({
          cachedContent: rawPayload.name,
          expiresAt,
        }),
        "EX",
        Math.max(60, input.ttlSeconds - GOOGLE_CACHE_REFRESH_WINDOW_SECONDS),
      );
    } catch (error) {
    }

    return rawPayload.name;
  } catch (error) {
    return null;
  } finally {
    try {
      await redis.del(lockKey);
    } catch {
      // Best effort cleanup only.
    }
  }
}

export async function preparePromptCache(input: {
  model: LanguageModel;
  systemPrompt?: string;
  promptCache?: PromptCacheOptions;
}): Promise<PromptCachePreparation> {
  const { promptCache } = input;
  if (!promptCache) {
    return { systemPrompt: input.systemPrompt };
  }

  const modelId = getModelId(input.model);
  const stablePrefix =
    promptCache.staticSystemPrompt ?? promptCache.staticPromptPrefix ?? "";
  const providerOptions: ProviderOptions = {};
  const staticSystemPrompt = promptCache.staticSystemPrompt;
  const combinedSystemPrompt =
    staticSystemPrompt &&
    staticSystemPrompt !== input.systemPrompt
      ? [staticSystemPrompt, input.systemPrompt]
          .filter((value): value is string => Boolean(value && value.trim()))
          .join("\n\n")
      : input.systemPrompt;
  let systemPrompt = combinedSystemPrompt;

  if (isCacheablePrefix(stablePrefix) && isOpenAIModel(modelId)) {
    providerOptions.openai = {
      promptCacheKey: buildOpenAIPromptCacheKey({
        namespace: promptCache.namespace,
        modelId,
        stablePrefix,
      }),
    };
  }

  if (
    staticSystemPrompt &&
    isCacheablePrefix(staticSystemPrompt) &&
    isGeminiModel(modelId)
  ) {
    const cachedContent = await getOrCreateGoogleCachedContent({
      namespace: promptCache.namespace,
      modelId,
      systemInstruction: staticSystemPrompt,
      ttlSeconds: promptCache.ttlSeconds ?? GOOGLE_CACHE_TTL_SECONDS,
    });

    if (cachedContent) {
      providerOptions.google = { cachedContent };
      systemPrompt =
        input.systemPrompt === staticSystemPrompt
          ? undefined
          : input.systemPrompt;
    }
  }

  return {
    providerOptions:
      Object.keys(providerOptions).length > 0 ? providerOptions : undefined,
    systemPrompt,
  };
}

import { SearchResult } from "./search";
import { logUsage } from "../billing/logger";
import { generateText, Output } from "ai";
import { flashLiteModel } from "../ai";
import { z } from "zod";

const VOYAGE_API_URL = "https://api.voyageai.com/v1/rerank";

export async function rerank(
  query: string,
  candidates: SearchResult[],
  topK: number = 5,
  metadata?: {
    userId?: string;
    organizationId?: string;
    surveyId?: string;
  },
): Promise<SearchResult[]> {
  if (candidates.length === 0) return [];

  // Protect against edge cases where the key is missing
  const apiKey = process.env.VOYAGE_API_KEY;
  if (apiKey) {
    try {
      const documents = candidates.map((c) => c.content);

      const response = await fetch(VOYAGE_API_URL, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${apiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          query,
          documents,
          model: "rerank-2",
          top_k: topK,
        }),
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Voyage API error: ${response.status} - ${errorText}`);
      }

      const data = await response.json();

      // Log the usage
      if (data.usage?.total_tokens) {
        logUsage({
          userId: metadata?.userId,
          organizationId: metadata?.organizationId,
          surveyId: metadata?.surveyId,
          type: "llm_text",
          provider: "voyage",
          modelName: "rerank-2",
          promptTokens: data.usage.total_tokens, // Voyage bills primarily on total tokens for reranking
          completionTokens: 0,
          totalTokens: data.usage.total_tokens,
        });
      }

      const rankedResults: SearchResult[] = [];
      const seenIndices = new Set<number>();

      // Voyage returns data array sorted by relevance_score
      for (const item of data.data) {
        const index = item.index;
        if (index >= 0 && index < candidates.length) {
          rankedResults.push({
            ...candidates[index],
            score: item.relevance_score ?? candidates[index].score // Update the score with the new rerank score if available
          });
          seenIndices.add(index);
        }
      }

      // Fallback fill just in case
      if (rankedResults.length < topK) {
        for (let i = 0; i < candidates.length; i++) {
          if (!seenIndices.has(i)) {
            rankedResults.push(candidates[i]);
            if (rankedResults.length >= topK) break;
          }
        }
      }

      return rankedResults;
    } catch (error) {
    }
  } else {
  }

  try {
    const { output: object, usage } = await generateText({
      model: flashLiteModel,
      output: Output.object({
        schema: z.object({
          rankedIndices: z
            .array(z.number())
            .describe("Indices of the candidates in order of relevance (0-based)"),
        }),
      }),
      system: `You are a search quality rater. Your task is to rank the following search results based on their relevance to the user's query.
Return the indices of the most relevant results, ordered from most relevant to least relevant.
Ignore results that are irrelevant to the query.`,
      prompt: `Query: "${query}"

Results:
${candidates.map((c, i) => `[${i}] ${c.content.substring(0, 300)}...`).join("\n")}

Rank the top ${topK} results.`,
    });

    if (usage) {
      logUsage({
        userId: metadata?.userId,
        organizationId: metadata?.organizationId,
        surveyId: metadata?.surveyId,
        type: "llm_text",
        provider: "google",
        modelName: "gemini-2.5-flash-lite",
        promptTokens: usage.inputTokens,
        completionTokens: usage.outputTokens,
        totalTokens: usage.totalTokens,
      });
    }

    const rankedResults: SearchResult[] = [];
    const seenIndices = new Set<number>();

    for (const index of object.rankedIndices) {
      if (index >= 0 && index < candidates.length && !seenIndices.has(index)) {
        rankedResults.push(candidates[index]);
        seenIndices.add(index);
      }
      if (rankedResults.length >= topK) break;
    }

    if (rankedResults.length < topK) {
      for (let i = 0; i < candidates.length; i++) {
        if (!seenIndices.has(i)) {
          rankedResults.push(candidates[i]);
          if (rankedResults.length >= topK) break;
        }
      }
    }

    return rankedResults;
  } catch (fallbackError) {
    return candidates.slice(0, topK);
  }
}

/**
 * Specialized reranker for text snippets.
 * Used by agents to refine context before including it in prompts.
 */
export async function rerankResults(
  query: string,
  items: string[],
  topK: number = 5,
): Promise<{ item: string; score?: number }[]> {
  if (items.length === 0) return [];

  const tempCandidates: SearchResult[] = items.map((content, i) => ({
    id: `temp-${i}`,
    content,
    score: 0,
    metadata: {},
    sourceType: "temp",
    createdAt: new Date(),
  }));

  const ranked = await rerank(query, tempCandidates, topK);

  return ranked.map((r) => ({
    item: r.content,
    score: r.score
  }));
}

import { getDb } from "@/db";
import { documentEmbeddings } from "@/db/schema/vectors";
import { generateEmbedding } from "./embeddings";
import { and, desc, eq, gt, sql, inArray } from "drizzle-orm";
import { SupportedLanguage } from "../translation-service";
import { generateText, Output } from "ai";
import { flashLiteModel } from "../ai";
import { z } from "zod";
import { rerank } from "./reranker";

export interface SearchFilters {
  organizationId?: string;
  surveyId?: string;
  sourceType?: (
    | "response"
    | "insight"
    | "analytics"
    | "document"
  )[];
  minDate?: Date;
  limit?: number;
  language?: SupportedLanguage;
  sessionType?: "sample" | "live";
}

export interface SearchResult {
  id: string;
  content: string;
  score: number;
  metadata: Record<string, unknown>;
  sourceType: string;
  sourceId?: string;
  createdAt: Date;
}

function normalizeMetadata(value: unknown): Record<string, unknown> {
  return typeof value === "object" && value !== null
    ? Object.fromEntries(Object.entries(value))
    : {};
}

export async function vectorSearch(
  query: string,
  filters: SearchFilters = {},
): Promise<SearchResult[]> {
  const embedding = await generateEmbedding(query);
  const limit = filters.limit || 20;
  const queryVector = JSON.stringify(embedding);

  // Search document embeddings
  const docResults = await getDb()
    .select({
      id: documentEmbeddings.id,
      content: documentEmbeddings.content,
      metadata: documentEmbeddings.metadata,
      sourceType: documentEmbeddings.sourceType,
      sourceId: documentEmbeddings.sourceId,
      createdAt: documentEmbeddings.createdAt,
      similarity: sql<number>`1 - (${documentEmbeddings.embedding} <=> ${queryVector})`,
    })
    .from(documentEmbeddings)
    .where(
      and(
        filters.surveyId
          ? eq(documentEmbeddings.surveyId, filters.surveyId)
          : undefined,
        filters.sourceType
          ? inArray(documentEmbeddings.sourceType, filters.sourceType)
          : undefined,
        filters.minDate
          ? gt(documentEmbeddings.createdAt, filters.minDate)
          : undefined,
        // Only valid embeddings
        sql`${documentEmbeddings.embedding} IS NOT NULL`,
        filters.language
          ? sql`${documentEmbeddings.metadata}->>'language' = ${filters.language}`
          : undefined,
        filters.organizationId
          ? sql`${documentEmbeddings.metadata}->>'organizationId' = ${filters.organizationId}`
          : undefined,
        filters.sessionType
          ? sql`${documentEmbeddings.metadata}->>'sessionType' = ${filters.sessionType}`
          : undefined,
      ),
    )
    .orderBy(sql`${documentEmbeddings.embedding} <=> ${queryVector} ASC`)
    .limit(limit);

  return docResults.map((r) => ({
    id: r.id,
    content: r.content,
    score: r.similarity,
    metadata: normalizeMetadata(r.metadata),
    sourceType: r.sourceType,
    sourceId: r.sourceId || undefined,
    createdAt: r.createdAt,
  }));
}

export async function fullTextSearch(
  query: string,
  filters: SearchFilters = {},
  language: SupportedLanguage = "en",
): Promise<SearchResult[]> {
  const limit = filters.limit || 20;
  const effectiveLanguage = filters.language ?? language;

  const langConfigMap: Record<SupportedLanguage, string> = {
    en: "english",
    fr: "french",
    de: "german",
    es: "spanish",
    it: "italian",
  };

  const tsConfig = langConfigMap[effectiveLanguage] || "english";
  const tsQuery = sql`websearch_to_tsquery(${tsConfig}, ${query})`;

  const docRank = sql<number>`ts_rank(to_tsvector(${tsConfig}, ${documentEmbeddings.content}), ${tsQuery})`;

  const docResults = await getDb()
    .select({
      id: documentEmbeddings.id,
      content: documentEmbeddings.content,
      metadata: documentEmbeddings.metadata,
      sourceType: documentEmbeddings.sourceType,
      sourceId: documentEmbeddings.sourceId,
      createdAt: documentEmbeddings.createdAt,
      rank: docRank,
    })
    .from(documentEmbeddings)
    .where(
      and(
        filters.surveyId
          ? eq(documentEmbeddings.surveyId, filters.surveyId)
          : undefined,
        filters.sourceType
          ? inArray(documentEmbeddings.sourceType, filters.sourceType)
          : undefined,
        filters.minDate
          ? gt(documentEmbeddings.createdAt, filters.minDate)
          : undefined,
        sql`to_tsvector(${tsConfig}, ${documentEmbeddings.content}) @@ ${tsQuery}`,
        effectiveLanguage
          ? sql`${documentEmbeddings.metadata}->>'language' = ${effectiveLanguage}`
          : undefined,
        filters.organizationId
          ? sql`${documentEmbeddings.metadata}->>'organizationId' = ${filters.organizationId}`
          : undefined,
        filters.sessionType
          ? sql`${documentEmbeddings.metadata}->>'sessionType' = ${filters.sessionType}`
          : undefined,
      ),
    )
    .orderBy(desc(docRank))
    .limit(limit);

  return docResults.map((r) => ({
    id: r.id,
    content: r.content,
    score: r.rank,
    metadata: normalizeMetadata(r.metadata),
    sourceType: r.sourceType,
    sourceId: r.sourceId || undefined,
    createdAt: r.createdAt,
  }));
}

export async function hybridSearch(
  query: string,
  filters: SearchFilters = {},
  language: SupportedLanguage = "en",
): Promise<SearchResult[]> {
  const limit = filters.limit || 20;

  const [vectorResults, textResults] = await Promise.all([
    vectorSearch(query, {
      ...filters,
      limit: limit * 2,
      language: filters.language || language,
    }),
    fullTextSearch(
      query,
      { ...filters, limit: limit * 2 },
      filters.language || language,
    ),
  ]);

  const k = 60;
  const scores = new Map<string, number>();
  const resultsMap = new Map<string, SearchResult>();

  vectorResults.forEach((result, index) => {
    scores.set(result.id, (scores.get(result.id) || 0) + 1 / (k + index + 1));
    resultsMap.set(result.id, result);
  });

  textResults.forEach((result, index) => {
    scores.set(result.id, (scores.get(result.id) || 0) + 1 / (k + index + 1));
    if (!resultsMap.has(result.id)) {
      resultsMap.set(result.id, result);
    }
  });

  const fusedResults = Array.from(scores.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([id, score]) => {
      const result = resultsMap.get(id)!;
      return {
        ...result,
        score: score,
      };
    });

  return fusedResults;
}

export async function executeRAGQuery(
  rawQuery: string,
  filters: SearchFilters,
  language: SupportedLanguage = "en",
): Promise<SearchResult[]> {
  if (!filters.organizationId) {
  }

  const queriesToRun = [rawQuery];

  try {
    const { output: object } = await generateText({
      model: flashLiteModel,
      output: Output.object({
        schema: z.object({
          hydeAnswer: z.string().describe("Write a hypothetical first-person respondent answer to the query constraint."),
          variants: z.array(z.string()).describe("Write 3 semantically distinct variations or alternative vocabulary phrasings of the raw user query."),
        }),
      }),
      prompt: `Original Query: "${rawQuery}"\nLanguage: ${language}\nGenerate a hypothetical answer and query variants for better RAG retrieval.`,
    });

    if (object.hydeAnswer) queriesToRun.push(object.hydeAnswer);
    if (object.variants && object.variants.length > 0) {
      queriesToRun.push(...object.variants.slice(0, 3));
    }
  } catch (error) {
  }

  const fetchLimit = filters.limit || 20;
  const k = 60;
  const scores = new Map<string, number>();
  const resultsMap = new Map<string, SearchResult>();

  await Promise.all(
    queriesToRun.map(async (q) => {
      const [vectorResults, textResults] = await Promise.all([
        vectorSearch(q, { ...filters, limit: fetchLimit * 2, language }),
        fullTextSearch(q, { ...filters, limit: fetchLimit * 2 }, language),
      ]);

      vectorResults.forEach((result, index) => {
        scores.set(result.id, (scores.get(result.id) || 0) + 1 / (k + index + 1));
        resultsMap.set(result.id, result);
      });

      textResults.forEach((result, index) => {
        scores.set(result.id, (scores.get(result.id) || 0) + 1 / (k + index + 1));
        if (!resultsMap.has(result.id)) {
          resultsMap.set(result.id, result);
        }
      });
    })
  );

  const candidatePool = Array.from(scores.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 150)
    .map(([id, score]) => {
      const result = resultsMap.get(id)!;
      return { ...result, score };
    });

  const finalContextLimit = fetchLimit;
  const reranked = await rerank(rawQuery, candidatePool, finalContextLimit);

  return reranked.map(r => {
    const rawAnswer = r.content;
    r.content = `[Source ID: ${r.id}] Context chunk:\n${rawAnswer}`;
    return r;
  });
}

import { generateText } from "ai";
import { google } from "@ai-sdk/google";
import { logUsage } from "./billing/logger";
import { appLocaleLabels, type AppLocale } from "@/lib/i18n/config";

/**
 * Translation Service for Locale-Aware Survey System
 * Handles conversation translation for dual storage (raw + translated)
 */

export type SupportedLanguage = AppLocale;

export interface ConversationMessage {
  role: "user" | "assistant";
  content: string;
  timestamp: string;
}

export interface TranslationResult {
  translatedConversation: ConversationMessage[];
  sourceLanguage: SupportedLanguage;
  targetLanguage: SupportedLanguage;
}

/**
 * Translate a conversation from one language to another
 * Uses Gemini for accurate, context-aware translation
 */
export async function translateConversation(
  conversation: ConversationMessage[],
  sourceLanguage: SupportedLanguage,
  targetLanguage: SupportedLanguage,
  metadata?: {
    userId?: string;
    surveyId?: string;
  },
): Promise<TranslationResult> {
  // If source and target are the same, return unchanged
  if (sourceLanguage === targetLanguage) {
    return {
      translatedConversation: conversation,
      sourceLanguage,
      targetLanguage,
    };
  }

  // Build translation prompt
  const conversationText = conversation
    .map(
      (msg) => `${msg.role === "user" ? "RESPONDENT" : "AI"}: ${msg.content}`,
    )
    .join("\n\n");

  const prompt = `You are a professional translator. Translate the following survey conversation from ${appLocaleLabels[sourceLanguage]} to ${appLocaleLabels[targetLanguage]}.

CRITICAL INSTRUCTIONS:
1. Maintain the exact structure: each line should start with either "RESPONDENT:" or "AI:"
2. Translate the content accurately while preserving meaning, tone, and context
3. Keep the conversation natural in the target language
4. Do NOT add any additional commentary or explanations
5. Output ONLY the translated conversation in the exact same format

Original Conversation (${appLocaleLabels[sourceLanguage]}):
---
${conversationText}
---

Translated Conversation (${appLocaleLabels[targetLanguage]}):`;

  try {
    const { text, usage } = await generateText({
      model: google("gemini-2.5-flash-lite"),
      prompt,
      temperature: 0.3, // Lower temperature for more consistent translations
    });

    // Log usage for translation
    logUsage({
      userId: metadata?.userId,
      surveyId: metadata?.surveyId,
      type: "llm_text",
      provider: "google",
      modelName: "gemini-2.5-flash-lite",
      promptTokens: usage.inputTokens,
      completionTokens: usage.outputTokens,
      totalTokens: usage.totalTokens,
    });

    // Parse the translated text back into conversation format
    const translatedMessages: ConversationMessage[] = [];
    const lines = text.trim().split("\n");

    let currentRole: "user" | "assistant" | null = null;
    let currentContent = "";

    for (const line of lines) {
      const trimmedLine = line.trim();

      if (trimmedLine.startsWith("RESPONDENT:")) {
        // Save previous message if exists
        if (currentRole && currentContent) {
          translatedMessages.push({
            role: currentRole,
            content: currentContent.trim(),
            timestamp:
              conversation[translatedMessages.length]?.timestamp ||
              new Date().toISOString(),
          });
        }
        currentRole = "user";
        currentContent = trimmedLine.substring("RESPONDENT:".length).trim();
      } else if (trimmedLine.startsWith("AI:")) {
        // Save previous message if exists
        if (currentRole && currentContent) {
          translatedMessages.push({
            role: currentRole,
            content: currentContent.trim(),
            timestamp:
              conversation[translatedMessages.length]?.timestamp ||
              new Date().toISOString(),
          });
        }
        currentRole = "assistant";
        currentContent = trimmedLine.substring("AI:".length).trim();
      } else if (trimmedLine && currentRole) {
        // Continuation of current message
        currentContent += " " + trimmedLine;
      }
    }

    // Add the last message
    if (currentRole && currentContent) {
      translatedMessages.push({
        role: currentRole,
        content: currentContent.trim(),
        timestamp:
          conversation[translatedMessages.length]?.timestamp ||
          new Date().toISOString(),
      });
    }

    // Validate we got the same number of messages
    if (translatedMessages.length !== conversation.length) {
      return {
        translatedConversation: conversation,
        sourceLanguage,
        targetLanguage,
      };
    }

    return {
      translatedConversation: translatedMessages,
      sourceLanguage,
      targetLanguage,
    };
  } catch (error) {
    // Fallback: return original conversation
    return {
      translatedConversation: conversation,
      sourceLanguage,
      targetLanguage,
    };
  }
}

/**
 * Batch translate multiple conversations for efficiency
 */
export async function batchTranslateConversations(
  conversations: Array<{
    id: string;
    messages: ConversationMessage[];
    sourceLanguage: SupportedLanguage;
  }>,
  targetLanguage: SupportedLanguage,
): Promise<Map<string, ConversationMessage[]>> {
  const results = new Map<string, ConversationMessage[]>();

  // Translate conversations in parallel (with reasonable concurrency limit)
  const BATCH_SIZE = 5;
  for (let i = 0; i < conversations.length; i += BATCH_SIZE) {
    const batch = conversations.slice(i, i + BATCH_SIZE);

    const batchResults = await Promise.all(
      batch.map(async (conv) => {
        const result = await translateConversation(
          conv.messages,
          conv.sourceLanguage,
          targetLanguage,
        );
        return { id: conv.id, translated: result.translatedConversation };
      }),
    );

    for (const { id, translated } of batchResults) {
      results.set(id, translated);
    }
  }

  return results;
}

/**
 * Get user's preferred language from database
 */
export async function getUserPreferredLanguage(
  userId: string,
): Promise<SupportedLanguage> {
  try {
    const { getDb } = await import("@/db");
    const { users } = await import("@/db/schema");
    const { eq } = await import("drizzle-orm");

    const [user] = await getDb()
      .select({ preferredLanguage: users.preferredLanguage, uiLocale: users.uiLocale })
      .from(users)
      .where(eq(users.id, userId))
      .limit(1);

    const locale = user?.uiLocale ?? user?.preferredLanguage;
    switch (locale) {
      case "fr":
      case "de":
      case "es":
      case "it":
      case "en":
        return locale;
      default:
        return "en";
    }
  } catch (error) {
    return "en";
  }
}

/**
 * Deepgram Voice Agent API Connection
 *
 * Wraps the Deepgram Voice Agent WebSocket API (v1) to provide a single
 * managed connection that handles STT→LLM→TTS internally.
 *
 * The server creates one of these per voice session, sends audio from the
 * browser to it, and relays events/audio back.
 */

import { WebSocket } from "ws";
import { EventEmitter } from "events";
import { env } from "@/lib/env";
import type { SupportedVoiceLocale } from "@/lib/voice/voice-locales";

// ── Types ────────────────────────────────────────────────────────────────────

export type SupportedLanguage = SupportedVoiceLocale;

export interface VoiceAgentFunction {
  name: string;
  description: string;
  parameters: Record<string, unknown>;
  client_side?: boolean;
  endpoint?: {
    url: string;
    method: string;
    headers?: Record<string, string>;
  };
}

export interface VoiceAgentSettings {
  audio?: {
    input?: { encoding?: string; sample_rate?: number };
    output?: { encoding?: string; sample_rate?: number; container?: string };
  };
  agent: {
    language?: string;
    listen?: {
      provider: {
        type: string;
        model?: string;
        version?: string;
        language?: string;
        smart_format?: boolean;
        endpointing?: number;
        keyterms?: string[];
      };
    };
    think: {
      provider: { type: string; model?: string };
      endpoint?: {
        url: string;
        headers?: Record<string, string>;
      };
      prompt: string;
      functions?: VoiceAgentFunction[];
    };
    speak?: {
      provider: {
        type: string;
        model?: string;
        model_id?: string;
      };
    };
    greeting?: string;
    context?: {
      messages: Array<{ role: string; content: string }>;
    };
  };
  flags?: {
    history?: boolean;
  };
}

export interface ConversationTextEvent {
  role: "user" | "assistant";
  content: string;
}

export interface FunctionCallRequestEvent {
  function_call_id: string;
  function_name: string;
  input: Record<string, unknown>;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseConversationTextEvent(
  value: unknown,
): ConversationTextEvent | null {
  if (
    !isRecord(value) ||
    (value.role !== "user" && value.role !== "assistant") ||
    typeof value.content !== "string"
  ) {
    return null;
  }

  return {
    role: value.role,
    content: value.content,
  };
}

function parseFunctionCallRequestEvent(
  value: unknown,
): FunctionCallRequestEvent | null {
  if (
    !isRecord(value) ||
    typeof value.id !== "string" ||
    typeof value.name !== "string"
  ) {
    return null;
  }

  let input: Record<string, unknown> = {};
  if (typeof value.arguments === "string") {
    try {
      const parsed = JSON.parse(value.arguments);
      input = isRecord(parsed) ? parsed : {};
    } catch {
      input = {};
    }
  }

  return {
    function_call_id: value.id,
    function_name: value.name,
    input,
  };
}

function getErrorCode(value: unknown): string {
  if (typeof value === "number" || typeof value === "string") {
    return String(value);
  }

  return "";
}

// ── Voice/Language Mapping ───────────────────────────────────────────────────

const VOICE_MODEL_MAP: Record<
  SupportedLanguage,
  { casual: string; formal: string; empathetic: string }
> = {
  en: {
    casual: "aura-2-asteria-en",
    formal: "aura-2-orpheus-en",
    empathetic: "aura-2-vesta-en",
  },
  fr: {
    casual: "aura-2-agathe-fr",
    formal: "aura-2-hector-fr",
    empathetic: "aura-2-agathe-fr",
  },
  de: {
    casual: "aura-2-viktoria-de",
    formal: "aura-2-fabian-de",
    empathetic: "aura-2-viktoria-de",
  },
  es: {
    casual: "aura-2-celeste-es",
    formal: "aura-2-nestor-es",
    empathetic: "aura-2-celeste-es",
  },
  it: {
    casual: "aura-2-livia-it",
    formal: "aura-2-dionisio-it",
    empathetic: "aura-2-livia-it",
  },
};

/**
 * Get the TTS model name for a given language and tone
 */
export function getVoiceModel(
  language: SupportedLanguage,
  tone: "casual" | "formal" | "playful" | "empathetic" = "casual",
): string {
  const models = VOICE_MODEL_MAP[language] || VOICE_MODEL_MAP.en;
  if (tone === "formal") return models.formal;
  if (tone === "empathetic") return models.empathetic; // now actually used
  return models.casual; // covers "casual" and "playful"
}

// ── Connection Class ─────────────────────────────────────────────────────────

const VOICE_AGENT_ENDPOINT = "wss://agent.deepgram.com/v1/agent/converse";
const KEEP_ALIVE_INTERVAL_MS = 8000;
export const VOICE_AGENT_THINK_MODEL = "gpt-4.1-mini";

export class DeepgramVoiceAgentConnection extends EventEmitter {
  private ws: WebSocket | null = null;
  private keepAliveInterval: NodeJS.Timeout | null = null;
  private isConnected: boolean = false;
  // v1 sequencing gates (per Deepgram message flow docs)
  private isWelcomeReceived: boolean = false;
  private isSettingsApplied: boolean = false; // Set on SettingsApplied → enables audio streaming
  private settings: VoiceAgentSettings;

  constructor(settings: VoiceAgentSettings) {
    super();
    this.settings = settings;
  }

  /**
   * Open the WebSocket connection to Deepgram Voice Agent
   */
  async connect(): Promise<void> {
    return new Promise((resolve, reject) => {
      const apiKey = env.DEEPGRAM_API_KEY;
      if (!apiKey) {
        reject(new Error("DEEPGRAM_API_KEY is not configured"));
        return;
      }

      const url = `${VOICE_AGENT_ENDPOINT}`;

      this.ws = new WebSocket(url, {
        headers: {
          Authorization: `Token ${apiKey}`,
        },
      });

      this.ws.on("open", () => {
        this.isConnected = true;
        resolve();
      });

      this.ws.on("message", (data: Buffer, isBinary: boolean) => {
        this.handleMessage(data, isBinary);
      });

      this.ws.on("error", (error) => {
        this.emit("error", error);
        if (!this.isConnected) {
          reject(error);
        }
      });

      this.ws.on("close", (code, reason) => {
        this.isConnected = false;
        this.isWelcomeReceived = false;
        this.isSettingsApplied = false;
        this.stopKeepAlive();
        this.emit("close", code, reason.toString());
      });
    });
  }

  /**
   * Send the Settings message to configure the agent
   */
  private sendSettings(): void {
    const settingsMessage = {
      type: "Settings",
      ...this.settings,
    };

    this.sendJson(settingsMessage);
  }

  /**
   * Send raw audio data to the Voice Agent
   */
  sendAudio(audioData: Buffer): void {
    // v1 doc: "Do not send audio until you receive SettingsApplied."
    if (!this.isSettingsApplied) {
      return;
    }
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(audioData);
    }
  }

  sendInjectAgentMessage(text: string): void {
    // Spec: { type: "InjectAgentMessage", message: "..." }
    // Note: InjectUserMessage (old) used { type: "InjectUserMessage", content: "..." }
    // InjectAgentMessage triggers the AGENT to say something.
    this.sendJson({
      type: "InjectAgentMessage",
      message: text,
    });
  }

  /** @deprecated Use InjectAgentMessage instead (agent speaks proactively) */
  sendInjectUserMessage(text: string): void {
    this.sendJson({
      type: "InjectUserMessage",
      content: text,
    });
  }

  /**
   * Respond to a function call request from the agent
   */
  sendFunctionCallResponse(
    functionCallId: string,
    name: string,
    output: string,
  ): void {
    this.sendJson({
      type: "FunctionCallResponse",
      id: functionCallId,
      name,
      content: output,
    });
  }

  /**
   * Replace the entire Think provider configuration mid-conversation.
   * This is preferred for prompt updates as it replaces rather than appends.
   */
  updateThink(think: VoiceAgentSettings["agent"]["think"]): void {
    this.settings.agent.think = think;
    if (this.isWelcomeReceived) {
      this.sendJson({
        type: "UpdateThink",
        think,
      });
    }
  }

  /**
   * Add to the existing system prompt mid-conversation.
   * Note: This appends to the current prompt.
   */
  updatePrompt(prompt: string): void {
    if (this.isWelcomeReceived) {
      this.sendJson({
        type: "UpdatePrompt",
        prompt,
      });
    }
  }

  /**
   * Change the Speak model mid-conversation.
   */
  updateSpeak(speak: VoiceAgentSettings["agent"]["speak"]): void {
    if (speak) {
      this.settings.agent.speak = speak;
      if (this.isWelcomeReceived) {
        this.sendJson({
          type: "UpdateSpeak",
          speak,
        });
      }
    }
  }

  /**
   * Send updated settings (e.g., language change)
   */
  updateSettings(settings: VoiceAgentSettings): void {
    this.settings = settings;
    // We must only send settings if we have already received the Welcome message from Deepgram.
    if (this.isWelcomeReceived) {
      this.sendSettings();
    }
  }

  /**
   * Close the connection
   */
  close(): void {
    this.stopKeepAlive();
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
    this.isConnected = false;
  }

  /**
   * Check if connected
   */
  get connected(): boolean {
    return this.isConnected && this.ws?.readyState === WebSocket.OPEN;
  }

  /** True once SettingsApplied has been received — audio streaming is safe after this. */
  get settingsApplied(): boolean {
    return this.isSettingsApplied;
  }

  // ── Private Helpers ──────────────────────────────────────────────────────

  private handleMessage(data: Buffer | string, isBinary: boolean): void {
    // Binary data = audio from agent
    if (isBinary) {
      //  // Commented out to reduce noise
      this.emit("audio", data);
      return;
    }

    // String data = JSON event
    try {
      const message = JSON.parse(data.toString());
      if (!isRecord(message) || typeof message.type !== "string") {
        return;
      }
      this.handleJsonMessage(message as { type: string; [key: string]: unknown });
    } catch (error) {
    }
  }

  private handleJsonMessage(message: { type: string; [key: string]: unknown }): void {
    switch (message.type) {
      case "Welcome":
        this.isWelcomeReceived = true;
        // v1 doc: send Settings only after Welcome, then start KeepAlive
        this.sendSettings();
        this.startKeepAlive();
        this.emit("welcome", message);
        break;

      case "SettingsApplied":
        this.isSettingsApplied = true;
        // v1 doc: audio streaming is now safe
        this.emit("settingsApplied", message);
        break;

      case "ConversationText":
        {
          const event = parseConversationTextEvent(message);
          if (event) {
            this.emit("conversationText", event);
          }
        }
        break;

      case "InjectionRefused":
        this.emit("injectionRefused", message);
        break;

      case "UserStartedSpeaking":
        this.emit("userStartedSpeaking");
        break;

      case "AgentThinking":
        this.emit("agentThinking", message.content);
        break;

      case "AgentStartedSpeaking":
        this.emit("agentStartedSpeaking");
        break;

      case "AgentAudioDone":
        this.emit("agentAudioDone");
        break;

      case "FunctionCallRequest":
        // V1 schema: { type: "FunctionCallRequest", functions: [{ id, name, arguments, client_side, ... }] }
        if (message.functions && Array.isArray(message.functions)) {
          for (const fn of message.functions) {
            const event = parseFunctionCallRequestEvent(fn);
            if (event) {
              this.emit("functionCallRequest", event);
            }
          }
        }
        break;

      case "Error":
        this.emit("error", {
          description:
            typeof message.description === "string"
              ? message.description
              : JSON.stringify(message),
          code: getErrorCode(message.code),
        });
        break;

      case "Warning":
        this.emit("warning", message);
        break;

      case "ThinkUpdated":
        this.emit("thinkUpdated");
        break;

      case "PromptUpdated":
        this.emit("promptUpdated");
        break;

      case "SpeakUpdated":
        this.emit("speakUpdated");
        break;

      default:
        break;
    }
  }

  private sendJson(data: Record<string, unknown>): void {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(data));
    } else {
      // Swallowed to reduce noise
    }
  }

  private stopKeepAlive(): void {
    if (this.keepAliveInterval) {
      clearInterval(this.keepAliveInterval);
      this.keepAliveInterval = null;
    }
  }

  /**
   * Start sending KeepAlive messages
   */
  private startKeepAlive(): void {
    this.stopKeepAlive();
    this.keepAliveInterval = setInterval(() => {
      this.sendJson({ type: "KeepAlive" });
    }, KEEP_ALIVE_INTERVAL_MS);
  }
}

// ── Factory Helper ───────────────────────────────────────────────────────────

/**
 * Build a VoiceAgentSettings object with sensible defaults
 */
export function buildVoiceAgentSettings(options: {
  language: SupportedLanguage;
  tone?: "casual" | "formal" | "playful" | "empathetic";
  systemPrompt: string;
  greeting?: string; // Native Deepgram greeting — spoken before waiting for user
  functions?: VoiceAgentFunction[];
  keyterms?: string[];
  conversationHistory?: Array<{ role: string; content: string }>;
  /**
   * When set, Deepgram's think block routes to our own endpoint instead of
   * calling the provider (OpenAI) directly. The endpoint must be OpenAI-
   * compatible (chat completions SSE format).
   *
   * This makes voice sessions as intelligent as text sessions — they use
   * the same ConductingSpecialist + domain skill bundle.
   */
  agentTurnEndpoint?: {
    url: string;
    sessionId: string;
    surveyId: string;
    internalKey: string;
  };
}): VoiceAgentSettings {
  const {
    language,
    tone = "casual",
    systemPrompt,
    greeting,
    functions,
    keyterms,
    conversationHistory,
    agentTurnEndpoint,
  } = options;

  const voiceModel = getVoiceModel(language, tone);

  const thinkBlock: VoiceAgentSettings["agent"]["think"] = {
    provider: {
      type: "open_ai",
      model: VOICE_AGENT_THINK_MODEL,
    },
    prompt: `${systemPrompt}\n\nRespond to the user in the language they are speaking to you in. If the user speaks Spanish, reply in natural Spanish. Match the language of each user message independently to provide seamless multilingual support.`,
    ...(functions && functions.length > 0
      ? {
          functions: functions.map((fn) => {
            const functionConfig = { ...fn };
            delete functionConfig.client_side;
            return functionConfig;
          }),
        }
      : {}),
  };

  // Wire up our own endpoint when provided
  if (agentTurnEndpoint) {
    thinkBlock.endpoint = {
      url: agentTurnEndpoint.url,
      headers: {
        "x-internal-key": agentTurnEndpoint.internalKey,
        "x-session-id": agentTurnEndpoint.sessionId,
        "x-survey-id": agentTurnEndpoint.surveyId,
      },
    };
  }

  return {
    flags: {
      history: true,
    },
    audio: {
      // Input: 16000 Hz linear16 — matches our AudioWorklet which forces 16kHz context
      input: { encoding: "linear16", sample_rate: 16000 },
      // Output: 24000 Hz linear16 — Deepgram's native TTS sample rate
      output: { encoding: "linear16", sample_rate: 24000, container: "none" },
    },
    agent: {
      listen: {
        provider: {
          type: "deepgram",
          model: "nova-3",
          version: "v1",
          language: "multi",
          smart_format: true,
          endpointing: 500, // Wait 500ms of silence before endpointing user speech (300ms was too aggressive — caused fragmented transcriptions)
          ...(keyterms && keyterms.length > 0 ? { keyterms } : {}),
        },
      },
      think: thinkBlock,
      speak: {
        provider: {
          type: "deepgram",
          model: voiceModel,
        },
      },
      // Set greeting so Deepgram speaks first — no InjectAgentMessage needed
      ...(greeting ? { greeting } : {}),
      ...(conversationHistory && conversationHistory.length > 0
        ? {
            context: {
              messages: conversationHistory.map((m) => ({
                role: (m.role === "user" ? "user" : "assistant") as
                  | "user"
                  | "assistant",
                content: m.content,
              })),
            },
          }
        : {}),
    },
  };
}

import { readFile } from "node:fs/promises";
import path from "node:path";
import { z } from "zod";

import {
  buildRefinementAssistantResponse,
  compilePlaybookAuthorInput,
} from "@/lib/education/playbook-workflow";
import {
  playbookAuthorInputSchema,
  type PlaybookAuthorInput,
} from "@/lib/education/playbooks";
import { researchBriefSchema, type ResearchBrief } from "@/lib/education/types";

type PlaybookEvalCase = {
  id: string;
  description: string;
  input: PlaybookAuthorInput;
  expected: {
    status: string;
    requiresClarification?: boolean;
    blockedReasonsCount?: number;
    minBlockedReasons?: number;
    minClarificationQuestions?: number;
    minUsefulnessScore?: number;
    minSpecificityScore?: number;
    minDerivedMetrics?: number;
    mustMentionOneOf?: string[];
  };
};

type RefinementEvalCase = {
  id: string;
  description: string;
  input: {
    creatorMessage: string;
    surveyTitle: string;
    currentPersonalityLabel: string;
    playbookSummaries: string[];
    latestSampleTranscript: string;
    brief: Partial<ResearchBrief>;
  };
  expected: {
    allowedProposalTypes?: string[];
    disallowedProposalTypes?: string[];
    maxProposalCount?: number;
    replyShouldAskClarifyingQuestion?: boolean;
  };
};

const playbookEvalCaseSchema = z.object({
  id: z.string(),
  description: z.string(),
  input: playbookAuthorInputSchema,
  expected: z.object({
    status: z.string(),
    requiresClarification: z.boolean().optional(),
    blockedReasonsCount: z.number().optional(),
    minBlockedReasons: z.number().optional(),
    minClarificationQuestions: z.number().optional(),
    minUsefulnessScore: z.number().optional(),
    minSpecificityScore: z.number().optional(),
    minDerivedMetrics: z.number().optional(),
    mustMentionOneOf: z.array(z.string()).optional(),
