async function loadJson<T>(
  filePath: string,
  parser: (value: unknown) => T,
): Promise<T> {
  const raw = await readFile(filePath, "utf8");
  return parser(JSON.parse(raw));
}

function assert(condition: unknown, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

async function runPlaybookEvals(cases: PlaybookEvalCase[]) {
  for (const testCase of cases) {
    const result = await compilePlaybookAuthorInput(testCase.input);
    assert(result.status === testCase.expected.status, `[${testCase.id}] expected status ${testCase.expected.status}, got ${result.status}`);

    if (typeof testCase.expected.requiresClarification === "boolean") {
      const actual = result.interpretation.clarificationQuestions.length > 0;
      assert(actual === testCase.expected.requiresClarification, `[${testCase.id}] clarification expectation mismatch`);
    }

    if (typeof testCase.expected.blockedReasonsCount === "number") {
      assert(
        result.interpretation.blockedReasons.length === testCase.expected.blockedReasonsCount,
        `[${testCase.id}] expected blocked reason count ${testCase.expected.blockedReasonsCount}, got ${result.interpretation.blockedReasons.length}`,
      );
    }

    if (typeof testCase.expected.minBlockedReasons === "number") {
      assert(
        result.interpretation.blockedReasons.length >= testCase.expected.minBlockedReasons,
        `[${testCase.id}] expected at least ${testCase.expected.minBlockedReasons} blocked reasons`,
      );
    }

    if (typeof testCase.expected.minClarificationQuestions === "number") {
      assert(
        result.interpretation.clarificationQuestions.length >= testCase.expected.minClarificationQuestions,
        `[${testCase.id}] expected at least ${testCase.expected.minClarificationQuestions} clarification questions`,
      );
    }

    if (typeof testCase.expected.minUsefulnessScore === "number") {
      assert(
        result.interpretation.usefulnessScore >= testCase.expected.minUsefulnessScore,
        `[${testCase.id}] usefulness score below threshold`,
      );
    }

    if (typeof testCase.expected.minSpecificityScore === "number") {
      assert(
        result.interpretation.specificityScore >= testCase.expected.minSpecificityScore,
        `[${testCase.id}] specificity score below threshold`,
      );
    }

    if (typeof testCase.expected.minDerivedMetrics === "number") {
      assert(
        result.interpretation.derivedMetrics.length >= testCase.expected.minDerivedMetrics,
        `[${testCase.id}] expected at least ${testCase.expected.minDerivedMetrics} derived metrics`,
      );
    }

    if (testCase.expected.mustMentionOneOf?.length) {
      const haystack = [
        result.interpretation.summary,
        ...result.interpretation.styleDirectives,
        ...result.preview.interpretedEffect,
      ]
        .join(" ")
        .toLowerCase();
      assert(
        testCase.expected.mustMentionOneOf.some((item) => haystack.includes(item.toLowerCase())),
        `[${testCase.id}] expected interpretation to mention one of: ${testCase.expected.mustMentionOneOf.join(", ")}`,
      );
    }
  }
}

async function runRefinementEvals(cases: RefinementEvalCase[]) {
  for (const testCase of cases) {
    const result = await buildRefinementAssistantResponse({
      ...testCase.input,
      brief: buildBrief(testCase.input.brief),
    });
    const types = result.proposals.map((proposal) => proposal.type);

    if (typeof testCase.expected.maxProposalCount === "number") {
      assert(
        result.proposals.length <= testCase.expected.maxProposalCount,
        `[${testCase.id}] expected at most ${testCase.expected.maxProposalCount} proposals, got ${result.proposals.length}`,
      );
    }

    const proposalTypes = new Set(types);

    for (const allowed of testCase.expected.allowedProposalTypes ?? []) {
      assert((proposalTypes as Set<string>).has(allowed), `[${testCase.id}] expected proposal type ${allowed}`);
    }

    for (const disallowed of testCase.expected.disallowedProposalTypes ?? []) {
      assert(!(proposalTypes as Set<string>).has(disallowed), `[${testCase.id}] did not expect proposal type ${disallowed}`);
    }

    if (testCase.expected.replyShouldAskClarifyingQuestion) {
      const reply = result.reply.toLowerCase();
      assert(
        reply.includes("?") || reply.includes("clarify") || reply.includes("do you mean"),
        `[${testCase.id}] expected a clarifying reply`,
      );
    }
  }
}

async function main() {
  const baseDir = path.join(process.cwd(), "evals", "creator-playbooks");
  const playbookCases = await loadJson(
    path.join(baseDir, "playbook-interpretation.json"),
    (value) => z.array(playbookEvalCaseSchema).parse(value),
  );
  const refinementCases = await loadJson(
    path.join(baseDir, "refinement-proposals.json"),
    (value) => z.array(refinementEvalCaseSchema).parse(value),
  );

  await runPlaybookEvals(playbookCases);
  await runRefinementEvals(refinementCases);

}

main().catch((error) => {
  process.exit(1);
});

import { WebSocket } from "ws";
import {
  checkMessageAllowed,
  checkAudioChunkAllowed,
} from "../middleware/rate-limit";
import {
  createVoiceAgentConnection,
  type VoiceAgentSettings,
  type ConversationTextEvent,
  type FunctionCallRequestEvent,
  type SupportedLanguage,
  type VoiceAgentConnection,
} from "@/lib/voice/voice-agent-provider";
import { logUsage } from "@/lib/billing/logger";

// Configuration constants
const IDLE_TIMEOUT_MS = 5 * 60 * 1000;
const IDLE_WARNING_MS = 30 * 1000;
const VAD_INTERRUPT_COOLDOWN_MS = 2500; // Defensive echo guard in case the client leaks agent audio back after playback starts.

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function getErrorCode(value: unknown): string | undefined {
  return isRecord(value) && typeof value.code === "string"
    ? value.code
    : undefined;
}

function normalizeErrorPayload(value: unknown): string | Record<string, unknown> {
  if (typeof value === "string") {
    return value;
  }

  if (isRecord(value)) {
    return value;
  }

  if (value instanceof Error) {
    return { message: value.message };
  }

  return { message: "Unknown error" };
}

/**
 * Base handler for voice sessions using the configured voice-agent provider.
 *
 * Replaces the old BaseVoiceHandler which manually orchestrated STT/LLM/TTS.
 * This handler acts as a proxy: browser audio → Deepgram Voice Agent → browser.
 * It intercepts ConversationText events for persistence and tool execution.
 */
export abstract class BaseVoiceAgentHandler {
  protected ws: WebSocket;
  protected userId?: string;
  protected identifier: string;
  protected isActive: boolean = true;
  protected initialDirective: string | null = null;

  // Attribution for billing
  public surveyId: string | null | undefined;
  protected organizationId: string | null | undefined;

  // Voice Agent connection
  protected voiceAgent: VoiceAgentConnection | null = null;

  // Idle timeout state
  protected idleTimeout: NodeJS.Timeout | null = null;
  protected idleWarningTimeout: NodeJS.Timeout | null = null;
  protected lastActivityTime: number = Date.now();
  protected lastAgentSpeechStartTime: number = 0;

  // Duration tracking
  protected activeDurationMs: number = 0;
  protected lastInteractionEndTime: number = Date.now();
  protected readonly MAX_SILENCE_GAP_MS = 30 * 1000;

  constructor(ws: WebSocket, identifier: string, userId?: string) {
    this.ws = ws;
    this.identifier = identifier;
    this.userId = userId;

    this.setupBrowserConnectionHandlers();
    this.setupBrowserMessageHandlers();
  }

  public getSocket(): WebSocket {
    return this.ws;
  }

  // ── Abstract Methods ─────────────────────────────────────────────────────

  /** Initialize the handler (load data, create voice agent, etc.) */
  abstract initialize(): Promise<void>;

  /** Get the language for this session */
  protected abstract getLanguage(): SupportedLanguage;

  /** Build the Voice Agent settings for this session (subclass provides greeting in settings) */
  protected abstract getVoiceAgentSettings(): Promise<VoiceAgentSettings>;

  /** Handle conversation text events (user or agent transcript) */
  protected abstract onConversationText(
    event: ConversationTextEvent,
  ): Promise<void>;

  /** Handle function call requests from the agent */
  protected abstract onFunctionCall(
    event: FunctionCallRequestEvent,
  ): Promise<void>;

  /** Handle control messages from the browser (subclass-specific) */
  protected abstract handleControlMessage(
    message: Record<string, unknown>,
  ): Promise<void>;

  /** Get initial user input to trigger proactively (AI speaks first) */
  protected abstract getInitialUserInput(): string | null;

  /** Check if this is a brand new session (no messages yet) */
  protected abstract isNewSession(): boolean;

  // ── Voice Agent Management ─────────────────────────────────────────────

  /**
   * Create and connect the configured voice agent
   */
  protected async connectVoiceAgent(): Promise<void> {
    const settings = await this.getVoiceAgentSettings();
    this.voiceAgent = createVoiceAgentConnection(settings);

    // Set up Voice Agent event handlers
    this.voiceAgent.on("audio", (audioData: Buffer) => {
      // Relay agent audio to browser
      if (this.ws.readyState === WebSocket.OPEN) {
        this.ws.send(audioData);
      }
    });

    this.voiceAgent.on(
      "conversationText",
      async (event: ConversationTextEvent) => {
        this.resetIdleTimeout();

        // Chain of Trust: Filter out internal directives
        if (event.role === "user" && event.content === this.initialDirective) {
          return;
        }

        // Send to browser for UI display
        this.send({
          type: "conversation_text",
          role: event.role,
          content: event.content,
        });

        // Let subclass handle persistence, extraction, etc.
        try {
          await this.onConversationText(event);
        } catch (error) {
        }
      },
    );

    this.voiceAgent.on(
      "functionCallRequest",
      async (event: FunctionCallRequestEvent) => {
        try {
          await this.onFunctionCall(event);
        } catch (error) {
          // Respond with error so the agent can continue
          this.voiceAgent?.sendFunctionCallResponse(
            event.function_call_id,
            event.function_name,
            JSON.stringify({ error: "Function execution failed" }),
          );
        }
      },
    );

    this.voiceAgent.on("userStartedSpeaking", () => {
      const now = Date.now();
      const timeSinceAgentStarted = now - this.lastAgentSpeechStartTime;

      if (timeSinceAgentStarted < VAD_INTERRUPT_COOLDOWN_MS) {
        return;
      }

      this.resetIdleTimeout();
      // Track active duration
      const gap = now - this.lastInteractionEndTime;
      if (gap > 0) {
        this.activeDurationMs += Math.min(gap, this.MAX_SILENCE_GAP_MS);
      }
      // Send interrupt to browser to stop playback
      this.send({ type: "interrupt" });
      this.send({ type: "speech_start" });
    });

    this.voiceAgent.on("agentThinking", () => {
      this.send({ type: "agent_thinking" });
    });

    this.voiceAgent.on("agentStartedSpeaking", () => {
      this.lastAgentSpeechStartTime = Date.now();
      this.send({ type: "agent_started_speaking" });
    });

    this.voiceAgent.on("agentAudioDone", () => {
      this.lastInteractionEndTime = Date.now();
      this.send({ type: "agent_audio_done" });
    });

    this.voiceAgent.on("settingsApplied", () => {
      this.send({
        type: "agent_ready",
        awaitingAgentIntro: this.isNewSession() || this.getInitialUserInput() !== null,
      });

      // Proactively trigger initial greeting if it's a new session
      if (this.isNewSession()) {
        const initialInput = this.getInitialUserInput();
        if (initialInput) {
          this.initialDirective = initialInput;
          // We use InjectUserMessage so the AI "hears" the instruction and responds naturally
          // based on its system prompt (e.g. greeting the user).
          // sendInjectAgentMessage would cause the AI to literally say the directive.
          this.voiceAgent?.sendInjectUserMessage(initialInput);
        }
      }
    });

    this.voiceAgent.on("error", (error: unknown) => {
      this.sendError(error, getErrorCode(error));
    });

    /*
    this.voiceAgent.on("close", () => {
    });
    */

    // Connect
    /*
    */
    await this.voiceAgent.connect();
    /*
    */
  }

  /**
   * Reconnect the Voice Agent with new settings (e.g., language change)
   */
  protected async reconnectVoiceAgent(): Promise<void> {
    if (this.voiceAgent) {
      this.voiceAgent.close();
      this.voiceAgent = null;
    }
    // Reset audio state so we inject again on new connection
    await this.connectVoiceAgent();
  }

  // ── Browser Connection Handlers ────────────────────────────────────────

  private setupBrowserConnectionHandlers(): void {
    this.ws.on("close", async () => {
      await this.cleanup();
    });

    this.ws.on("error", (error) => {
      this.cleanup();
    });
  }

  private setupBrowserMessageHandlers(): void {
    this.ws.on("message", async (data: Buffer, isBinary: boolean) => {
      //       if (!this.isActive) return;

      this.resetIdleTimeout();

      if (!isBinary) {
        try {
          // Try to parse as JSON (control messages)
          const strData = data.toString();

          const message = JSON.parse(strData);
          if (!isRecord(message) || typeof message.type !== "string") {
            return;
          }
          /*
          if (message.type !== "ping") {
          }
          */

          // Handle audio configuration (legacy — ignored since Voice Agent handles this)
          if (message.type === "audio_config") {
            return;
          }

          // Handle ping
          if (message.type === "ping") {
            this.send({ type: "pong" });
            return;
          }

          // Rate limit checks for JSON messages
          const messageCheck = await checkMessageAllowed(this.identifier);
          if (!messageCheck.allowed) {
            this.send({
              type: "rate_limit",
              error: messageCheck.reason,
              retryAfter: messageCheck.retryAfter,
            });
            return;
          }

          await this.handleControlMessage(message);
        } catch (error) {
        }
      } else {
        // Treat as audio data from browser
        await this.handleBrowserAudio(data);
      }
    });
  }

  /**
   * Handle audio data from browser — relay to Voice Agent
   */
  private async handleBrowserAudio(audioData: Buffer): Promise<void> {
    // Check audio chunk rate limit
    const audioCheck = await checkAudioChunkAllowed(this.identifier);
    if (!audioCheck.allowed) {
      return;
    }

    if (!audioData || audioData.length === 0) return;

    // Relay to Voice Agent
    if (this.voiceAgent?.connected) {
      this.voiceAgent.sendAudio(audioData);
    }
  }

  // ── Helpers ────────────────────────────────────────────────────────────

  public send(data: Record<string, unknown> | Buffer): void {
    if (this.ws.readyState === WebSocket.OPEN) {
      if (!Buffer.isBuffer(data)) {
        const dataType =
          isRecord(data) && typeof data.type === "string" ? data.type : undefined;
        if (dataType !== "audio" && dataType !== "pong") {
          if (dataType === "error") {
          }
        }
      }
      try {
        this.ws.send(Buffer.isBuffer(data) ? data : JSON.stringify(data));
      } catch (err) {
      }
    } else {
      const dataType =
        !Buffer.isBuffer(data) &&
        typeof data === "object" &&
        data !== null &&
        "type" in data &&
        typeof data.type === "string"
          ? data.type
          : "unknown";
    }
  }

  protected sendError(errorPayload: unknown, code?: string): void {
    this.send({
      type: "error",
      error: normalizeErrorPayload(errorPayload),
      code,
    });
  }

  // ── Idle Timeout ───────────────────────────────────────────────────────

  protected resetIdleTimeout(): void {
    this.lastActivityTime = Date.now();

    if (this.idleTimeout) clearTimeout(this.idleTimeout);
    if (this.idleWarningTimeout) clearTimeout(this.idleWarningTimeout);

    this.idleWarningTimeout = setTimeout(() => {
      this.send({
        type: "idle_warning",
        message: "Session will close in 30 seconds due to inactivity.",
        secondsRemaining: 30,
      });
    }, IDLE_TIMEOUT_MS - IDLE_WARNING_MS);

    this.idleTimeout = setTimeout(() => {
      this.send({ type: "idle_timeout" });
      this.cleanup();
      this.ws.close(1000, "Idle timeout");
    }, IDLE_TIMEOUT_MS);
  }

  // ── Cleanup ────────────────────────────────────────────────────────────

  protected async cleanup(): Promise<void> {
    if (!this.isActive) return;
    this.isActive = false;

    // Close Voice Agent connection
    if (this.voiceAgent) {
      this.voiceAgent.close();
      this.voiceAgent = null;

      // Log voice session usage
      if (this.activeDurationMs > 0) {
        logUsage({
          userId: this.userId,
          organizationId: this.organizationId || undefined,
          surveyId: this.surveyId || undefined,
          type: "voice_session",
          provider: "deepgram",
          modelName: "voice-agent-v1",
          durationMs: this.activeDurationMs,
        });
      }
    }

    // Clear timeouts
    if (this.idleTimeout) clearTimeout(this.idleTimeout);
    if (this.idleWarningTimeout) clearTimeout(this.idleWarningTimeout);

    // Subclasses should override and call super.cleanup()
  }
}

import { WebSocket } from "ws";
import { AuthenticatedConnection } from "../middleware/auth";
import { getRedisClient } from "@/lib/redis";
import { getDb } from "@/db";
import { users } from "@/db/schema/auth";
import { eq } from "drizzle-orm";

/**
 * WebSocket Handler for Real-Time Presence
 * 
 * Tracks which users are currently active in a workspace or survey.
 * Broadcasts presence updates to all members of the same workspace/survey.
 */

export interface PresenceMessage {
  type: "presence_update" | "user_joined" | "user_left" | "error" | "connected";
  workspaceId: string;
  surveyId?: string;
  users?: Array<{
    userId: string;
    name: string;
    image?: string | null;
    lastActive: number;
  }>;
  user?: {
    userId: string;
    name: string;
    image?: string | null;
  };
}

export class PresenceHandler {
  private ws: WebSocket;
  private userId: string;
  private memberId: string;
  private workspaceId: string;
  public surveyId?: string;
  private isActive: boolean = true;
  private hasLeft = false;
  private userName = "User";
  private userImage: string | null = null;
  private redisClient = getRedisClient();

  constructor(
    connection: AuthenticatedConnection,
    memberId: string,
    workspaceId: string,
    surveyId?: string
  ) {
    this.ws = connection.ws;
    this.userId = connection.userId;
    this.memberId = memberId;
    this.workspaceId = workspaceId;
    this.surveyId = surveyId;

    this.setupEventHandlers();
  }

  public getSocket(): WebSocket {
    return this.ws;
  }

  async initialize(): Promise<void> {
    try {
      // 1. Fetch user data
      const [userData] = await getDb()
        .select({ name: users.name, image: users.image })
        .from(users)
        .where(eq(users.id, this.userId));

      this.userName = userData?.name || "User";
      this.userImage = userData?.image || null;

      // 2. Join the presence set in Redis with a connection-scoped member id.
      // This preserves presence across multiple tabs from the same user.
      await this.updatePresence();

      // 3. Broadcast initial presence after the connection is registered.
      const activeUsers = await this.getActiveUsers();
      await this.broadcast({
        type: "presence_update",
        workspaceId: this.workspaceId,
        surveyId: this.surveyId,
        users: activeUsers,
      });

      await this.broadcast({
        type: "user_joined",
        workspaceId: this.workspaceId,
        surveyId: this.surveyId,
        user: {
          userId: this.userId,
          name: this.userName,
          image: this.userImage,
        }
      });

      // 4. Send initial state to the user
      this.send({
        type: "connected",
        workspaceId: this.workspaceId,
        surveyId: this.surveyId,
        users: activeUsers
      });

    } catch (error) {
      this.ws.close(1011, "Internal server error");
    }
  }

  private async updatePresence(): Promise<void> {
    const key = this.getPresenceKey();
    const score = Date.now();
    const memberMetadataKey = this.getPresenceMemberMetadataKey();

    await this.redisClient.hset(
      memberMetadataKey,
      "userId", this.userId,
      "name", this.userName,
      "image", this.userImage || "",
      "lastActive", String(score),
    );
    await this.redisClient.expire(memberMetadataKey, 300);
    await this.redisClient.zadd(key, score, this.memberId);
    // Set expiry for the presence set
    await this.redisClient.expire(key, 300); // 5 minutes
  }

  private async getActiveUsers(): Promise<PresenceMessage["users"]> {
    const key = this.getPresenceKey();
    const now = Date.now();
    const threshold = now - 60000; // 1 minute inactivity

    // Clean up stale users
    await this.redisClient.zremrangebyscore(key, 0, threshold);

    const memberIds = await this.redisClient.zrange(key, 0, -1);
    const activeUsers = new Map<string, NonNullable<PresenceMessage["users"]>[number]>();

    // Fetch metadata for all active connections, then collapse to unique users.
    await Promise.all(
      memberIds.map(async (memberId) => {
        const meta = await this.redisClient.hgetall(
          this.getPresenceMemberMetadataKey(memberId),
        );
        const userId = meta.userId;
        if (!userId) {
          return;
        }

        const candidate = {
          userId,
          name: meta.name || `User ${userId.substring(0, 4)}`,
          image: meta.image || null,
          lastActive:
            meta.lastActive && !Number.isNaN(Number(meta.lastActive))
              ? Number(meta.lastActive)
              : now,
        };

        const existing = activeUsers.get(userId);
        if (!existing || candidate.lastActive >= existing.lastActive) {
          activeUsers.set(userId, candidate);
        }
      }),
    );

    return Array.from(activeUsers.values());
  }

  private getPresenceKey(): string {
    return `presence:${this.workspaceId}${this.surveyId ? `:${this.surveyId}` : ""}`;
  }

  private getPresenceMemberMetadataKey(memberId: string = this.memberId): string {
    return `presence:member:${memberId}`;
  }

  private getPresenceChannel(): string {
    return `pubsub:presence:${this.workspaceId}${this.surveyId ? `:${this.surveyId}` : ""}`;
  }

  public matchesScope(workspaceId: string, surveyId?: string): boolean {
    return this.workspaceId === workspaceId && this.surveyId === surveyId;
  }

  private setupEventHandlers(): void {
    this.ws.on("close", async () => {
      this.isActive = false;
      await this.handleLeave();
    });

    this.ws.on("error", () => {
      this.isActive = false;
    });

    this.ws.on("message", async (raw) => {
      try {
        const data = JSON.parse(String(raw));
        if (
          typeof data === "object" &&
          data !== null &&
          "type" in data &&
          data.type === "heartbeat"
        ) {
          await this.updatePresence();
        }
      } catch {
        // Ignore malformed presence messages from the client.
      }
    });

    // Keepalive/Heartbeat
    this.ws.on("pong", async () => {
      await this.updatePresence();
    });
  }

  private async handleLeave(): Promise<void> {
    if (this.hasLeft) {
      return;
    }
    this.hasLeft = true;

    const key = this.getPresenceKey();
    await this.redisClient.zrem(key, this.memberId);
    await this.redisClient.del(this.getPresenceMemberMetadataKey());

    const activeUsers = await this.getActiveUsers();
    await this.broadcast({
      type: "presence_update",
      workspaceId: this.workspaceId,
      surveyId: this.surveyId,
      users: activeUsers,
    });
    await this.broadcast({
      type: "user_left",
      workspaceId: this.workspaceId,
      surveyId: this.surveyId,
      user: {
        userId: this.userId,
        name: this.userName,
        image: this.userImage,
      }
    });
  }

  private async broadcast(message: PresenceMessage): Promise<void> {
    await this.redisClient.publish(this.getPresenceChannel(), JSON.stringify(message));
  }

  public send(message: PresenceMessage): void {
    if (this.isActive && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(message));
    }
  }

  async cleanup(): Promise<void> {
    this.isActive = false;
    await this.handleLeave();
    if (this.ws.readyState === WebSocket.OPEN) {
      this.ws.close();
    }
  }
}

