export class SurveyResponseVoiceHandler extends BaseVoiceAgentHandler {
  private state: ResponseState;
  private participantId: string;
  private sessionStartTime = Date.now();
  private cleanupStarted = false;
  private ownerId: string | null = null;

  constructor(
    ws: WebSocket,
    surveyId: string,
    conversationId: string,
    identifier: string,
    language?: string,
  ) {
    super(ws, identifier);

    this.participantId = "";
    this.state = {
      surveyId,
      conversationId,
      voiceSessionId: nanoid(),
      messages: [],
      survey: null,
      language: normalizeVoiceLocale(language),
      brief: null,
      coveragePlan: null,
      sessionId: null,
      sessionState: null,
    };
  }

  async initialize(): Promise<void> {
    try {
      const survey = await getDb()
        .select()
        .from(surveys)
        .where(eq(surveys.shareableLink, this.state.surveyId))
        .then((rows) => rows[0]);

      if (!survey) {
        this.sendError("Survey not found");
        this.ws.close();
        return;
      }

      if (survey.status !== "active") {
        this.sendError("Survey is not active");
        this.ws.close();
        return;
      }

      const [briefRow, planRow] = await Promise.all([
        getResearchBrief(survey.id),
        getActiveCoveragePlan(survey.id),
      ]);
      if (!briefRow || !planRow) {
        this.sendError("This survey is not ready for education interviews yet.");
        this.ws.close();
        return;
      }

      this.state.survey = survey;
      this.state.brief = briefRow.brief;
      this.state.coveragePlan = planRow.plan;
      this.surveyId = survey.id;
      this.organizationId = survey.organizationId;
      this.ownerId = survey.userId;

      if (!this.state.language || this.state.language === "en") {
        this.state.language = normalizeVoiceLocale(survey.language);
      }

      const conversation = await getDb()
        .select()
        .from(surveyConversations)
        .where(eq(surveyConversations.id, this.state.conversationId!))
        .then((rows) => rows[0]);

      if (!conversation || conversation.surveyId !== survey.id) {
        this.sendError("Conversation not found");
        this.ws.close();
        return;
      }

      this.participantId = conversation.participantId || nanoid(8);
      this.state.messages = getUsableRespondentMessages(
        toVisibleConversationMessages(
          toPersistedUIChatMessages(
            Array.isArray(conversation.rawConversation)
              ? conversation.rawConversation
              : [],
            ["user", "assistant"],
          ),
        ),
        survey.isVoice,
      );
      if (!conversation.participantId) {
        await getDb()
          .update(surveyConversations)
          .set({ participantId: this.participantId, updatedAt: new Date() })
          .where(eq(surveyConversations.id, conversation.id));
      }

      await getDb().insert(voiceSessions).values({
        id: this.state.voiceSessionId,
        surveyId: survey.id,
        conversationId: conversation.id,
        sessionType: "survey_response",
        status: "active",
        startedAt: new Date(),
      });

      let sessionRow = await getSessionBySourceId(conversation.id);
      if (!sessionRow) {
        sessionRow = await ensureSession({
          surveyId: survey.id,
          sessionType: "live",
          sourceConversationId: conversation.id,
          language: this.state.language,
          respondentId: this.participantId,
          initialState: createInitialSessionState({
            surveyId: survey.id,
            sessionId: nanoid(),
            sessionType: "live",
            language: this.state.language,
            coveragePlan: planRow.plan,
          }),
        });
      }

      this.state.sessionId = sessionRow.id;
      this.state.sessionState = sessionRow.sessionState;
      this.resetIdleTimeout();

      this.send({
        type: "ready",
        voiceSessionId: this.state.voiceSessionId,
        conversationId: conversation.id,
        language: this.state.language,
      });

      await this.connectVoiceAgent();
    } catch (error) {
      this.sendError("Failed to initialize voice session");
      this.ws.close();
    }
  }

  protected getLanguage(): SupportedLanguage {
    return this.state.language;
  }

  protected getInitialUserInput(): string | null {
    if (this.state.messages.length === 0) {
      return null;
    }

    const lastMessage = this.state.messages[this.state.messages.length - 1];
    if (lastMessage.role === "user") {
      return "The participant is resuming the interview. Briefly welcome them back, acknowledge their last answer, and continue naturally.";
    }

    return null;
  }

  protected isNewSession(): boolean {
    return this.state.messages.length === 0;
  }

  protected async getVoiceAgentSettings(): Promise<VoiceAgentSettings> {
    if (!this.state.survey || !this.state.brief || !this.state.coveragePlan || !this.state.sessionState) {
      throw new Error("Survey response voice state is incomplete");
    }

    const [activeLiveProfile, sampleFallbackProfile, runtimeLayers] = await Promise.all([
      getActiveConductingProfile(this.state.survey!.id, "live"),
      getActiveConductingProfile(this.state.survey!.id, "sample"),
      getConductingRuntimeLayers({
        surveyId: this.state.survey!.id,
        organizationId: this.state.survey!.organizationId,
        mode: "live",
      }),
    ]);
    const systemPrompt = buildConductingSystemPrompt({
      brief: this.state.brief,
      coveragePlan: this.state.coveragePlan,
      sessionState: this.state.sessionState,
      sessionType: "live",
      conductingProfile: activeLiveProfile?.profile ?? sampleFallbackProfile?.profile ?? null,
      playbookContext: runtimeLayers.playbookContext,
      personalityContext: runtimeLayers.personalityContext,
      toolContext: {
        canFinishSurvey: true,
        canShowMedia: false,
      },
    });

    const tone = (this.state.survey.tone || "casual") as
      | "casual"
      | "formal"
      | "playful"
      | "empathetic";

    return buildVoiceAgentSettings({
      language: this.state.language,
      tone,
      systemPrompt,
      functions: buildRespondentVoiceFunctions(
        false,
      ),
      keyterms: buildVoiceAgentKeyterms({
        surveyTitle: this.state.survey.title,
        requiredQuestions: this.state.survey.requiredQuestions,
        media: [],
        brief: this.state.brief,
      }),
      greeting:
        this.state.messages.length === 0
          ? buildRespondentVoiceGreeting({
              language: this.state.language,
              surveyTitle: this.state.survey.title,
              brief: this.state.brief,
            })
          : undefined,
      conversationHistory:
        this.state.messages.length > 0
          ? this.state.messages.map((message) => ({
              role: message.role,
              content: message.content,
            }))
          : undefined,
    });
  }

  protected async onConversationText(event: ConversationTextEvent): Promise<void> {
    const now = new Date();
    const lastMessage = this.state.messages[this.state.messages.length - 1];

    if (
      lastMessage &&
      lastMessage.role === event.role &&
      now.getTime() - new Date(lastMessage.timestamp).getTime() < 3000
    ) {
      lastMessage.content += ` ${event.content}`;
      lastMessage.timestamp = now.toISOString();
    } else {
      this.state.messages.push({
        id: nanoid(),
        role: event.role,
        content: event.content,
        timestamp: now.toISOString(),
      });
    }

    if (!this.state.conversationId) return;

    if (event.role === "user" && this.state.survey) {
      const admission = await admitParticipantOnFirstUserTurn({
        surveyId: this.state.survey.id,
        conversationId: this.state.conversationId,
      });

      if (!admission.allowed) {
        this.send({
          type: "error",
          error: "Survey has reached participant limit",
        });
        this.ws.close(1008, "Survey has reached participant limit");
        return;
      }
    }

    await getDb()
      .update(surveyConversations)
      .set({
        rawConversation: this.state.messages,
        updatedAt: new Date(),
      })
      .where(eq(surveyConversations.id, this.state.conversationId));

    if (
      event.role !== "assistant" ||
      !this.state.sessionId ||
      !this.state.sessionState ||
      !this.state.brief ||
      !this.state.coveragePlan ||
      !hasUserTurn(this.state.messages)
    ) {
      return;
    }

    const { nextState } = await finalizeConductingTurn({
      surveyId: this.state.survey!.id,
      sessionId: this.state.sessionId,
      brief: this.state.brief,
      coveragePlan: this.state.coveragePlan,
      sessionState: this.state.sessionState,
      messages: this.state.messages.map(m => ({
        ...m,
        id: m.id || nanoid(),
        timestamp: m.timestamp || new Date().toISOString()
      })),
    });

    this.state.sessionState = nextState;
    await enqueueConversationInsights({
      conversationId: this.state.conversationId!,
      surveyId: this.state.survey!.id,
      userId: this.ownerId || this.state.survey!.userId,
    }).catch((error) => {
    });

    this.send({
      type: "progress",
      completionPercentage: Math.round(nextState.overallCoverage * 100),
      state: nextState.status,
      shouldWrapUp: nextState.status === "completed",
    });

    const [refreshedLiveProfile, refreshedSampleProfile, refreshedRuntimeLayers] = await Promise.all([
      getActiveConductingProfile(this.state.survey!.id, "live"),
      getActiveConductingProfile(this.state.survey!.id, "sample"),
      getConductingRuntimeLayers({
        surveyId: this.state.survey!.id,
        organizationId: this.state.survey!.organizationId,
        mode: "live",
      }),
    ]);
    const refreshedPrompt = buildConductingSystemPrompt({
      brief: this.state.brief,
      coveragePlan: this.state.coveragePlan,
      sessionState: nextState,
      sessionType: "live",
      conductingProfile: refreshedLiveProfile?.profile ?? refreshedSampleProfile?.profile ?? null,
      playbookContext: refreshedRuntimeLayers.playbookContext,
      personalityContext: refreshedRuntimeLayers.personalityContext,
    });
    this.voiceAgent?.updateThink({
      provider: { type: "open_ai", model: VOICE_AGENT_THINK_MODEL },
      prompt: `${refreshedPrompt}\n\nRespond in the language the participant is speaking.`,
      functions: buildRespondentVoiceFunctions(
        false,
      ),
    });

    if (nextState.status === "completed") {
      setTimeout(() => {
        this.send({ type: "survey_completed" });
        this.handleComplete();
      }, 1200);
    }
  }

  protected async onFunctionCall(event: FunctionCallRequestEvent): Promise<void> {
    switch (event.function_name) {
      case "finishSurvey": {
        if (!this.state.sessionState || !this.state.sessionId || !this.state.coveragePlan) {
          this.voiceAgent?.sendFunctionCallResponse(
            event.function_call_id,
            event.function_name,
            JSON.stringify({ error: "Session state not ready" }),
          );
          return;
        }

        const threshold = this.state.coveragePlan.completionRule.minimumRequiredNodeCoverage;
        if (
          this.state.sessionState.status !== "completed" &&
          this.state.sessionState.overallCoverage < threshold
        ) {
          this.voiceAgent?.sendFunctionCallResponse(
            event.function_call_id,
            event.function_name,
            JSON.stringify({
              error: "Interview coverage is not high enough to finish yet",
              currentCoverage: this.state.sessionState.overallCoverage,
              requiredCoverage: threshold,
            }),
          );
          return;
        }

        const completedState: SessionState =
          this.state.sessionState.status === "completed"
            ? this.state.sessionState
            : {
                ...this.state.sessionState,
                status: "completed",
                stopReason: "agent_finish_signal",
              };

        if (completedState !== this.state.sessionState) {
          await updateSessionState(this.state.sessionId, completedState);
          this.state.sessionState = completedState;
        }

        this.voiceAgent?.sendFunctionCallResponse(
          event.function_call_id,
          event.function_name,
          JSON.stringify({ success: true, message: "Survey marked as complete" }),
        );

        setTimeout(() => {
          this.send({ type: "survey_completed" });
          this.handleComplete();
        }, 500);
        return;
      }

      default:
        this.voiceAgent?.sendFunctionCallResponse(
          event.function_call_id,
          event.function_name,
          JSON.stringify({ error: `Unknown function: ${event.function_name}` }),
        );
    }
  }

  protected async handleControlMessage(
    message: Record<string, unknown>,
  ): Promise<void> {
    if (message.type === "complete") {
      await this.handleComplete();
    }
  }

  private async handleComplete(): Promise<void> {
    try {
      if (this.state.conversationId) {
        await getDb()
          .update(surveyConversations)
          .set({ completed: true, updatedAt: new Date() })
          .where(eq(surveyConversations.id, this.state.conversationId));

        try {
          await enqueueConversationInsights({
            conversationId: this.state.conversationId,
            surveyId: this.state.survey?.id || "",
            userId: this.ownerId || "",
          });
        } catch (error) {
        }
      }

      const sessionDurationMs = Date.now() - this.sessionStartTime;
      const durationMinutes = sessionDurationMs / 60000;
      const estimatedSttCost = durationMinutes * ESTIMATED_STT_COST_PER_MINUTE;
      const totalAssistantChars = this.state.messages
        .filter((message) => message.role === "assistant")
        .reduce((sum, message) => sum + message.content.length, 0);
      const estimatedTtsCost = totalAssistantChars * ESTIMATED_TTS_COST_PER_CHAR;
      const totalCost = estimatedSttCost + estimatedTtsCost;

      await getDb()
        .update(voiceSessions)
        .set({
          status: "completed",
          endedAt: new Date(),
          durationMs: sessionDurationMs,
          audioDurationMs: Math.round(this.activeDurationMs),
          totalCost: totalCost.toString(),
          sttCost: estimatedSttCost.toString(),
          ttsCost: estimatedTtsCost.toString(),
        })
        .where(eq(voiceSessions.id, this.state.voiceSessionId));

      if (this.state.conversationId) {
        await getDb()
          .update(surveyConversations)
          .set({
            durationMs: sessionDurationMs,
            activeDurationMs: Math.round(this.activeDurationMs),
          })
          .where(eq(surveyConversations.id, this.state.conversationId));
      }

      this.send({
        type: "completed",
        conversationId: this.state.conversationId,
      });
      this.ws.close();
    } catch (error) {
      this.send({ type: "error", error: "Failed to complete survey" });
    }
  }

  protected async cleanup(): Promise<void> {
    if (this.cleanupStarted) return;
    this.cleanupStarted = true;

    try {
      await super.cleanup();

      const sessionDurationMs = Date.now() - this.sessionStartTime;
      const [session] = await getDb()
        .select()
        .from(voiceSessions)
        .where(eq(voiceSessions.id, this.state.voiceSessionId));

      if (!session) return;

      const newStatus = session.status === "active" ? "abandoned" : session.status;
      const durationMinutes = sessionDurationMs / 60000;
      const estimatedSttCost = durationMinutes * ESTIMATED_STT_COST_PER_MINUTE;
      const totalAssistantChars = this.state.messages
        .filter((message) => message.role === "assistant")
        .reduce((sum, message) => sum + message.content.length, 0);
      const estimatedTtsCost = totalAssistantChars * ESTIMATED_TTS_COST_PER_CHAR;
      const totalCost = estimatedSttCost + estimatedTtsCost;

      await getDb()
        .update(voiceSessions)
        .set({
          status: newStatus,
          endedAt: new Date(),
          durationMs: sessionDurationMs,
          audioDurationMs: Math.round(this.activeDurationMs),
          totalCost: totalCost.toString(),
          sttCost: estimatedSttCost.toString(),
          ttsCost: estimatedTtsCost.toString(),
        })
        .where(eq(voiceSessions.id, this.state.voiceSessionId));

      if (this.state.conversationId) {
        await getDb()
          .update(surveyConversations)
          .set({
            durationMs: sessionDurationMs,
            activeDurationMs: Math.round(this.activeDurationMs),
          })
          .where(eq(surveyConversations.id, this.state.conversationId));
      }
    } catch (error) {
    }
  }
}

import { createServer, IncomingMessage } from "http";
import { WebSocketServer, WebSocket } from "ws";
import { parse } from "url";
import { loadEnvConfig } from "@next/env";

const projectDir = process.cwd();
loadEnvConfig(projectDir);

import * as Sentry from "@sentry/node";
import { scrubSentryEvent } from "@/lib/privacy/sentry";

// Initialize Sentry for the standalone Node.js Project
Sentry.init({
  dsn: process.env.SENTRY_DSN,
  tracesSampleRate: 1.0,
  environment: process.env.NODE_ENV || "development",
  serverName: "websocket-server",
  sendDefaultPii: false,
  beforeSend(event) {
    return scrubSentryEvent(event);
  },
});


import { env } from "@/lib/env";
import {
  authenticateWebSocket,
  verifyPublicAccess,
  sendAuthError,
} from "./middleware/auth";
import {
  checkConnectionAllowed,
  releaseConnection,
  getClientIdentifier,
} from "./middleware/rate-limit";
import { SurveyResponseVoiceHandler } from "./handlers/survey-response-voice";
import { SampleSurveyVoiceHandler } from "./handlers/sample-survey-voice";
import { PresenceHandler } from "./handlers/presence";
import { getRedisSubscriber } from "@/lib/redis";
import {
  getSurveyPermissionContext,
  isWorkspaceMember,
} from "@/lib/workspace-access";

/**
 * WebSocket Server for Voice-Enabled Surveys
 * Handles real-time voice interactions for survey creation and responses
 */

const PORT = parseInt(env.WEBSOCKET_PORT);

// Track active connections
const activeConnections = new Map<
  string,
  {
    handler:
    | SurveyResponseVoiceHandler
    | SampleSurveyVoiceHandler
    | PresenceHandler;
    userId?: string;
    createdAt: number; // Track when connection was created for cleanup
  }
>();

// Track each presence socket independently so multiple tabs from the same user
// do not overwrite each other.
const presenceConnections = new Map<string, PresenceHandler>();
const realtimeConnections = new Map<
  string,
  {
    ws: WebSocket;
    userId: string;
    subscriptions: Set<string>;
  }
>();
const realtimeChannelSubscriptions = new Map<string, Set<string>>();

// Redis pub/sub subscriber for presence and realtime events
let redisSubscriber: ReturnType<typeof getRedisSubscriber> | null = null;
let redisSubscriberReconnectAttempts = 0;
const MAX_REDIS_RECONNECT_ATTEMPTS = 10;
const REDIS_RECONNECT_DELAY_MS = 5000;

// Cleanup interval for stale connections
const CLEANUP_INTERVAL_MS = 60000; // Every minute
const MAX_CONNECTION_AGE_MS = 4 * 60 * 60 * 1000; // 4 hours max connection age

function getSingleQueryParam(value: string | string[] | undefined): string | undefined {
  return Array.isArray(value) ? value[0] : value;
}

function hasCleanupMethod(
  handler: object
): handler is { cleanup: () => Promise<void> } {
  const cleanup = Reflect.get(handler, "cleanup");
  return typeof cleanup === "function";
}

/**
 * Cleanup stale connections that may have leaked
 * This catches connections where the close event was missed
 */
function cleanupStaleConnections(): void {
  const now = Date.now();
  let cleanedCount = 0;

  for (const [connectionId, connection] of activeConnections) {
    try {
      // Check if WebSocket is closed by accessing private ws property
      const ws =
        connection.handler && "getSocket" in connection.handler
          ? connection.handler.getSocket()
          : null;

      const isClosed = ws && ws.readyState === WebSocket.CLOSED;
      const isTooOld = now - connection.createdAt > MAX_CONNECTION_AGE_MS;

      if (isClosed || isTooOld) {
        if (presenceConnections.has(connectionId)) {
          presenceConnections.delete(connectionId);
        }
        if (hasCleanupMethod(connection.handler)) {
          void connection.handler.cleanup().catch((error) => {
            console.error("[websocket] handler cleanup failed", {
              connectionId,
              message: error instanceof Error ? error.message : "Unknown error",
            });
          });
        }
        activeConnections.delete(connectionId);
        cleanedCount++;

      }
    } catch (error) {
      console.error("[websocket] stale connection cleanup failed", {
        connectionId,
        message: error instanceof Error ? error.message : "Unknown error",
      });
      // If we can't check the connection, remove it to be safe
      if (presenceConnections.has(connectionId)) {
        presenceConnections.delete(connectionId);
      }
      activeConnections.delete(connectionId);
      cleanedCount++;
    }
  }

  for (const [connectionId, connection] of realtimeConnections) {
    if (
      connection.ws.readyState === WebSocket.CLOSED ||
      connection.ws.readyState === WebSocket.CLOSING
    ) {
      realtimeConnections.delete(connectionId);
      for (const channel of connection.subscriptions) {
        realtimeChannelSubscriptions.get(channel)?.delete(connectionId);
        if (realtimeChannelSubscriptions.get(channel)?.size === 0) {
          realtimeChannelSubscriptions.delete(channel);
        }
      }
      cleanedCount++;
    }
  }

  if (cleanedCount > 0) {
  }
}

// Start periodic cleanup
const cleanupInterval = setInterval(
  cleanupStaleConnections,
  CLEANUP_INTERVAL_MS,
);

/**
 * Create HTTP server
 */
const server = createServer((req, res) => {
  // Health check endpoint
  if (req.url === "/health") {
    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(
      JSON.stringify({
        status: "ok",
        activeConnections: activeConnections.size,
        timestamp: new Date().toISOString(),
      }),
    );
    return;
  }

  res.writeHead(404);
  res.end("Not Found");
});

/**
 * Create WebSocket server
 */
const wss = new WebSocketServer({
  server,
  perMessageDeflate: {
    zlibDeflateOptions: {
      chunkSize: 1024,
      memLevel: 7,
      level: 3,
    },
    zlibInflateOptions: {
      chunkSize: 10 * 1024,
    },
    clientNoContextTakeover: true,
    serverNoContextTakeover: true,
    serverMaxWindowBits: 10,
    concurrencyLimit: 10,
    threshold: 1024,
  },
});

/**
 * Handle new WebSocket connections
 */
wss.on("connection", async (ws: WebSocket, req) => {
  const url = parse(req.url || "", true);
  const pathname = url.pathname || "";


  try {
    // Route based on pathname
    if (pathname === "/voice/survey-response") {
      await handleSurveyResponse(ws, req);
    } else if (pathname === "/voice/sample-conversation") {
      await handleSampleConversation(ws, req);
    } else if (pathname === "/realtime") {
      await handleRealtime(ws, req);
    } else if (pathname.startsWith("/presence")) {
      await handlePresence(ws, req);
    } else {
      ws.send(
        JSON.stringify({
          type: "error",
          error: "Invalid endpoint",
        }),
      );
      ws.close();
    }
  } catch (error) {
    ws.send(
      JSON.stringify({
        type: "error",
        error: `Internal server error: ${error instanceof Error ? error.message : String(error)}`,
      }),
    );
    ws.close();
  }
});

/**
 * Handle survey response voice connections (public)
 */
async function handleSurveyResponse(
  ws: WebSocket,
  req: IncomingMessage,
): Promise<void> {
  const accessResult = await verifyPublicAccess(req);

  if ("code" in accessResult) {
    sendAuthError(ws, accessResult);
    return;
  }

  const { surveyId, conversationId } = accessResult;

  // Get client identifier (IP-based for public access)
  const identifier = getClientIdentifier(req);

  // Check rate limits with Upstash
  const rateLimitCheck = await checkConnectionAllowed(identifier);

  if (!rateLimitCheck.allowed) {
    ws.send(
      JSON.stringify({
        type: "error",
        error: rateLimitCheck.reason,
        retryAfter: rateLimitCheck.retryAfter,
      }),
    );
    ws.close();
    return;
  }

  try {
    // Extract language from URL
    const url = parse(req.url || "", true);
    const language = getSingleQueryParam(url.query?.language) || "en";

    // Create handler with language
    const handler = new SurveyResponseVoiceHandler(
      ws,
      surveyId,
      conversationId,
      identifier,
      language,
    );
    await handler.initialize();

    // Track connection with timestamp for cleanup
    const connectionId = `response-${surveyId}-${Date.now()}`;
    activeConnections.set(connectionId, { handler, createdAt: Date.now() });

    // Handle disconnection
    ws.on("close", async () => {
      activeConnections.delete(connectionId);
      await releaseConnection(identifier);
    });

  } catch (error) {
    await releaseConnection(identifier);
    ws.send(
      JSON.stringify({
        type: "error",
        error: `Failed to initialize voice session: ${error instanceof Error ? error.message : String(error)}`,
      }),
    );
    ws.close();
  }
}

/**
 * Handle sample survey voice connections (authenticated owner)
 */
async function handleSampleConversation(
  ws: WebSocket,
  req: IncomingMessage,
): Promise<void> {
  // Authenticate as owner
  const authResult = await authenticateWebSocket(ws, req);

  if ("code" in authResult) {
    sendAuthError(ws, authResult);
    return;
  }

  const connection = authResult;

  // Get surveyId and conversationNumber from query parameters
  const url = parse(req.url || "", true);
  const surveyId = getSingleQueryParam(url.query?.surveyId);
  const conversationNumber = parseInt(
    getSingleQueryParam(url.query?.conversationNumber) || "1",
  );

  if (!surveyId) {
    ws.send(
      JSON.stringify({
        type: "error",
        error: "Survey ID required",
      }),
    );
    ws.close();
    return;
  }

  const identifier = getClientIdentifier(req, connection.userId);
  const rateLimitCheck = await checkConnectionAllowed(identifier);

  if (!rateLimitCheck.allowed) {
    ws.send(
      JSON.stringify({
        type: "error",
        error: rateLimitCheck.reason,
        retryAfter: rateLimitCheck.retryAfter,
      }),
    );
    ws.close();
    return;
  }

  try {
    const handler = new SampleSurveyVoiceHandler(
      connection,
      surveyId,
      conversationNumber,
    );
    await handler.initialize();

    const connectionId = `sample-${connection.userId}-${surveyId}-${Date.now()}`;
    activeConnections.set(connectionId, {
      handler,
      userId: connection.userId,
      createdAt: Date.now(),
    });

    ws.on("close", async () => {
      activeConnections.delete(connectionId);
      await releaseConnection(identifier);
    });

  } catch (error) {
    await releaseConnection(identifier);
    ws.send(
      JSON.stringify({
        type: "error",
        error: `Failed to initialize sample voice session: ${error instanceof Error ? error.message : String(error)}`,
      }),
    );
    ws.close();
  }
}

/**
 * Handle presence connections (authenticated)
 * URL format: /presence?workspaceId={id}&surveyId={id}
 */
async function handlePresence(
  ws: WebSocket,
  req: IncomingMessage,
): Promise<void> {
  const authResult = await authenticateWebSocket(ws, req);

  if ("code" in authResult) {
    sendAuthError(ws, authResult);
    return;
  }

  const connection = authResult;
  const url = parse(req.url || "", true);
  const workspaceId = getSingleQueryParam(url.query.workspaceId);
  const surveyId = getSingleQueryParam(url.query.surveyId);

  if (!workspaceId) {
    ws.send(JSON.stringify({ type: "error", error: "Workspace ID required" }));
    ws.close();
    return;
  }

  const member = await isWorkspaceMember(connection.userId, workspaceId);
  if (!member) {
    ws.send(JSON.stringify({ type: "error", error: "Unauthorized" }));
    ws.close();
    return;
  }

  // Get client identifier (user-based)
  const identifier = getClientIdentifier(req, connection.userId);
  const rateLimitCheck = await checkConnectionAllowed(identifier);

  if (!rateLimitCheck.allowed) {
    ws.send(JSON.stringify({ type: "error", error: rateLimitCheck.reason }));
    ws.close();
    return;
  }

  try {
    const connectionId = `presence-${connection.userId}-${workspaceId}-${Date.now()}`;
    const handler = new PresenceHandler(
      connection,
      connectionId,
      workspaceId,
      surveyId,
    );
    await handler.initialize();

    activeConnections.set(connectionId, {
      handler,
      userId: connection.userId,
      createdAt: Date.now(),
    });
    presenceConnections.set(connectionId, handler);

    ws.on("close", async () => {
      activeConnections.delete(connectionId);
      presenceConnections.delete(connectionId);
      await releaseConnection(identifier);
    });

  } catch (error) {
    console.error("[websocket] presence handler initialization failed", {
      message: error instanceof Error ? error.message : "Unknown error",
    });
    await releaseConnection(identifier);
    ws.close();
  }
}

async function handleRealtime(
  ws: WebSocket,
  req: IncomingMessage,
): Promise<void> {
  const authResult = await authenticateWebSocket(ws, req);

  if ("code" in authResult) {
    sendAuthError(ws, authResult);
    return;
  }

  const connection = authResult;
  const identifier = getClientIdentifier(req, connection.userId);
  const rateLimitCheck = await checkConnectionAllowed(identifier);

  if (!rateLimitCheck.allowed) {
    ws.send(
      JSON.stringify({
        type: "error",
        error: rateLimitCheck.reason,
        retryAfter: rateLimitCheck.retryAfter,
      }),
    );
    ws.close();
    return;
  }

  const connectionId = `realtime-${connection.userId}-${Date.now()}`;
  realtimeConnections.set(connectionId, {
    ws,
    userId: connection.userId,
    subscriptions: new Set<string>(),
  });

  ws.on("message", async (raw) => {
    try {
      const data = JSON.parse(String(raw));
      if (data.type === "subscribe") {
        const channel = String(data.channel || "");
        const allowed = await authorizeRealtimeSubscription(
          connection.userId,
          channel,
        );

        if (!allowed) {
          ws.send(
            JSON.stringify({
              type: "subscription_error",
              channel,
              error: "Unauthorized",
            }),
          );
          return;
        }

        realtimeConnections.get(connectionId)?.subscriptions.add(channel);
        if (!realtimeChannelSubscriptions.has(channel)) {
          realtimeChannelSubscriptions.set(channel, new Set<string>());
        }
        realtimeChannelSubscriptions.get(channel)?.add(connectionId);
        ws.send(JSON.stringify({ type: "subscribed", channel }));
        return;
      }

      if (data.type === "unsubscribe") {
        const channel = String(data.channel || "");
        realtimeConnections.get(connectionId)?.subscriptions.delete(channel);
        realtimeChannelSubscriptions.get(channel)?.delete(connectionId);
        if (realtimeChannelSubscriptions.get(channel)?.size === 0) {
          realtimeChannelSubscriptions.delete(channel);
        }
        ws.send(JSON.stringify({ type: "unsubscribed", channel }));
      }
    } catch (error) {
      ws.send(
        JSON.stringify({
          type: "error",
          error:
            error instanceof Error ? error.message : "Invalid realtime message",
        }),
      );
    }
  });

  ws.on("close", async () => {
    const active = realtimeConnections.get(connectionId);
    if (active) {
      for (const channel of active.subscriptions) {
        realtimeChannelSubscriptions.get(channel)?.delete(connectionId);
        if (realtimeChannelSubscriptions.get(channel)?.size === 0) {
          realtimeChannelSubscriptions.delete(channel);
        }
      }
    }
    realtimeConnections.delete(connectionId);
    await releaseConnection(identifier);
  });

  ws.send(JSON.stringify({ type: "connected" }));
}

async function authorizeRealtimeSubscription(
  userId: string,
  channel: string,
): Promise<boolean> {
  if (channel.startsWith("workspace:")) {
    const workspaceId = channel.slice("workspace:".length);
    return await isWorkspaceMember(userId, workspaceId);
  }

  if (channel.startsWith("survey:")) {
    const surveyId = channel.slice("survey:".length);
    const permission = await getSurveyPermissionContext(userId, surveyId);
    return Boolean(permission?.canView && permission.collaborationAllowed);
  }

  return false;
}

/**
 * Initialize Redis pub/sub subscriber
 */
function initializeRedisSubscriber(): void {
  try {
    if (redisSubscriber) {
      redisSubscriber.quit().catch(() => { });
      redisSubscriber = null;
    }

    redisSubscriber = getRedisSubscriber();

    // Subscribe to patterns
    redisSubscriber.psubscribe("pubsub:presence:*");
    redisSubscriber.psubscribe("pubsub:realtime:*");

    redisSubscriber.on("pmessage", async (_pattern, channel, message) => {
      try {
        if (channel.startsWith("pubsub:presence:")) {
          const channelParts = channel.split(":");
          const workspaceId = channelParts[2];
          const surveyId =
            channelParts.length > 3 ? channelParts.slice(3).join(":") : undefined;
          const data = JSON.parse(message);

          for (const handler of presenceConnections.values()) {
            if (handler.matchesScope(workspaceId, surveyId)) {
              handler.send(data);
            }
          }
        } else if (channel.startsWith("pubsub:realtime:")) {
          const parts = channel.split(":");
          const scope = parts[2];
          const entityId = parts[3];
          const data = JSON.parse(message);
          const subscriptionKey = `${scope}:${entityId}`;

          for (const connectionId of realtimeChannelSubscriptions.get(subscriptionKey) ?? []) {
            const connection = realtimeConnections.get(connectionId);
            if (connection?.ws.readyState === WebSocket.OPEN) {
              connection.ws.send(JSON.stringify(data));
            }
          }
        }
      } catch (error) {
        console.error("[websocket] redis message handling failed", {
          message: error instanceof Error ? error.message : "Unknown error",
        });
      }
    });

    redisSubscriber.on("error", (error) => {
      if (redisSubscriberReconnectAttempts < MAX_REDIS_RECONNECT_ATTEMPTS) {
        const delay = REDIS_RECONNECT_DELAY_MS * Math.pow(2, redisSubscriberReconnectAttempts);
        redisSubscriberReconnectAttempts++;
        setTimeout(initializeRedisSubscriber, delay);
      }
    });

    redisSubscriber.on("connect", () => {
      redisSubscriberReconnectAttempts = 0;
    });

    redisSubscriber.on("end", () => {
      if (redisSubscriberReconnectAttempts < MAX_REDIS_RECONNECT_ATTEMPTS) {
        redisSubscriberReconnectAttempts++;
        setTimeout(initializeRedisSubscriber, REDIS_RECONNECT_DELAY_MS);
      }
    });

  } catch (error) {
    console.error("[websocket] redis subscriber initialization failed", {
      message: error instanceof Error ? error.message : "Unknown error",
    });
    if (redisSubscriberReconnectAttempts < MAX_REDIS_RECONNECT_ATTEMPTS) {
      redisSubscriberReconnectAttempts++;
      setTimeout(initializeRedisSubscriber, REDIS_RECONNECT_DELAY_MS);
    }
  }
}

/**
 * Handle server errors
 */
wss.on("error", (error) => {
  console.error("[websocket] server error", {
    message: error instanceof Error ? error.message : "Unknown error",
  });
});

/**
 * Start server
 */
server.listen(PORT, () => {
  // Initialize Redis pub/sub subscriber
  initializeRedisSubscriber();


  if (process.env.SENTRY_TEST_TRIGGER === "true") {
    throw new Error("Sentry Test WebSocket Error: This is a test error from the WebSocket process.");
  }
});

/**
 * Graceful shutdown
 */
process.on("SIGTERM", async () => {

  // Stop the cleanup interval
  clearInterval(cleanupInterval);

  // Prevent Redis reconnection attempts during shutdown
  redisSubscriberReconnectAttempts = MAX_REDIS_RECONNECT_ATTEMPTS;

  // Unsubscribe from Redis channels
  if (redisSubscriber) {
    try {
      await redisSubscriber.punsubscribe("pubsub:presence:*");
      await redisSubscriber.punsubscribe("pubsub:realtime:*");
      await redisSubscriber.quit();
    } catch (error) {
      console.error("[websocket] redis subscriber shutdown failed", {
        message: error instanceof Error ? error.message : "Unknown error",
      });
    }
  }

  // Close all active connections
  for (const [connectionId, { handler }] of activeConnections.entries()) {
    try {
      if (hasCleanupMethod(handler)) {
        await handler.cleanup();
      }
    } catch (error) {
      console.error("[websocket] handler shutdown failed", {
        connectionId,
        message: error instanceof Error ? error.message : "Unknown error",
      });
    }
  }

  for (const connection of realtimeConnections.values()) {
    if (connection.ws.readyState === WebSocket.OPEN) {
      connection.ws.close();
    }
  }

  // Close WebSocket server
  wss.close(() => {
  });

  // Close HTTP server
  server.close(() => {
    process.exit(0);
  });

  // Force exit after 10 seconds
  setTimeout(() => {
    process.exit(1);
  }, 10000);
});

process.on("SIGINT", async () => {
  process.emit("SIGTERM");
});

import { Worker, Job } from "bullmq";
import { z } from "zod";

import type { ConversationInsightsJobData } from "@/lib/queue";
import { buildSessionInsight } from "@/lib/education/analytics-workflow";
import { scheduleAnalyticsRefresh } from "@/lib/analytics-scheduler";
import {
  getSessionBySourceId,
  purgeSessionAnalyticsArtifacts,
} from "@/lib/education/storage";
import { getRedisClient } from "@/lib/redis";

const jobDataSchema = z.object({
  conversationId: z.string().min(1),
  surveyId: z.string().min(1),
  userId: z.string().min(1),
});

const conversationInsightsWorker = new Worker<ConversationInsightsJobData>(
  "conversation-insights",
  async (job: Job<ConversationInsightsJobData>) => {
    const validated = jobDataSchema.parse(job.data);
    const session = await getSessionBySourceId(validated.conversationId);
    if (session?.sessionType === "sample") {
      await purgeSessionAnalyticsArtifacts({
        surveyId: validated.surveyId,
        sessionId: session.id,
      }).catch((error) => {
      });
      await job.updateProgress(100);
      return {
        success: true,
        skipped: "sample_session",
        conversationId: validated.conversationId,
        surveyId: validated.surveyId,
      };
    }

    const insight = session ? await buildSessionInsight(session.id) : null;
    if (session?.sessionType === "live") {
      await scheduleAnalyticsRefresh({
        surveyId: validated.surveyId,
        userId: validated.userId,
      }).catch((error) => {
      });
    }
    await job.updateProgress(100);
    return {
      success: Boolean(insight),
      conversationId: validated.conversationId,
      surveyId: validated.surveyId,
    };
  },
  {
    connection: getRedisClient(),
    concurrency: 2,
  },
);

export default conversationInsightsWorker;

